                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest">ประเภท</th>
                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest text-right">ขนาด</th>
