    const [isUpdatingMember, setIsUpdatingMember] = useState(false);

    // Package form state
    const [showPackageForm, setShowPackageForm] = useState(false);
    const [newPkg, setNewPkg] = useState({ name: '', days: '', price: '', maxStaff: 1 });
    const [isEditingPkg, setIsEditingPkg] = useState(false);

    useEffect(() => {
        loadData();
    }, [activeTab]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [pkgRes] = await Promise.all([
                fetchPackages()
            ]);
            if (pkgRes.status === 'success') setPackages(pkgRes.packages);

            if (activeTab === 'pending') {
                const reqRes = await adminFetchPendingRequests();
                if (reqRes.status === 'success') {
                    setRequests(reqRes.requests);
                    const initialDurations = {};
                    reqRes.requests.forEach(r => {
                        if (r.requested_days) initialDurations[r.id] = r.requested_days.toString();
                    });
                    setDurationValues(initialDurations);
                }
            } else if (activeTab === 'members') {
                const memRes = await adminFetchAllMembers();
                if (memRes.status === 'success') {
                    setMembers(memRes.members);
                }
            } else if (activeTab === 'settings') {
                const bankRes = await adminFetchBankSettings();
                if (bankRes.status === 'success') {
                    setBankDetails({
                        bank_name: bankRes.settings?.bank_name || '',
                        bank_account: bankRes.settings?.bank_account || '',
                        bank_owner: bankRes.settings?.bank_owner || '',
                        promptpay_id: bankRes.settings?.promptpay_id || ''
                    });
                }
            }
        } catch (err) {
            toast.error('โหลดข้อมูลผิดพลาด');
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateBankInfo = async (e) => {
        e.preventDefault();
        setIsSavingBank(true);
        try {
            const res = await adminUpdateBankSettings(bankDetails);
            if (res.status === 'success') {
                toast.success('อัปเดตข้อมูลบัญชีธนาคารเรียบร้อย');
            }
        } catch (err) {
            toast.error('บันทึกไม่สำเร็จ: ' + err.message);
        } finally {
            setIsSavingBank(false);
        }
    };

    const handleAction = async (requestId, action) => {
        if (!window.confirm(`ยืนยันการ ${action === 'approve' ? 'อนุมัติ' : 'ปฏิเสธ'} คำขอนี้?`)) return;

        let days = undefined;
        if (action === 'approve') {
            const selected = durationValues[requestId] || '30';
            if (selected === 'custom') {
                const customStr = window.prompt('ระบุจำนวนวัน (เช่น 15, 45, 90):');
                if (!customStr) return; 
                days = parseInt(customStr, 10);
                if (isNaN(days) || days <= 0) {
                    return toast.error('จำนวนวันไม่ถูกต้อง ยกเลิกการอนุมัติ');
                }
            } else {
                days = parseInt(selected, 10);
            }
        }

        setProcessingId(requestId);
        try {
            const res = await adminActionSubscription(requestId, action, days);
            if (res.status === 'success') {
                toast.success(action === 'approve' ? 'อนุมัติการใช้งานเรียบร้อยแล้ว' : 'ปฏิเสธคำขอเรียบร้อยแล้ว');
                const reqRes = await adminFetchPendingRequests();
                if (reqRes.status === 'success') setRequests(reqRes.requests);
            }
        } catch (err) {
            toast.error('การดำเนินการล้มเหลว: ' + err.message);
        } finally {
            setProcessingId(null);
        }
    };

    const handleOpenEditMember = (member) => {
        setEditingMember(member);
        setEditForm({
            status: member.subscription_status || 'trial',
            expiry: member.subscription_expiry ? member.subscription_expiry.substring(0, 10) : '',
            maxStaffLimit: member.maxStaffLimit || 1
        });
    };

    const handleUpdateMember = async () => {
        if (!editingMember) return;
        setIsUpdatingMember(true);
        try {
            const res = await adminUpdateUserSubscription(editingMember.id, editForm.status, editForm.expiry, editForm.maxStaffLimit);
            if (res.status === 'success') {
                toast.success('อัปเดตข้อมูลสมาชิกเรียบร้อยแล้ว');
                setEditingMember(null);
                const memRes = await adminFetchAllMembers();
                if (memRes.status === 'success') setMembers(memRes.members);
            }
        } catch (err) {
            toast.error('อัปเดตไม่สำเร็จ: ' + err.message);
        } finally {
            setIsUpdatingMember(false);
        }
    };

    const handleCreatePackage = async (e) => {
        e.preventDefault();
        try {
            const res = await adminCreatePackage(newPkg);
            if (res.status === 'success') {
                toast.success(isEditingPkg ? 'อัปเดตแพ็กเกจเรียบร้อยแล้ว' : 'สร้างแพ็กเกจเรียบร้อยแล้ว');
                setNewPkg({ name: '', days: '', price: '', maxStaff: 1 });
                setShowPackageForm(false);
                setIsEditingPkg(false);
                const pkgRes = await fetchPackages();
                if (pkgRes.status === 'success') setPackages(pkgRes.packages);
            }
        } catch (err) {
            toast.error('การดำเนินการล้มเหลว: ' + err.message);
        }
    };

    const handleEditPackage = (pkg) => {
        setNewPkg({
            id: pkg.id,
            name: pkg.name,
            days: pkg.days,
            price: pkg.price,
            maxStaff: pkg.maxStaff || 1
        });
        setIsEditingPkg(true);
        setShowPackageForm(true);
        // Scroll to form
        window.scrollTo({ top: 300, behavior: 'smooth' });
    };

    const handleCancelPkgEdit = () => {
        setNewPkg({ name: '', days: '', price: '', maxStaff: 1 });
        setIsEditingPkg(false);
        setShowPackageForm(false);
    };

    const handleDeletePackage = async (id) => {
        if (!window.confirm('ยืนยันที่จะลบแพ็กเกจนี้?')) return;
        try {
            const res = await adminDeletePackage(id);
            if (res.status === 'success') {
                toast.success('ลบแพ็กเกจแล้ว');
                const pkgRes = await fetchPackages();
                if (pkgRes.status === 'success') setPackages(pkgRes.packages);
            }
        } catch (err) {
            toast.error('ลบแพ็กเกจไม่สำเร็จ: ' + err.message);
        }
    };

    const filteredRequests = requests.filter(req => 
        req.username.toLowerCase().includes(searchTerm.toLowerCase()) || 
        req.email.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const filteredMembers = members.filter(m => 
        m.username?.toLowerCase().includes(searchTerm.toLowerCase()) || 
        m.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        m.store_name?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const getStatusBadge = (status) => {
        switch (status) {
            case 'active': return <span className="px-2 py-1 bg-green-50 text-green-600 text-[10px] font-black rounded-lg border border-green-100 uppercase">Active</span>;
            case 'trial': return <span className="px-2 py-1 bg-blue-50 text-blue-600 text-[10px] font-black rounded-lg border border-blue-100 uppercase">Trial</span>;
            case 'expired': return <span className="px-2 py-1 bg-red-50 text-red-600 text-[10px] font-black rounded-lg border border-red-100 uppercase">Expired</span>;
            case 'cancelled': return <span className="px-2 py-1 bg-gray-50 text-gray-500 text-[10px] font-black rounded-lg border border-gray-100 uppercase">Cancelled</span>;
            default: return <span className="px-2 py-1 bg-gray-100 text-gray-400 text-[10px] font-black rounded-lg uppercase">Unknown</span>;
        }
    };

    if (loading) return (
        <div className="flex justify-center items-center h-64">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-rubber-600"></div>
        </div>
    );

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-12 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-gray-900 tracking-tight flex items-center">
                        <ShieldCheck className="mr-3 text-rubber-600" size={32} />
                        ศูนย์จัดการสมาชิก (Super Admin)
                    </h1>
                    <p className="text-gray-500 font-medium mt-1">จัดการคำขอ ตรวจสอบสลิป และแก้ไขข้อมูลวันหมดอายุสมาชิก</p>
                </div>

                {/* Search Bar */}
                <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder={activeTab === 'pending' ? "ค้นหาคำขอ..." : "ค้นหาสมาชิก/ร้านค้า..."}
                        className="pl-12 pr-6 py-4 bg-white border border-gray-100 rounded-2xl w-full md:w-[350px] shadow-sm focus:ring-2 focus:ring-rubber-500 transition-all outline-none font-medium"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            {/* Tabs Navigation */}
            <div className="flex space-x-1 bg-gray-100/80 backdrop-blur-sm p-1.5 rounded-[20px] w-fit">
                <button
                    onClick={() => setActiveTab('pending')}
                    className={`flex items-center space-x-2 px-6 py-3 rounded-[14px] text-sm font-black transition-all duration-300 ${
                        activeTab === 'pending'
                            ? 'bg-white text-rubber-700 shadow-sm'
                            : 'text-gray-500 hover:text-gray-700'
                    }`}
                >
                    <Clock size={18} />
                    <span>คำขออนุมัติใหม่</span>
                    {requests.length > 0 && (
                        <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full ml-1 animate-pulse">
                            {requests.length}
                        </span>
                    )}
                </button>
                <button
                    onClick={() => setActiveTab('members')}
                    className={`flex items-center space-x-2 px-6 py-3 rounded-[14px] text-sm font-black transition-all duration-300 ${
                        activeTab === 'members'
                            ? 'bg-white text-rubber-700 shadow-sm'
                            : 'text-gray-500 hover:text-gray-700'
                    }`}
                >
                    <Users size={18} />
                    <span>จัดการสมาชิกทั้งหมด</span>
                </button>
                <button
                    onClick={() => setActiveTab('settings')}
                    className={`flex items-center space-x-2 px-6 py-3 rounded-[14px] text-sm font-black transition-all duration-300 ${
                        activeTab === 'settings'
                            ? 'bg-white text-rubber-700 shadow-sm'
                            : 'text-gray-500 hover:text-gray-700'
                    }`}
                >
                    <Settings size={18} />
                    <span>ตั้งค่าการชำระเงิน</span>
                </button>
            </div>

            {/* Content Area */}
            {activeTab === 'pending' ? (
                <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                    {/* Package Management Section (Inside Pending Tab to keep view clean) */}
                    <div className="bg-white rounded-[32px] border border-gray-100 shadow-xl shadow-gray-200/40 p-8">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl font-black text-gray-800 flex items-center">
                                <Package className="mr-3 text-rubber-500" size={24} />
                                จัดการแพ็กเกจสมาชิก
                            </h2>
                            <button 
                                onClick={() => {
                                    if(showPackageForm && isEditingPkg) {
                                        handleCancelPkgEdit();
                                    } else {
                                        setShowPackageForm(!showPackageForm);
                                        if(!showPackageForm) setIsEditingPkg(false);
                                    }
                                }}
                                className={`flex items-center space-x-2 px-4 py-2 rounded-xl font-bold transition-colors ${
                                    showPackageForm && isEditingPkg ? 'bg-gray-100 text-gray-600' : 'bg-rubber-50 hover:bg-rubber-100 text-rubber-600'
                                }`}
                            >
                                {showPackageForm && isEditingPkg ? <XCircle size={18} /> : <Plus size={18} />}
                                <span>{showPackageForm && isEditingPkg ? 'ยกเลิกการแก้ไข' : 'เพิ่มแพ็กเกจ'}</span>
                            </button>
                        </div>

                        {showPackageForm && (
                            <form onSubmit={handleCreatePackage} className="bg-gray-50 border border-gray-100 rounded-2xl p-6 mb-8 mt-4 grid grid-cols-1 md:grid-cols-5 gap-4 items-end">
                                <div className="space-y-1">
                                    <label className="text-xs font-black text-gray-500 uppercase tracking-wider">ชื่อแพ็กเกจ</label>
                                    <input required type="text" className="w-full rounded-xl border border-gray-200 p-3 outline-none focus:ring-2 focus:ring-rubber-500" value={newPkg.name} onChange={e => setNewPkg({...newPkg, name: e.target.value})} placeholder="เช่น 1 เดือน" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-black text-gray-500 uppercase tracking-wider">จำนวนวัน</label>
                                    <input required type="number" className="w-full rounded-xl border border-gray-200 p-3 outline-none focus:ring-2 focus:ring-rubber-500" value={newPkg.days} onChange={e => setNewPkg({...newPkg, days: e.target.value})} placeholder="30" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-black text-gray-400 uppercase tracking-wider">ราคา (บาท)</label>
                                    <input required type="number" step="0.01" className="w-full rounded-xl border border-gray-200 p-3 outline-none focus:ring-2 focus:ring-rubber-500" value={newPkg.price} onChange={e => setNewPkg({...newPkg, price: e.target.value})} placeholder="299" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-black text-gray-400 uppercase tracking-wider">พนักงานสูงสุด</label>
                                    <input required type="number" className="w-full rounded-xl border border-gray-200 p-3 outline-none focus:ring-2 focus:ring-rubber-500" value={newPkg.maxStaff} onChange={e => setNewPkg({...newPkg, maxStaff: e.target.value})} placeholder="3" />
                                </div>
                                <button type="submit" className={`${isEditingPkg ? 'bg-amber-500 hover:bg-amber-600' : 'bg-rubber-600 hover:bg-rubber-700'} text-white rounded-xl p-3 font-bold shadow flex justify-center items-center h-[50px] transition-colors`}>
                                    {isEditingPkg ? 'บันทึกการแก้ไข' : 'สร้างแพ็กเกจ'}
                                </button>
                            </form>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4 text-sm">
                            {packages.map(pkg => (
                                <div key={pkg.id} className="border border-gray-100 bg-white rounded-2xl p-5 shadow-sm relative group hover:border-rubber-200 hover:shadow-md transition-all">
                                <div className="absolute top-4 right-4 flex space-x-2">
                                    <button onClick={() => handleEditPackage(pkg)} className="text-gray-300 hover:text-amber-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                                        <Edit3 size={18} />
                                    </button>
                                    <button onClick={() => handleDeletePackage(pkg.id)} className="text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                                    <div className="text-xs font-bold text-rubber-500 uppercase tracking-widest mb-1">{pkg.days} วัน</div>
                                    <div className="text-xl font-black text-gray-800">{pkg.name}</div>
                                    <div className="flex justify-between items-center mt-2 group-hover:transform group-hover:translate-y-[-2px] transition-transform">
                                        <div className="text-lg font-bold text-rubber-600">฿{pkg.price}</div>
                                        <div className="flex items-center text-[11px] font-black text-gray-400 uppercase bg-gray-50 px-2.5 py-1 rounded-lg">
                                            <Users size={12} className="mr-1.5" />
                                            {pkg.maxStaff} Staff
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Pending Requests Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {filteredRequests.map(req => (
                            <div key={req.id} className="bg-white rounded-[32px] border border-gray-100 overflow-hidden shadow-xl shadow-gray-200/40 group">
                                <div className="p-8 pb-6 border-b border-gray-50">
                                    <div className="flex items-center space-x-4 mb-6">
                                        <div className="w-14 h-14 bg-rubber-100 rounded-2xl flex items-center justify-center text-rubber-600">
                                            <User size={28} />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="text-xs font-black text-rubber-600 uppercase tracking-widest mb-0.5">Shop Owner</div>
                                            <h3 className="text-lg font-black text-gray-900 truncate tracking-tight">{req.username}</h3>
                                            <div className="text-sm text-gray-400 font-medium truncate">{req.email}</div>
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="bg-gray-50 p-4 rounded-2xl">
                                            <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">ยอดโอน</div>
                                            <div className="text-lg font-black text-gray-800">฿{req.amount}</div>
                                        </div>
                                        <div className="bg-gray-50 p-4 rounded-2xl">
                                            <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">วันที่แจ้ง</div>
                                            <div className="text-xs font-bold text-gray-800">{format(new Date(req.requestedAt), 'HH:mm dd/MM/yy')}</div>
                                        </div>
                                    </div>
                                </div>

                                <div className="p-8 pt-6 space-y-6">
                                    <div className="relative aspect-[3/4] rounded-3xl overflow-hidden bg-gray-100 border-2 border-dashed border-gray-200">
                                        <img src={req.slipUrl} alt="Slip" className="w-full h-full object-cover" />
                                        <a href={req.slipUrl} target="_blank" rel="noreferrer" className="absolute inset-0 bg-black/40 opacity-0 hover:opacity-100 transition-opacity flex flex-col items-center justify-center text-white backdrop-blur-sm">
                                            <ExternalLink size={24} className="mb-2" />
                                            <span className="font-black text-sm uppercase tracking-widest">ขยายรูปสลิป</span>
                                        </a>
                                    </div>

                                    <div className="space-y-3">
                                        <label className="text-xs font-black text-gray-400 uppercase tracking-widest block">ระบุจำนวนวันอนุมัติ</label>
                                        <select 
                                            className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 text-sm font-bold text-gray-700 outline-none focus:ring-2 focus:ring-rubber-500"
                                            value={durationValues[req.id] || '30'}
                                            onChange={(e) => setDurationValues({...durationValues, [req.id]: e.target.value})}
                                        >
                                            {packages.map(pkg => <option key={pkg.id} value={pkg.days}>{pkg.name} ({pkg.days} วัน)</option>)}
                                            <option value="custom">ระบุจำนวนวันเอง...</option>
                                        </select>
                                    </div>

                                    <div className="flex gap-3">
                                        <button onClick={() => handleAction(req.id, 'reject')} className="flex-1 py-4 bg-white text-red-600 border border-red-100 rounded-2xl font-black text-sm uppercase transition-all flex items-center justify-center space-x-2">
                                            <XCircle size={18} />
                                            <span>ปฏิเสธ</span>
                                        </button>
                                        <button onClick={() => handleAction(req.id, 'approve')} className="flex-[2] py-4 bg-rubber-600 text-white rounded-2xl font-black text-sm uppercase transition-all flex items-center justify-center space-x-2 shadow-lg shadow-rubber-200">
                                            {processingId === req.id ? <div className="w-5 h-5 border-b-2 border-white rounded-full animate-spin"></div> : <><CheckCircle size={18} /> <span>อนุมัติสิทธิ์</span></>}
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {filteredRequests.length === 0 && (
                            <div className="col-span-full py-20 bg-white rounded-[32px] border border-gray-100 text-center">
                                <ImageIcon size={48} className="mx-auto mb-4 text-gray-200" />
                                <p className="text-gray-400 font-bold">ไม่มีคำขอรออนุมัติในขณะนี้</p>
                            </div>
                        )}
                    </div>
                </div>
            ) : activeTab === 'settings' ? (
                /* Bank Settings Tab */
                <div className="max-w-2xl mx-auto bg-white rounded-[32px] border border-gray-100 shadow-xl shadow-gray-200/40 p-10 animate-in zoom-in-95 duration-500">
                    <div className="flex items-center space-x-4 mb-8">
                        <div className="w-16 h-16 bg-blue-50 rounded-3xl flex items-center justify-center text-blue-600">
                            <Building2 size={32} />
                        </div>
                        <div>
                            <h2 className="text-2xl font-black text-gray-800 tracking-tight">ตั้งค่าบัญชีธนาคารกลาง</h2>
                            <p className="text-gray-400 font-medium">ข้อมูลนี้จะไปแสดงผลในหน้าชำระเงินของสมาชิกทุกราย</p>
                        </div>
                    </div>

                    <form onSubmit={handleUpdateBankInfo} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block pl-2">ชื่อธนาคาร</label>
                            <input 
                                required
                                type="text"
                                className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-blue-500 transition-all outline-none"
                                value={bankDetails.bank_name}
                                onChange={(e) => setBankDetails({...bankDetails, bank_name: e.target.value})}
                                placeholder="เช่น ธนาคารกสิกรไทย"
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block pl-2">เลขที่บัญชี</label>
                            <input 
                                required
                                type="text"
                                className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-blue-500 transition-all outline-none"
                                value={bankDetails.bank_account}
                                onChange={(e) => setBankDetails({...bankDetails, bank_account: e.target.value})}
                                placeholder="000-0-00000-0"
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block pl-2">ชื่อเจ้าของบัญชี</label>
                            <input 
                                required
                                type="text"
                                className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-blue-500 transition-all outline-none"
                                value={bankDetails.bank_owner}
                                onChange={(e) => setBankDetails({...bankDetails, bank_owner: e.target.value})}
                                placeholder="ชื่อ-นามสกุล"
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black text-rubber-600 uppercase tracking-widest block pl-2">PromptPay ID</label>
                            <input 
                                type="text"
                                className="w-full bg-gray-50 border-2 border-rubber-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-rubber-500 transition-all outline-none"
                                value={bankDetails.promptpay_id}
                                onChange={(e) => setBankDetails({...bankDetails, promptpay_id: e.target.value})}
                                placeholder="เบอร์โทรศัพท์ หรือ เลขบัตรประชาชน"
                            />
                            <p className="text-[10px] text-gray-400 pl-2">* สำหรับสร้าง QR Code อัตโนมัติ (ใส่เฉพาะตัวเลข)</p>
                        </div>

                        <div className="pt-4">
                            <button
                                type="submit"
                                disabled={isSavingBank}
                                className="w-full bg-rubber-600 hover:bg-rubber-700 text-white py-5 rounded-3xl font-black text-lg shadow-xl shadow-rubber-200 transition-all flex items-center justify-center gap-3"
                            >
                                {isSavingBank ? <div className="w-6 h-6 border-b-2 border-white rounded-full animate-spin"></div> : <><Save size={24} /> <span>บันทึกข้อมูลธนาคาร</span></>}
                            </button>
                        </div>
                    </form>
                </div>
            ) : (
                /* Members Management Tab */
                <div className="bg-white rounded-[32px] border border-gray-100 shadow-xl shadow-gray-200/40 overflow-hidden animate-in slide-in-from-bottom-4 duration-500">
                    <div className="p-8 border-b border-gray-50 flex items-center justify-between">
                        <h2 className="text-xl font-black text-gray-800 flex items-center tracking-tight">
                            <Users size={24} className="mr-3 text-rubber-500" />
                            รายชื่อสมาชิกทั้งหมด
                        </h2>
                        <div className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                            ทั้งหมด {filteredMembers.length} คน
                        </div>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 text-[10px] font-black uppercase tracking-widest text-gray-400">
                                <tr>
                                    <th className="px-8 py-4">ชื่อร้าน / สมาชิก</th>
                                    <th className="px-8 py-4">บัญชี</th>
                                    <th className="px-8 py-4">สถานะ</th>
                                    <th className="px-8 py-4 text-center">พนักงาน</th>
                                    <th className="px-8 py-4 text-center">วันหมดอายุ</th>
                                    <th className="px-8 py-4 text-right">การจัดการ</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {filteredMembers.map(m => (
                                    <tr key={m.id} className="hover:bg-gray-50/50 transition-colors">
                                        <td className="px-8 py-5">
                                            <div className="font-black text-gray-900">{m.store_name || '-'}</div>
                                            <div className="text-[11px] text-gray-400 font-bold italic tracking-wide">ID: {m.id.substring(0, 8)}</div>
                                        </td>
                                        <td className="px-8 py-5">
                                            <div className="font-bold text-gray-700">{m.username}</div>
                                            <div className="text-xs text-gray-400 truncate max-w-[150px]">{m.email}</div>
                                        </td>
                                        <td className="px-8 py-5">
                                            {getStatusBadge(m.subscription_status)}
                                        </td>
                                        <td className="px-8 py-5 text-center">
                                            <div className="inline-flex items-center px-2 py-1 bg-gray-50 rounded-lg border border-gray-100 font-black text-gray-600 text-xs shadow-inner">
                                                <Users size={12} className="mr-1.5 text-gray-400" />
                                                {m.maxStaffLimit || 1}
                                            </div>
                                        </td>
                                        <td className="px-8 py-5 text-center font-bold text-sm text-gray-600">
                                            {m.subscription_expiry ? format(new Date(m.subscription_expiry), 'dd/MM/yyyy') : '-'}
                                        </td>
                                        <td className="px-8 py-5 text-right">
                                            <button 
                                                onClick={() => handleOpenEditMember(m)}
                                                className="p-3 text-gray-400 hover:text-rubber-600 hover:bg-rubber-50 rounded-2xl transition-all"
                                                title="แก้ไขสิทธิ์"
                                            >
                                                <Edit3 size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                                {filteredMembers.length === 0 && (
                                    <tr>
                                        <td colSpan="5" className="px-8 py-12 text-center text-gray-400 font-medium">ไม่พบข้อมูลสมาชิกตามที่ค้นหา</td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Edit Member Subscription Modal */}
            {editingMember && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
                    <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-300">
                        <div className="p-10">
                            <div className="flex justify-between items-start mb-8">
                                <div className="flex items-center space-x-4">
                                    <div className="w-16 h-16 bg-rubber-100 rounded-3xl flex items-center justify-center text-rubber-600">
                                        <User size={32} />
                                    </div>
                                    <div>
                                        <h3 className="text-2xl font-black text-gray-900 tracking-tight">{editingMember.username}</h3>
                                        <p className="text-gray-400 font-medium">{editingMember.store_name || 'ไม่มีชื่อร้าน'}</p>
                                    </div>
                                </div>
                                <button onClick={() => setEditingMember(null)} className="p-2 text-gray-300 hover:text-gray-600">
                                    <XCircle size={24} />
                                </button>
                            </div>

                            <div className="space-y-6">
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center">
                                        <Filter size={12} className="mr-1.5" />
                                        สถานะสมาชิก (Status)
                                    </label>
                                    <div className="grid grid-cols-2 gap-3">
                                        {['active', 'trial', 'expired', 'cancelled'].map(s => (
                                            <button
                                                key={s}
                                                onClick={() => setEditForm({...editForm, status: s})}
                                                className={`px-4 py-3 rounded-2xl font-black text-xs uppercase tracking-wider transition-all border-2 ${
                                                    editForm.status === s 
                                                        ? 'bg-rubber-600 text-white border-rubber-600 shadow-lg shadow-rubber-200' 
                                                        : 'bg-white text-gray-400 border-gray-100 hover:border-gray-200'
                                                }`}
                                            >
                                                {s}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center">
                                        <Calendar size={12} className="mr-1.5" />
                                        วันหมดอายุ (Subscription Expiry)
                                    </label>
                                    <input 
                                        type="date"
                                        className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-rubber-500 transition-all outline-none"
                                        value={editForm.expiry}
                                        onChange={(e) => setEditForm({...editForm, expiry: e.target.value})}
                                    />
                                    <p className="text-[10px] text-gray-400 italic">
                                        * กำหนดวันสิ้นสุดการรับโบนัสและการใช้ฟีเจอร์พรีเมียม
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center">
                                        <Users size={12} className="mr-1.5" />
                                        โควตาพนักงาน (Staff Quota)
                                    </label>
                                    <div className="relative">
                                        <input 
                                            type="number"
                                            className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 font-bold text-gray-800 focus:ring-2 focus:ring-rubber-500 transition-all outline-none"
                                            value={editForm.maxStaffLimit}
                                            onChange={(e) => setEditForm({...editForm, maxStaffLimit: e.target.value})}
                                            min="1"
                                        />
                                        <div className="absolute right-6 top-1/2 -translate-y-1/2 text-xs font-black text-gray-300">USER(S)</div>
                                    </div>
                                    <p className="text-[10px] text-gray-400 italic">
                                        * จำนวนพนักงานที่เจ้าของร้านสามารถเพิ่มเข้าระบบได้
                                    </p>
                                </div>

                                <div className="pt-4 flex flex-col space-y-3">
                                    <button
                                        onClick={handleUpdateMember}
                                        disabled={isUpdatingMember}
                                        className="w-full bg-rubber-600 hover:bg-rubber-700 text-white py-5 rounded-3xl font-black text-lg shadow-xl shadow-rubber-200 transition-all flex items-center justify-center gap-3"
                                    >
                                        {isUpdatingMember ? <div className="w-6 h-6 border-b-2 border-white rounded-full animate-spin"></div> : "บันทึกการเปลี่ยนแปลง"}
                                    </button>
                                    <div className="p-4 bg-amber-50 rounded-2xl flex items-start space-x-3 border border-amber-100">
                                        <AlertCircle size={18} className="text-amber-500 mt-0.5 shrink-0" />
                                        <p className="text-[11px] text-amber-700 font-medium leading-relaxed">
                                            ระวัง: การเปลี่ยนสถานะด้วยมือจะมีผลทันทีและไม่ทิ้งประวัติในตารางคำขออนุมัติแพ็กเกจ
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminSubscriptions;

pages/buy/BuyESlipCapture.jsx.content:
import React from 'react';
import { Leaf, User, Coins } from 'lucide-react';
import { format, addYears } from 'date-fns';
import { th } from 'date-fns/locale';

const BuyESlipCapture = ({ eslipRef, settings, watch, watchRubberType, printingReceipt, editingRecord, selectedFarmer, farmers, memberTypes, currentEmpPct, calculateDryRubber, calculateTotal }) => {
    const isCupLump = watchRubberType === 'cup_lump' || printingReceipt?.rubberType === 'cup_lump';

    return (
        <div style={{ display: 'none', position: 'fixed', left: '-9999px', top: '0', zIndex: 9999 }} ref={eslipRef}>
            <div className="eslip-capture w-[500px] bg-white flex flex-col font-sans">
                {/* Header: Dark Green */}
                <div className="bg-[#2d5a3f] py-6 px-8 text-center text-white relative">
                    <div className="flex justify-center mb-3">
                        <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md overflow-hidden">
                            {settings.logoUrl ? (
                                <img src={settings.logoUrl} alt="Logo" className="w-full h-full object-cover" />
                            ) : (
                                <Leaf size={36} className="text-white" />
                            )}
                        </div>
                    </div>
                    <h1 className="text-[42px] font-black tracking-tight mb-1 leading-tight">
                        {settings.factoryName || 'ร้านรับซื้อน้ำยางพารา'}
                    </h1>
                    <p className="text-[16px] opacity-70 font-medium mb-4">
                        {settings.address || '-'} โทร: {settings.phone || '-'}
                    </p>

                    <div className="inline-block px-6 py-1.5 bg-white/20 rounded-full border border-white/10 backdrop-blur-sm text-[18px] font-black tracking-widest leading-none">
                        {isCupLump ? 'ใบรับซื้อขี้ยางพารา' : 'ใบรับซื้อน้ำยางพารา'}
                    </div>
                </div>

                <div className="px-8 pt-6 pb-8 bg-white">
                    {/* Transaction ID & Date Bar */}
                    <div className="flex justify-between items-center mb-4 text-[18px] font-black text-gray-500 bg-gray-100/80 px-4 py-2 rounded-lg">
                        <span>เลขที่: <span className="text-gray-700">{(editingRecord?.id || ('buy_' + Date.now())).substring(0, 14)}</span></span>
                        <span>{format(addYears(new Date(), 543), 'dd MMMM yyyy HH:mm', { locale: th })}</span>
                    </div>

                    {/* Customer Info Card */}
                    <div className="mb-6">
                        <p className="text-[18px] font-bold text-gray-400 mb-1">ข้อมูลลูกค้า</p>
                        <div className="flex items-center justify-between border-b-2 border-dotted border-gray-100 pb-4">
                            <div>
                                <h2 className="text-[42px] font-black text-gray-800 leading-tight">
                                    {printingReceipt?.farmerName || farmers.find(f => f.id === watch('farmerId'))?.name || 'ลูกค้าทั่วไป'}
                                </h2>
                                <p className="text-[20px] font-bold text-gray-400">
                                    รหัส: {printingReceipt?.lineId || farmers.find(f => f.id === watch('farmerId'))?.lineId || '-'}
                                </p>
                            </div>
                            <div className="p-3 bg-gray-50 rounded-2xl">
                                <User size={40} className="text-gray-400" />
                            </div>
                        </div>
                    </div>

                    {/* Details Table */}
                    <div className="space-y-3 mb-6">
                        <p className="text-[18px] font-bold text-gray-400 mb-2">รายละเอียดการรับซื้อ</p>

                        <div className="flex justify-between items-center text-[24px]">
                            <span className="font-bold text-gray-600">{isCupLump ? 'น้ำหนักขี้ยาง' : 'น้ำหนักยางดิบ'}</span>
                            <span className="font-black text-gray-900">{(Number(watch('weight')) || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })} กก.</span>
                        </div>

                        {Number(watch('bucketWeight')) > 0 && (
                            <div className="flex justify-between items-center text-[24px]">
                                <span className="font-bold text-red-500 ml-4 italic">- น้ำหนักถังยาง</span>
                                <span className="font-bold text-red-500">-{Number(watch('bucketWeight')).toLocaleString(undefined, { minimumFractionDigits: 1 })} กก.</span>
                            </div>
                        )}

                        {Number(watch('bucketWeight')) > 0 && (
                            <div className="flex justify-between items-center text-[26px] py-1 border-t border-dotted border-gray-50">
                                <span className="font-bold text-gray-700">น้ำหนักสุทธิ</span>
                                <span className="font-black text-gray-900">{(Number(watch('weight')) - Number(watch('bucketWeight'))).toLocaleString(undefined, { minimumFractionDigits: 1 })} กก.</span>
                            </div>
                        )}

                        {!isCupLump && (
                            <>
                                <div className="flex justify-between items-center text-[24px]">
                                    <span className="font-bold text-gray-600">% DRC</span>
                                    <span className="font-black text-gray-900">{(Number(watch('drc')) || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}%</span>
                                </div>

                                <div className="flex justify-between items-center text-[30px] py-3 border-y-2 border-gray-100 font-black bg-gray-50/50 px-2 rounded-lg">
                                    <span className="text-gray-700">ยางแห้ง</span>
                                    <span className="text-gray-900">{calculateDryRubber().toLocaleString(undefined, { minimumFractionDigits: 1 })} กก.</span>
                                </div>
                            </>
                        )}

                        <div className="flex justify-between items-center text-[24px] pt-2">
                            <span className="font-bold text-gray-600">ราคากลาง</span>
                            <span className="font-bold text-gray-900 font-mono">฿{(Number(printingReceipt?.basePrice ?? watch('basePrice')) || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}/กก.</span>
                        </div>

                        {!isCupLump && (
                            <div className="flex justify-between items-center text-[24px]">
                                <span className="font-bold text-gray-600">โบนัส DRC</span>
                                <span className="font-bold text-green-600 font-mono">+฿{(Number(printingReceipt?.bonusDrc ?? watch('bonusDrc')) || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}/กก.</span>
                            </div>
                        )}
                        {!isCupLump && (
                            <>
                                {(Number(printingReceipt?.fscBonus || (farmers.find(f => f.id === watch('farmerId'))?.fscId ? (settings.fsc_bonus || 1) : 0))) > 0 && (
                                    <div className="flex justify-between items-center text-[24px] text-amber-600">
                                        <span className="font-bold">โบนัส FSC</span>
                                        <span className="font-bold font-mono">+฿{Number(printingReceipt?.fscBonus || (farmers.find(f => f.id === watch('farmerId'))?.fscId ? (settings.fsc_bonus || 1) : 0)).toLocaleString(undefined, { minimumFractionDigits: 1 })}/กก.</span>
                                    </div>
                                )}

                                {(Number(printingReceipt?.bonusMemberType ?? (farmers.find(f => f.id === watch('farmerId'))?.memberTypeId ? memberTypes.find(mt => mt.id === farmers.find(f => f.id === watch('farmerId')).memberTypeId)?.bonus : 0))) > 0 && (
                                    <div className="flex justify-between items-center text-[24px] text-rubber-700 bg-rubber-50 px-2 rounded-lg">
                                        <span className="font-black">{memberTypes.find(mt => mt.id === (printingReceipt?.memberTypeId || farmers.find(f => f.id === watch('farmerId'))?.memberTypeId))?.name || 'โบนัสสมาชิก'}</span>
                                        <span className="font-black font-mono">+฿{Number(printingReceipt?.bonusMemberType ?? (farmers.find(f => f.id === watch('farmerId'))?.memberTypeId ? memberTypes.find(mt => mt.id === farmers.find(f => f.id === watch('farmerId')).memberTypeId)?.bonus : 0)).toLocaleString(undefined, { minimumFractionDigits: 1 })}/กก.</span>
                                    </div>
                                )}
                            </>
                        )}

                        <div className="flex justify-between items-center text-[28px] pt-2 border-t border-dotted border-gray-100 mt-2 font-black">
                            <span className="text-gray-800">ราคาจริง (สุทธิ)</span>
                            <span className="text-gray-900 font-mono">฿{Math.floor(Number(printingReceipt?.actualPrice ?? (Number(watch('basePrice') || 0) + Number(watch('bonusDrc') || 0) + (selectedFarmer?.fscId ? (Number(settings.fsc_bonus) || 1) : 0) + (selectedFarmer?.memberTypeId ? (Number(memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId)?.bonus) || 0) : 0))) || 0).toLocaleString(undefined, { minimumFractionDigits: 0 })}/กก.</span>
                        </div>
                    </div>

                    {/* Shares / Splits */}
                    {!isCupLump && (
                        <div className="bg-gray-50 rounded-[32px] p-8 border border-gray-100 space-y-6">
                            <div className="flex items-center space-x-4 mb-2">
                                <div className="p-2 bg-rubber-100 rounded-xl"><Coins size={24} className="text-rubber-600" /></div>
                                <p className="text-[14px] font-black text-rubber-700 uppercase tracking-widest">การจัดสรรเงิน</p>
                            </div>

                            <div className="space-y-4 pt-6 mt-6 border-t border-dotted border-gray-100">
                                <div className="flex justify-between items-center text-[22px]">
                                    <div className="flex items-center space-x-3">
                                        <Coins size={32} className="text-orange-400" />
                                        <span className="font-bold text-orange-400">เกษตรกรได้รับ ({(100 - currentEmpPct)}%)</span>
                                    </div>
                                    <span className="font-black text-[#5ba2d7] font-mono italic">฿{Math.floor((calculateTotal() * (100 - currentEmpPct)) / 100).toLocaleString(undefined, { minimumFractionDigits: 0 })}</span>
                                </div>

                                {currentEmpPct > 0 && (
                                    <div className="flex justify-between items-center text-[22px]">
                                        <div className="flex items-center space-x-3">
                                            <User size={32} className="text-[#a855f7]" />
                                            <span className="font-bold text-[#a855f7]">ลูกจ้างได้รับ ({currentEmpPct}%)</span>
                                        </div>
                                        <span className="font-black text-[#a855f7] font-mono italic">฿{Math.floor((calculateTotal() * currentEmpPct) / 100).toLocaleString(undefined, { minimumFractionDigits: 0 })}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Note */}
                    {watch('note') && (
                        <div className="mt-8 p-5 bg-amber-50 rounded-2xl border border-amber-100 text-[14px] text-amber-700 font-medium italic">
                            หมายเหตุ: {watch('note')}
                        </div>
                    )}
                </div>

                {/* Footer: Large Green Footer */}
                <div className="bg-[#2d5a3f] p-6 flex justify-between items-center text-white">
                    <span className="text-[28px] font-black uppercase">รวมจ่าย</span>
                    <span className="text-[80px] font-black leading-none tabular-nums tracking-tighter">
                        ฿{Math.floor(calculateTotal()).toLocaleString(undefined, { minimumFractionDigits: 0 })}
                    </span>
                </div>
            </div>
        </div>
    );
};

export default BuyESlipCapture;

pages/buy/BuyForm.jsx.content:
import React from 'react';
import { PlusCircle, Search, Leaf, Wallet, Calculator, Percent } from 'lucide-react';
import { truncateOneDecimal } from '../../utils/calculations';

const BuyForm = ({
    register, handleSubmit, onSubmit, watch, setValue, errors,
    watchRubberType, watchWeight, watchBucketWeight, watchBasePrice, watchBonusDrc, watchFarmerId, watchFarmerName,
    farmers, employees, memberTypes, settings, selectedFarmer,
    farmerSearch, setFarmerSearch, showFarmerDropdown, setShowFarmerDropdown, farmerDropdownRef,
    submitting, calculateTotal, calculateDryRubber, getEmpPct, setShowCalculator
}) => {
    return (
        <div className="lg:col-span-1">
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                    <PlusCircle className="mr-2 text-rubber-600" size={20} />
                    เพิ่มรายการใหม่
                </h2>

                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">วันที่ <span className="text-red-500">*</span></label>
                        <input 
                            type="date" 
                            {...register('date', { 
                                required: 'กรุณาระบุวันที่',
                                validate: (val) => new Date(val) <= new Date() || 'ห้ามระบุวันที่ในอนาคต'
                            })} 
                            className={`w-full px-3 py-2 border rounded-lg focus:ring-rubber-500 focus:border-rubber-500 ${errors.date ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                        />
                        {errors.date && <p className="text-red-500 text-xs mt-1 font-medium">{errors.date.message || 'กรุณาระบุวันที่ให้ถูกต้อง'}</p>}
                    </div>

                    <div className="relative" ref={farmerDropdownRef}>
                        <label className="block text-sm font-medium text-gray-700 mb-1">เลือกเกษตรกร <span className="text-red-500">*</span></label>

                        <div className="relative">
                            <input
                                type="text"
                                placeholder="พิมพ์เพื่อค้นหาชื่อ..."
                                value={farmerSearch}
                                onChange={(e) => {
                                    setFarmerSearch(e.target.value);
                                    setShowFarmerDropdown(true);
                                    if (!e.target.value) {
                                        setValue('farmerId', '');
                                    }
                                }}
                                onFocus={() => setShowFarmerDropdown(true)}
                                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-rubber-500 focus:border-rubber-500 bg-white"
                            />
                            <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                                <Search size={16} className="text-gray-400" />
                            </div>
                        </div>

                        {showFarmerDropdown && (
                            <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-xl max-h-60 overflow-y-auto">
                                {farmers
                                    .filter(f => f.name.toLowerCase().includes(farmerSearch.toLowerCase()) || (f.id && f.id.toLowerCase().includes(farmerSearch.toLowerCase())))
                                    .map(f => (
                                        <div
                                            key={f.id}
                                            className="px-4 py-2 hover:bg-rubber-50 cursor-pointer border-b border-gray-50 last:border-none flex justify-between items-center"
                                            onClick={() => {
                                                setValue('farmerId', f.id);
                                                setFarmerSearch(f.name);
                                                setShowFarmerDropdown(false);
                                            }}
                                        >
                                            <span className="text-sm font-medium text-gray-900">{f.name}</span>
                                            <span className="text-[10px] text-gray-400 font-mono uppercase">{f.id}</span>
                                        </div>
                                    ))
                                }
                                {farmers.filter(f => f.name.toLowerCase().includes(farmerSearch.toLowerCase())).length === 0 && (
                                    <div className="px-4 py-3 text-sm text-gray-500 italic text-center">
                                        ไม่พบในรายชื่อ...
                                    </div>
                                )}
                            </div>
                        )}

                        <input type="hidden" {...register('farmerId', { required: !watchFarmerName })} />

                        <div className="flex items-center text-[10px] text-gray-400 my-2 px-1">
                            <span className="flex-grow border-t border-gray-100"></span>
                            <span className="px-2 uppercase font-bold tracking-widest">หรือระบุชื่อใหม่</span>
                            <span className="flex-grow border-t border-gray-100"></span>
                        </div>

                        <input
                            type="text"
                            placeholder="ระบุชื่อ-นามสกุล (ถ้าไม่มีในรายการ)"
                            {...register('farmerName', { required: !watchFarmerId })}
                            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-rubber-500 focus:border-rubber-500"
                            onChange={(e) => {
                                if (e.target.value) {
                                    setValue('farmerId', '');
                                    setFarmerSearch('');
                                }
                            }}
                        />
                        {(errors.farmerName || errors.farmerId) && <span className="text-red-500 text-xs mt-1 block font-medium">กรุณาระบุหรือเลือกเกษตรกร</span>}
                    </div>

                    {/* Product Type Selector */}
                    <div className="grid grid-cols-2 gap-2 mb-2 p-1 bg-gray-100 rounded-xl relative overflow-hidden">
                        <button
                            type="button"
                            onClick={() => setValue('rubberType', 'latex')}
                            className={`flex items-center justify-center p-2 rounded-lg text-xs font-bold transition-all z-10 ${watchRubberType === 'latex' ? 'bg-white text-emerald-700 shadow-sm' : 'text-gray-500'}`}
                        >
                            <Leaf size={14} className="mr-1.5" />
                            น้ำยางพารา
                        </button>
                        <button
                            type="button"
                            onClick={() => setValue('rubberType', 'cup_lump')}
                            className={`flex items-center justify-center p-2 rounded-lg text-xs font-bold transition-all z-10 ${watchRubberType === 'cup_lump' ? 'bg-white text-amber-700 shadow-sm' : 'text-gray-500'}`}
                        >
                            <div className="w-3 h-3 rounded-full bg-amber-600 mr-1.5 shadow-inner"></div>
                            ขี้ยางพารา
                        </button>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1 flex justify-between items-center">
                                <span>น้ำหนัก (กก.) <span className="text-red-500">*</span></span>
                                <button
                                    type="button"
                                    onClick={() => setShowCalculator(true)}
                                    className="text-rubber-600 hover:text-rubber-700 p-1 rounded-md hover:bg-rubber-50 transition-colors"
                                    title="เครื่องคิดเลขรวมน้ำหนัก"
                                >
                                    <Calculator size={16} />
                                </button>
                            </label>
                            <input 
                                type="number" 
                                step="0.01" 
                                placeholder="0.00" 
                                {...register('weight', { 
                                    required: 'กรุณาระบุน้ำหนัก', 
                                    min: { value: 0.1, message: 'น้ำหนักต้องมากกว่า 0' } 
                                })} 
                                className={`w-full px-3 py-2 border rounded-lg focus:ring-rubber-500 focus:border-rubber-500 ${errors.weight ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                            />
                            {errors.weight && <p className="text-red-500 text-[10px] mt-1 font-medium">{errors.weight.message}</p>}
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">น้ำหนักถัง (กก.)</label>
                            <input 
                                type="number" 
                                step="0.01" 
                                placeholder="0.00" 
                                {...register('bucketWeight', { 
                                    min: { value: 0, message: 'น้ำหนักถังต้องไม่ติดลบ' },
                                    validate: (val) => Number(val || 0) < Number(watchWeight || 0) || 'น้ำหนักถังต้องน้อยกว่าน้ำหนักรวม'
                                })} 
                                className={`w-full px-3 py-2 border rounded-lg focus:ring-rubber-500 focus:border-rubber-500 ${errors.bucketWeight ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                            />
                            {errors.bucketWeight && <p className="text-red-500 text-[10px] mt-1 font-medium">{errors.bucketWeight.message}</p>}
                        </div>
                    </div>

                    {watchRubberType !== 'cup_lump' && (
                        <div className="grid grid-cols-2 gap-4">
                            <div className="col-span-2">
                                <label className="block text-sm font-medium text-gray-700 mb-1">% DRC</label>
                                <input 
                                    type="number" 
                                    step="0.01" 
                                    placeholder="0.00" 
                                    {...register('drc', { 
                                        min: { value: 1, message: 'DRC ขั้นต่ำ 1%' }, 
                                        max: { value: 100, message: 'DRC สูงสุด 100%' } 
                                    })} 
                                    className={`w-full px-3 py-2 border rounded-lg focus:ring-rubber-500 focus:border-rubber-500 ${errors.drc ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                                />
                                {errors.drc && <p className="text-red-500 text-xs mt-1 font-medium">{errors.drc.message}</p>}
                            </div>
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center">
                                <Wallet size={14} className="mr-1 text-gray-400" />
                                ราคากลาง (บาท)
                            </label>
                            <input
                                type="number"
                                step="0.1"
                                placeholder="0.0"
                                {...register('basePrice', { 
                                    required: 'กรุณาระบุราคา', 
                                    min: { value: 0.1, message: 'ราคาต้องมากกว่า 0' } 
                                })}
                                className={`w-full px-3 py-2 border rounded-lg focus:ring-rubber-500 focus:border-rubber-500 font-bold ${errors.basePrice ? 'border-red-500 bg-red-50' : 'border-blue-100 bg-blue-50/30'}`}
                            />
                            {errors.basePrice && <p className="text-red-500 text-[10px] mt-1 font-medium">{errors.basePrice.message}</p>}
                        </div>
                        {watchRubberType !== 'cup_lump' && (
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center">
                                    <PlusCircle size={14} className="mr-1 text-green-500" />
                                    โบนัส DRC
                                </label>
                                <input
                                    type="number"
                                    step="0.1"
                                    min="0"
                                    placeholder="0.0"
                                    {...register('bonusDrc')}
                                    className="w-full px-3 py-2 border border-green-100 bg-green-50/30 rounded-lg focus:ring-rubber-500 focus:border-rubber-500 font-bold text-green-700"
                                />
                            </div>
                        )}
                    </div>

                    {farmers.find(f => f.id === watchFarmerId)?.fscId && (
                        <div className="mb-2 p-2 bg-amber-50 border border-amber-200 rounded-lg flex items-center justify-between text-amber-800">
                            <div className="flex items-center text-xs font-bold">
                                <Leaf size={14} className="mr-1.5 text-amber-600" />
                                🌿 FSC โบนัส
                            </div>
                            <span className="text-xs font-black">+{Number(settings.fsc_bonus || 1).toLocaleString(undefined, { minimumFractionDigits: 1 })} บาท/กก.</span>
                        </div>
                    )}

                    {selectedFarmer?.memberTypeId && memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId) && (
                        <div className="mb-2 p-2 bg-rubber-50 border border-rubber-200 rounded-lg flex items-center justify-between text-rubber-800">
                            <div className="flex items-center text-xs font-black uppercase">
                                <Percent size={14} className="mr-1.5 text-rubber-600" />
                                กลุ่ม: {memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId).name}
                            </div>
                            <span className="text-xs font-black">+{Number(memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId).bonus).toLocaleString(undefined, { minimumFractionDigits: 1 })} บาท/กก.</span>
                        </div>
                    )}

                    <div className="p-3 bg-gray-50 rounded-lg border border-gray-100">
                        <div className="flex justify-between items-center">
                            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">ราคาจริงรวมโบนัส:</span>
                            <span className="text-sm font-black text-gray-700 font-mono">
                                ฿{(Number(watchBasePrice || 0) + Number(watchBonusDrc || 0) + (selectedFarmer?.fscId ? (Number(settings.fsc_bonus) || 1) : 0) + (selectedFarmer?.memberTypeId ? (Number(memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId)?.bonus) || 0) : 0)).toLocaleString(undefined, { minimumFractionDigits: 1 })}/กก.
                            </span>
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">หมายเหตุ</label>
                        <input type="text" placeholder="ข้อมูลเพิ่มเติม..." {...register('note')} className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-rubber-500 focus:border-rubber-500" />
                    </div>

                    <div className="bg-rubber-50 p-4 rounded-lg border border-rubber-100 mt-6 text-right">
                        <div className="flex justify-between items-center">
                            <span className="text-sm text-rubber-800">ยอดจ่ายรวม:</span>
                            <span className="text-lg font-bold text-rubber-900 font-mono">฿{truncateOneDecimal(calculateTotal()).toLocaleString(undefined, { minimumFractionDigits: 1 })}</span>
                        </div>
                        <div className="flex justify-between items-center text-[10px] text-rubber-600/70 italic">
                            <span>(คำนวณจากเนื้อยางแห้ง: {truncateOneDecimal(calculateDryRubber()).toLocaleString(undefined, { minimumFractionDigits: 1 })} กก.)</span>
                        </div>
                        {getEmpPct() > 0 && (
                            <div className="flex justify-between items-center pt-2 border-t border-rubber-200">
                                <span className="text-xs text-rubber-700">ส่วนแบ่งพนักงาน ({getEmpPct()}%):</span>
                                <span className="text-sm font-bold text-blue-600 font-mono">
                                    - ฿{truncateOneDecimal(calculateTotal() * (getEmpPct() / 100)).toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                </span>
                            </div>
                        )}

                        <div className="flex flex-col space-y-1 mt-3 pt-3 border-t border-rubber-200/50">
                            {watchRubberType !== 'cup_lump' && (
                                <div className="flex justify-between items-center text-sm">
                                    <span className="text-rubber-700">ยางแห้ง:</span>
                                    <span className="font-bold text-rubber-800">{truncateOneDecimal(calculateDryRubber() || 0).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} กก.</span>
                                </div>
                            )}
                            <div className="flex justify-between items-center text-sm text-emerald-700">
                                <span>{watchRubberType === 'cup_lump' ? 'ยอดสุทธิ' : `เกษตรกร (${100 - getEmpPct()}%)`}:</span>
                                <span className="font-bold">฿ {truncateOneDecimal((calculateTotal() * (100 - getEmpPct())) / 100).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                            </div>
                            {watchRubberType !== 'cup_lump' && getEmpPct() > 0 && (
                                <div className="flex justify-between items-center text-sm text-purple-700">
                                    <span>ลูกจ้าง ({getEmpPct()}%):</span>
                                    <span className="font-bold">฿ {truncateOneDecimal((calculateTotal() * getEmpPct()) / 100).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                                </div>
                            )}
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={submitting}
                        className="w-full bg-rubber-600 text-white rounded-lg px-4 py-3 font-semibold hover:bg-rubber-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-rubber-500 disabled:opacity-50 transition-colors flex items-center justify-center mt-4 shadow-md"
                    >
                        {submitting ? 'กำลังบันทึก...' : 'บันทึกและพิมพ์ใบเสร็จ'}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default BuyForm;

pages/buy/DeleteConfirmDialog.jsx.content:
import React from 'react';
import { Trash2 } from 'lucide-react';

const DeleteConfirmDialog = ({ confirmDeleteId, setConfirmDeleteId, confirmDelete }) => {
    if (!confirmDeleteId) return null;

    return (
        <div className="fixed inset-0 bg-black/40 z-[100] flex items-center justify-center print:hidden">
            <div className="bg-white rounded-xl shadow-2xl p-6 max-w-sm w-full mx-4 border border-gray-100">
                <div className="flex items-center mb-3">
                    <div className="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center mr-3">
                        <Trash2 className="text-red-600" size={20} />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">ยืนยันการลบ</h3>
                </div>
                <p className="text-gray-600 mb-5 text-sm">คุณต้องการลบรายการนี้ใช่หรือไม่? การกระทำนี้ไม่สามารถย้อนกลับได้</p>
                <div className="flex justify-end space-x-3">
                    <button
                        onClick={() => setConfirmDeleteId(null)}
                        className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                    >ยกเลิก</button>
                    <button
                        onClick={confirmDelete}
                        className="px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors"
                    >ลบรายการ</button>
                </div>
            </div>
        </div>
    );
};

export default DeleteConfirmDialog;

pages/Buy.jsx.content:
import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useForm } from 'react-hook-form';
import { format } from 'date-fns';
import toast from 'react-hot-toast';
import { addBuyRecord, fetchBuyRecords, deleteRecord, updateRecord, fetchFarmers, fetchDailyPrice, getSettings, fetchEmployees, saveReceiptImageToDrive, deleteReceiptFileToDrive, sendLineReceipt, fetchMemberTypes, isCached, addFarmer } from '../services/apiService';
import { truncateOneDecimal, calculateDrcBonus } from '../utils/calculations';
import { printRecord } from '../utils/PrintService';

// Sub-components
import DeleteConfirmDialog from './buy/DeleteConfirmDialog';
import WeightCalculator from './buy/WeightCalculator';
import BuyPaperReceipt from './buy/BuyPaperReceipt';
import BuyESlipModal from './buy/BuyESlipModal';
import BuyESlipCapture from './buy/BuyESlipCapture';
import BuyTable from './buy/BuyTable';
import BuyForm from './buy/BuyForm';

export const Buy = () => {
    const [records, setRecords] = useState([]);
    const { user } = useAuth();
    const [farmers, setFarmers] = useState([]);
    const [employees, setEmployees] = useState([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedDate, setSelectedDate] = useState(format(new Date(), 'yyyy-MM-dd'));
    const [printingReceipt, setPrintingReceipt] = useState(null);
    const [dailyPriceObj, setDailyPriceObj] = useState({ price: '50', date: '' });
    const [settings, setLocalSettings] = useState({ factoryName: 'ร้านรับซื้อน้ำยางพารา', address: '', phone: '' });
    const [drcBonuses, setDrcBonuses] = useState([]);
    const [confirmDeleteId, setConfirmDeleteId] = useState(null);
    const [viewingEslip, setViewingEslip] = useState(null);
    const [memberTypes, setMemberTypes] = useState([]);
    const activeTab = 'buy';
    const isDemo = false;
    const eslipRef = useRef(null);

    const [farmerSearch, setFarmerSearch] = useState('');
    const [showFarmerDropdown, setShowFarmerDropdown] = useState(false);
    const farmerDropdownRef = useRef(null);

    const [editingRecord, setEditingRecord] = useState(null);
    const printRef = useRef(null);

    const [showCalculator, setShowCalculator] = useState(false);
    const [calcItems, setCalcItems] = useState([]);
    const [calcInput, setCalcInput] = useState('');

    // Pagination State
    const [currentPage, setCurrentPage] = useState(1);
    const ITEMS_PER_PAGE = 15;

    const { register, handleSubmit, watch, setValue, reset, formState: { errors, dirtyFields } } = useForm({
        defaultValues: {
            date: format(new Date(), 'yyyy-MM-dd'),
            farmerId: '',
            farmerName: '',
            weight: '',
            bucketWeight: '',
            drc: '',
            pricePerKg: '',
            basePrice: '',
            bonusDrc: '',
            note: '',
            rubberType: 'latex'
        }
    });

    const watchRubberType = watch('rubberType');
    const watchWeight = watch('weight');
    const watchBucketWeight = watch('bucketWeight');
    const watchPricePerKg = watch('pricePerKg');
    const watchBasePrice = watch('basePrice');
    const watchBonusDrc = watch('bonusDrc');
    const watchDrc = watch('drc');
    const watchFarmerId = watch('farmerId');
    const watchFarmerName = watch('farmerName');
    const selectedFarmer = farmers.find(f => f.id === watchFarmerId);

    // Bonus Logic: Update PricePerKg when DRC, Farmer or Member Type changes
    useEffect(() => {
        const isCupLump = watchRubberType === 'cup_lump' || watchRubberType === 'ขี้ยาง';
        const base = isCupLump 
            ? (Number(settings.cupLumpPrice) || 0) 
            : (Number(dailyPriceObj.price) || 0);
        const drc = Number(watchDrc) || 0;
        const bonusDrc = calculateDrcBonus(drc, drcBonuses);

        const selectedFarmer = farmers.find(f => f.id === watchFarmerId);
        const fscBonus = selectedFarmer?.fscId ? (Number(settings.fsc_bonus) || 1) : 0;

        let memberBonus = 0;
        if (selectedFarmer?.memberTypeId) {
            const mType = memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId);
            if (mType) memberBonus = Number(mType.bonus) || 0;
        }

        if (!dirtyFields.basePrice) setValue('basePrice', base.toString());
        if (!dirtyFields.bonusDrc) setValue('bonusDrc', isCupLump ? '0' : bonusDrc.toString());
        setValue('pricePerKg', (base + (isCupLump ? 0 : bonusDrc) + fscBonus + memberBonus).toString());
    }, [watchDrc, watchFarmerId, watchRubberType, farmers, memberTypes, dailyPriceObj.price, settings.cupLumpPrice, setValue, drcBonuses]);

    // Load data
    useEffect(() => {
        loadData();
        loadLocalSettings();

        const handleClickOutside = (event) => {
            if (farmerDropdownRef.current && !farmerDropdownRef.current.contains(event.target)) {
                setShowFarmerDropdown(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);

        const handleRefresh = () => {
            loadData();
        };
        window.addEventListener('dashboard-refresh', handleRefresh);

        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
            window.removeEventListener('dashboard-refresh', handleRefresh);
        };
    }, []);

    // Reset pagination on filter change
    useEffect(() => {
        setCurrentPage(1);
    }, [searchTerm, selectedDate]);

    const loadLocalSettings = async () => {
        try {
            const res = await getSettings();
            if (res.status === 'success' && res.data) {
                setLocalSettings(prev => ({ ...prev, ...res.data }));
            }
        } catch (error) {
            console.error('Error loading settings:', error);
        }
    };

    const loadData = async () => {
        if (!isCached('buys', 'farmers')) setLoading(true);
        try {
            if (isDemo) {
                setRecords([
                    { id: '1', date: new Date().toISOString(), farmerName: 'สมชาย รักดี', weight: 150, drc: 32, pricePerKg: 35, total: 5250, timestamp: new Date().toISOString() },
                    { id: '2', date: new Date().toISOString(), farmerName: 'สมปอง ใจสู้', weight: 80, drc: 35, pricePerKg: 38, total: 3040, timestamp: new Date().toISOString() }
                ]);
                setFarmers([
                    { id: 'f1', name: 'สมชาย รักดี' },
                    { id: 'f2', name: 'สมปอง ใจสู้' }
                ]);
                setDailyPriceObj({ price: '50', date: new Date().toISOString().split('T')[0] });
                setEmployees([{ id: 'e1', farmerId: 'f1', name: 'ลูกจ้างชาย', profitSharePct: 40 }]);
                const demoDrc = localStorage.getItem('demo_drc_bonuses');
                if (demoDrc) {
                    try { setDrcBonuses(JSON.parse(demoDrc)); } catch (e) { }
                }
                setValue('pricePerKg', '50');
                return;
            }
            const [buyData, farmersData, priceData, settingsRes, employeesData, mtData] = await Promise.all([
                fetchBuyRecords(),
                fetchFarmers(),
                fetchDailyPrice(),
                getSettings(),
                fetchEmployees(),
                fetchMemberTypes()
            ]);
            setRecords(Array.isArray(buyData) ? buyData : []);
            setFarmers(Array.isArray(farmersData) ? farmersData : []);
            setEmployees(Array.isArray(employeesData) ? employeesData : []);
            setMemberTypes(Array.isArray(mtData) ? mtData : []);

            if (priceData && priceData.status === 'success') {
                setDailyPriceObj(priceData.data);
                setValue('pricePerKg', priceData.data.price);
            }

            if (settingsRes && settingsRes.status === 'success' && settingsRes.data) {
                setLocalSettings(prev => ({ ...prev, ...settingsRes.data }));
                if (settingsRes.data.drcBonuses) {
                    try { setDrcBonuses(JSON.parse(settingsRes.data.drcBonuses)); } catch (e) { }
                }
            }
        } catch (error) {
            toast.error('โหลดข้อมูลล้มเหลว');
        } finally {
            setLoading(false);
        }
    };

    const onSubmit = async (data) => {
        setSubmitting(true);
        const toastId = toast.loading('กำลังประมวลผล...');
        try {
            let farmerId = data.farmerId;
            let farmerName = data.farmerName;
            const isNewFarmer = !farmerId && farmerName;

            if (isNewFarmer) {
                if (!data.note || data.note.trim().length < 5) {
                    setSubmitting(false);
                    toast.error('กรุณาระบุเลขบัตรประชาชนหรือเบอร์โทรศัพท์ในช่องหมายเหตุสำหรับเกษตรกรใหม่', { id: toastId });
                    return;
                }
                toast.loading('กำลังลงทะเบียนเกษตรกรใหม่...', { id: toastId });
                try {
                    const resFarmer = await addFarmer({ name: farmerName, note: data.note });
                    if (resFarmer.status === 'success') {
                        farmerId = resFarmer.id;
                        const newFarmerEntry = { id: farmerId, name: farmerName, note: data.note };
                        setFarmers(prev => [newFarmerEntry, ...prev]);
                        toast.loading('ลงทะเบียนสำเร็จ กำลังบันทึกรายการ...', { id: toastId });
                    } else {
                        throw new Error(resFarmer.message || 'ลงทะเบียนล้มเหลว');
                    }
                } catch (err) {
                    setSubmitting(false);
                    toast.error('ไม่สามารถลงทะเบียนเกษตรกรใหม่ได้: ' + err.message, { id: toastId });
                    return;
                }
            } else {
                const sf = farmers.find(f => f.id === farmerId);
                if (sf) farmerName = sf.name;
            }

            let w = Number(data.weight) || 0;
            let bw = Number(data.bucketWeight) || 0;
            let d = Number(data.drc) || 0;
            let bp = Number(data.basePrice) || 0;
            let bDrc = Number(data.bonusDrc) || 0;

            const fscBonus = selectedFarmer?.fscId ? (Number(settings.fsc_bonus) || 1) : 0;
            let bonusMemberType = 0;
            if (selectedFarmer?.memberTypeId) {
                const mType = memberTypes.find(mt => mt.id === selectedFarmer.memberTypeId);
                if (mType) bonusMemberType = Number(mType.bonus) || 0;
            }

            const p = bp + bDrc + fscBonus + bonusMemberType;
            const farmerEmps = employees.filter(e => e.farmerId === farmerId);
            const empPct = farmerEmps.length > 0 ? Number(farmerEmps[0].profitSharePct) : 0;

            const netWeight = truncateOneDecimal(w - bw);
            const dryRubber = truncateOneDecimal((netWeight * d) / 100);
            const actualPrice = truncateOneDecimal(p);

            const isCupLump = (data.rubberType || watchRubberType) === 'cup_lump';
            const total = isCupLump ? Math.floor(netWeight * actualPrice) : Math.floor(dryRubber * actualPrice);
            const employeeTotal = Math.floor((total * empPct) / 100);
            const farmerTotal = Math.floor(total - employeeTotal);

            // --- E-Slip Generation ---
            let receiptUrl = '';
            const shouldPrintESlip = settings.printESlip === undefined ? true : (settings.printESlip === 'true' || settings.printESlip === true);

            if (!isDemo && shouldPrintESlip) {
                toast.loading('กำลังสร้าง E-Slip...', { id: toastId });
                try {
                    if (!window.html2canvas) {
                        await new Promise((resolve, reject) => {
                            const script = document.createElement('script');
                            script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
                            script.onload = resolve; script.onerror = reject;
                            document.head.appendChild(script);
                        });
                    }
                    const element = eslipRef.current;
                    if (element) {
                        element.style.display = 'block';
                        await new Promise(r => setTimeout(r, 800));
                        const captureEl = element.querySelector('.eslip-capture');
                        const canvas = await window.html2canvas(captureEl, {
                            scale: 2, useCORS: true, backgroundColor: '#ffffff',
                            width: 500, logging: false, windowWidth: 500,
                            scrollX: 0, scrollY: 0
                        });
                        element.style.display = 'none';
                        const base64 = canvas.toDataURL('image/png');
                        const filename = `ESlip_Buy_${Date.now()}.png`;
                        const uploadRes = await saveReceiptImageToDrive(base64, filename);
                        if (uploadRes.status === 'success') {
                            receiptUrl = uploadRes.url;
                        }
                    }
                } catch (e) {
                    console.error('E-Slip error:', e);
                }
            }

            const payload = {
                date: data.date, farmerId, farmerName,
                weight: Number(data.weight) || 0, bucketWeight: Number(data.bucketWeight) || 0,
                drc: Number(data.drc) || 0, basePrice: bp, bonusDrc: bDrc,
                actualPrice, pricePerKg: Number(actualPrice), total: Math.floor(total),
                dryRubber: isCupLump ? Number(netWeight) : Number(dryRubber),
                dryWeight: isCupLump ? Number(netWeight) : Number(dryRubber),
                empPct: Number(empPct), employeeTotal: Math.floor(employeeTotal),
                farmerTotal: Math.floor(farmerTotal), fscBonus: Number(fscBonus),
                bonusMemberType: Number(bonusMemberType), note: data.note,
                rubberType: data.rubberType || 'latex', receiptUrl,
                status: 'Completed', farmerStatus: 'Pending', employeeStatus: 'Pending',
                timestamp: new Date().toISOString()
            };

            if (isDemo) {
                const todayStr = format(new Date(), 'yyyy-MM-dd');
                const todayRecords = records.filter(r => String(r.id).startsWith(todayStr + '-'));
                let maxNum = 0;
                todayRecords.forEach(r => {
                    const parts = String(r.id).split('-');
                    const n = parseInt(parts[parts.length - 1], 10);
                    if (!isNaN(n) && n > maxNum) maxNum = n;
                });
                const newId = `${todayStr}-${String(maxNum + 1).padStart(4, '0')}`;
                const newRecord = { ...payload, id: newId, timestamp: new Date().toISOString() };
                setRecords([newRecord, ...records]);
                toast.success('บันทึกสำเร็จ (Demo)', { id: toastId });
                reset({ date: format(new Date(), 'yyyy-MM-dd'), farmerId: '', farmerName: '', weight: '', bucketWeight: '', drc: '', pricePerKg: dailyPriceObj.price, note: '', rubberType: 'latex' });
                setFarmerSearch('');
            } else {
                const res = await addBuyRecord(payload);
                if (res.status === 'success') {
                    toast.success('บันทึกสำเร็จ', { id: toastId });
                    const newRecord = { ...payload, id: res.id, timestamp: new Date().toISOString() };
                    setRecords([newRecord, ...records]);

                    if (receiptUrl && farmerId) {
                        sendLineReceipt(farmerId, receiptUrl)
                            .then(r => console.log('LINE Sent:', r))
                            .catch(e => console.error('LINE Error:', e));
                    }

                    reset({
                        date: format(new Date(), 'yyyy-MM-dd'), farmerId: '', farmerName: '',
                        weight: '', bucketWeight: '', drc: '',
                        pricePerKg: dailyPriceObj.price || '0', note: ''
                    });
                    setFarmerSearch('');
                    setSubmitting(false);

                    const shouldPrintPaper = settings.printPaperSlip === undefined ? true : (settings.printPaperSlip === 'true' || settings.printPaperSlip === true);
                    if (shouldPrintPaper) {
                        setTimeout(() => {
                            toast.dismiss();
                            handlePrintReceipt(newRecord);
                        }, 500);
                    }
                } else {
                    setSubmitting(false);
                    toast.error(res.message, { id: toastId });
                }
            }
        } catch (error) {
            setSubmitting(false);
            toast.error('บันทึกล้มเหลว: ' + error.message, { id: toastId });
        }
    };

    const handleDelete = async (id) => { setConfirmDeleteId(id); };

    const confirmDelete = async () => {
        const id = confirmDeleteId;
        setConfirmDeleteId(null);
        const toastId = toast.loading('กำลังลบ...');
        try {
            if (isDemo) {
                setRecords(prev => prev.filter(r => String(r.id) !== String(id)));
                toast.success('ลบสำเร็จ (Demo)', { id: toastId });
                return;
            }
            const targetRecord = records.find(r => String(r.id) === String(id));
            const res = await deleteRecord('buys', id);
            if (res && res.status === 'success') {
                if (targetRecord && targetRecord.receiptUrl) {
                    deleteReceiptFileToDrive(targetRecord.receiptUrl)
                        .then(r => console.log('[Delete Drive File]', r))
                        .catch(e => console.warn('[Delete Drive File Error]', e));
                }
                toast.success('ลบสำเร็จ', { id: toastId });
                setRecords(prev => prev.filter(r => String(r.id) !== String(id)));
            } else {
                const errMsg = (res && res.message) ? res.message : JSON.stringify(res);
                toast.error('ลบล้มเหลว: ' + errMsg, { id: toastId, duration: 8000 });
            }
        } catch (error) {
            toast.error('ลบล้มเหลว (exception): ' + error.message, { id: toastId, duration: 8000 });
        }
    };

    const handlePrintReceipt = (record) => {
        setPrintingReceipt(record);
        setTimeout(() => {
            if (printRef.current) {
                printRecord(printRef.current.innerHTML);
                setPrintingReceipt(null);
            }
        }, 500);
    };

    const calculateTotal = () => {
        const w = truncateOneDecimal(Number(watchWeight) || 0);
        const bw = truncateOneDecimal(Number(watchBucketWeight) || 0);
        const netWeight = truncateOneDecimal(w - bw);
        const d = truncateOneDecimal(Number(watchDrc) || 0);
        const dry = truncateOneDecimal((netWeight * d) / 100);

        const sf = farmers.find(f => f.id === watchFarmerId);
        const fscBonus = sf?.fscId ? (Number(settings.fsc_bonus) || 1) : 0;
        let memberBonus = 0;
        if (sf?.memberTypeId) {
            const mType = memberTypes.find(mt => mt.id === sf.memberTypeId);
            if (mType) memberBonus = Number(mType.bonus) || 0;
        }
        const actualPrice = truncateOneDecimal(Number(watchBasePrice || 0) + Number(watchBonusDrc || 0) + fscBonus + memberBonus);

        if (watchRubberType === 'cup_lump' || watchRubberType === 'ขี้ยาง') {
            return Math.floor(netWeight * actualPrice);
        }
        return Math.floor(dry * actualPrice);
    };

    const getEmpPct = () => {
        const emp = employees.find(e => e.farmerId === watchFarmerId);
        return emp ? Number(emp.profitSharePct) : 0;
    };

    const calculateDryRubber = () => {
        const w = truncateOneDecimal(Number(watchWeight) || 0);
        const bw = truncateOneDecimal(Number(watchBucketWeight) || 0);
        const netWeight = truncateOneDecimal(w - bw);
        const d = truncateOneDecimal(Number(watchDrc) || 0);
        if (watchRubberType === 'cup_lump' || watchRubberType === 'ขี้ยาง') return netWeight;
        return truncateOneDecimal((netWeight * d) / 100);
    };

    const filteredRecords = records.filter(r => {
        const matchesSearch = (r.farmerName || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
            (r.id || '').toLowerCase().includes(searchTerm.toLowerCase());
        const matchesDate = (r.date || '').split('T')[0] === selectedDate;
        return matchesSearch && matchesDate;
    });

    const totalPages = Math.ceil(filteredRecords.length / ITEMS_PER_PAGE);
    const paginatedRecords = filteredRecords.slice(
        (currentPage - 1) * ITEMS_PER_PAGE,
        currentPage * ITEMS_PER_PAGE
    );

    const addCalcItem = (e) => {
        if (e) e.preventDefault();
        if (calcInput && !isNaN(calcInput)) {
            setCalcItems([...calcItems, Number(calcInput)]);
            setCalcInput('');
        }
    };

    const removeCalcItem = (index) => { setCalcItems(calcItems.filter((_, i) => i !== index)); };

    const applyCalcResult = () => {
        const total = calcItems.reduce((sum, val) => sum + val, 0);
        setValue('weight', truncateOneDecimal(total).toString());
        setShowCalculator(false);
        setCalcItems([]);
    };

    const dailySummary = {
        count: filteredRecords.length,
        totalWeight: filteredRecords.reduce((sum, r) => sum + (Number(r.weight) - Number(r.bucketWeight || 0)), 0),
        totalAmount: filteredRecords.reduce((sum, r) => sum + Number(r.total), 0)
    };

    const currentEmpPct = Number(employees.find(e => e.farmerId === watchFarmerId)?.profitSharePct) || 0;

    return (
        <div className="space-y-6">
            {/* Direct Print Style Injection for 57mm Thermal Printer */}
            <style dangerouslySetInnerHTML={{
                __html: `
                @media print {
                    @page { size: 48mm 210mm; margin: 0; }
                    body { margin: 0; padding: 0; -webkit-print-color-adjust: exact; }
                    .receipt-content { width: 48mm; padding: 2mm; margin: 0 auto; font-family: 'Noto Sans Thai', sans-serif; }
                    .no-print { display: none !important; }
                }
            ` }} />

            {/* Modals & Overlays */}
            <DeleteConfirmDialog confirmDeleteId={confirmDeleteId} setConfirmDeleteId={setConfirmDeleteId} confirmDelete={confirmDelete} />

            {/* Hidden Print Container */}
            <BuyPaperReceipt printingReceipt={printingReceipt} printRef={printRef} setPrintingReceipt={setPrintingReceipt} settings={settings} drcBonuses={drcBonuses} farmers={farmers} memberTypes={memberTypes} />

            {/* Main UI */}
            <div className="print:hidden">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">บันทึกรับซื้อน้ำยาง</h1>
                <p className="text-gray-500 mb-6">บันทึกข้อมูลการรับซื้อน้ำยางจากเกษตรกรและพิมพ์ใบเสร็จ</p>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Add Form */}
                    <BuyForm
                        register={register} handleSubmit={handleSubmit} onSubmit={onSubmit}
                        watch={watch} setValue={setValue} errors={errors}
                        watchRubberType={watchRubberType} watchWeight={watchWeight} watchBucketWeight={watchBucketWeight}
                        watchBasePrice={watchBasePrice} watchBonusDrc={watchBonusDrc}
                        watchFarmerId={watchFarmerId} watchFarmerName={watchFarmerName}
                        farmers={farmers} employees={employees} memberTypes={memberTypes}
                        settings={settings} selectedFarmer={selectedFarmer}
                        farmerSearch={farmerSearch} setFarmerSearch={setFarmerSearch}
                        showFarmerDropdown={showFarmerDropdown} setShowFarmerDropdown={setShowFarmerDropdown}
                        farmerDropdownRef={farmerDropdownRef}
                        submitting={submitting} calculateTotal={calculateTotal}
                        calculateDryRubber={calculateDryRubber} getEmpPct={getEmpPct}
                        setShowCalculator={setShowCalculator}
                    />

                    {/* Records Table */}
                    <BuyTable
                        filteredRecords={paginatedRecords} dailySummary={dailySummary}
                        loading={loading} searchTerm={searchTerm} setSearchTerm={setSearchTerm}
                        selectedDate={selectedDate} setSelectedDate={setSelectedDate}
                        handlePrintReceipt={handlePrintReceipt} handleDelete={handleDelete}
                        setViewingEslip={setViewingEslip} user={user}
                        pagination={{
                            currentPage,
                            totalPages,
                            totalCount: filteredRecords.length,
                            pageSize: ITEMS_PER_PAGE
                        }}
                        onPageChange={setCurrentPage}
                    />
                </div>

                {/* Premium E-Slip Modal */}
                <BuyESlipModal viewingEslip={viewingEslip} setViewingEslip={setViewingEslip} settings={settings} farmers={farmers} memberTypes={memberTypes} />

                {/* Weight Calculator Modal */}
                <WeightCalculator
                    showCalculator={showCalculator} setShowCalculator={setShowCalculator}
                    calcItems={calcItems} setCalcItems={setCalcItems}
                    calcInput={calcInput} setCalcInput={setCalcInput}
                    addCalcItem={addCalcItem} removeCalcItem={removeCalcItem}
                    applyCalcResult={applyCalcResult}
                />
            </div>

            {/* Hidden E-Slip Capture Template */}
            <BuyESlipCapture
                eslipRef={eslipRef} settings={settings} watch={watch}
                watchRubberType={watchRubberType} printingReceipt={printingReceipt}
                editingRecord={editingRecord} selectedFarmer={selectedFarmer}
                farmers={farmers} memberTypes={memberTypes}
                currentEmpPct={currentEmpPct}
                calculateDryRubber={calculateDryRubber} calculateTotal={calculateTotal}
            />
        </div>
    );
};

export default Buy;

