                                            <td className="px-8 py-5 text-center">
                                                <span className="bg-orange-50 text-orange-700 px-3 py-1 rounded-lg font-black text-xs border border-orange-100">
                                                    {Number(s.drc || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}%
                                                </span>
                                            </td>
                                            <td className="px-8 py-5 text-right font-mono font-black text-orange-600">{(Number(s.weight || 0) * Number(s.drc || 0) / 100).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                            <td className="px-8 py-5 text-right text-gray-500 font-mono font-bold">฿{Number(s.pricePerKg || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                            <td className="px-8 py-5 text-right font-black text-gray-900 font-mono bg-rubber-50/30">฿{Number(s.total || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                        </tr>
                                    ));
                                })()}
                            </tbody>
                            {dailyData.sells.length > 0 && (
                                <tfoot className="bg-gray-900 text-white font-black border-t-4 border-rubber-600">
                                    <tr className="divide-x divide-white/10 uppercase text-sm tracking-tight">
                                        <td colSpan="2" className="px-8 py-5 text-rubber-400 text-left">ยอดรวม {dailyData.sells.length} รายการ</td>
                                        <td className="px-8 py-5 text-right font-mono text-gray-400">{dailyData.sells.reduce((sum, s) => sum + Number(s.weight || 0), 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                        <td className="px-8 py-5"></td>
                                        <td className="px-8 py-5 text-right font-mono text-orange-400">
                                            {dailyData.sells.reduce((sum, s) => sum + (Number(s.weight || 0) * Number(s.drc || 0) / 100), 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                        <td className="px-8 py-5"></td>
                                        <td className="px-8 py-5 text-right font-mono text-white bg-rubber-900/50">
                                            ฿{dailyData.sells.reduce((sum, s) => sum + Number(s.total || 0), 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                    </tr>
                                </tfoot>
                            )}
                        </table>
                        <PaginationFooter totalCount={dailyData.sells.length} currentPage={currentPage} setCurrentPage={setCurrentPage} />
                    </div>
                )}

                {activeTab === 'expenses' && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-gray-100">
                        {/* General Expenses */}
                        <div className="p-0 flex flex-col h-full border-r border-gray-100">
                            <div className="bg-[#1e293b] px-8 py-5 flex justify-between items-center text-white">
                                <h3 className="font-black flex items-center tracking-tight">
                                    <Wallet size={20} className="mr-3 text-red-400" />
                                    ค่าใช้จ่ายทั่วไป
                                </h3>
                                <span className="bg-red-500/20 text-red-400 px-5 py-2 rounded-2xl text-base font-black shadow-inner border border-red-500/20">
                                    ฿{dailyData.expenses.reduce((sum, e) => sum + Number(e.amount || 0), 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                </span>
                            </div>
                            <div className="overflow-x-auto flex-1">
                                <table className="w-full text-sm text-left">
                                    <tbody className="divide-y divide-gray-100">
                                        {(() => {
                                            const paginated = dailyData.expenses.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);
                                            if (dailyData.expenses.length === 0) {
                                                return (
                                                    <tr>
                                                        <td className="px-8 py-20 text-center text-gray-400 font-medium italic">ไม่มีข้อมูลค่าใช้จ่ายทั่วไป</td>
                                                    </tr>
                                                );
                                            }
                                            return paginated.map((e, idx) => (
                                                <tr key={e.id || idx} className="hover:bg-red-50/30 transition-colors group text-sm">
                                                    <td className="px-8 py-5">
                                                        <div className="font-black text-gray-900 group-hover:text-red-700 transition-colors">{e.title}</div>
                                                        <div className="text-xs text-gray-400 font-bold uppercase tracking-tighter">{e.category || 'ทั่วไป'}</div>
                                                    </td>
                                                    <td className="px-8 py-5 text-right font-black text-red-600 font-mono text-base whitespace-nowrap">฿{Number(e.amount || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                                </tr>
                                            ));
                                        })()}
                                    </tbody>
                                </table>
                            </div>
                            <PaginationFooter totalCount={dailyData.expenses.length} currentPage={currentPage} setCurrentPage={setCurrentPage} />
                        </div>

                        {/* Wages */}
                        <div className="p-0 flex flex-col h-full">
                            <div className="bg-[#1e293b] px-8 py-5 flex justify-between items-center text-white border-l border-white/10">
                                <h3 className="font-black flex items-center tracking-tight">
                                    <Users size={20} className="mr-3 text-orange-400" />
                                    ค่าจ้างพนักงาน
                                </h3>
                                <span className="bg-orange-500/20 text-orange-400 px-5 py-2 rounded-2xl text-base font-black shadow-inner border border-orange-500/20">
                                    ฿{dailyData.wages.reduce((sum, w) => sum + Number(w.total || 0), 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                </span>
                            </div>
                            <div className="overflow-x-auto flex-1">
                                <table className="w-full text-sm text-left">
                                    <tbody className="divide-y divide-gray-100">
                                        {(() => {
                                            const paginated = dailyData.wages.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);
                                            if (dailyData.wages.length === 0) {
                                                return (
                                                    <tr>
                                                        <td className="px-8 py-20 text-center text-gray-400 font-medium italic">ไม่มีข้อมูลค่าจ้างพนักงาน</td>
                                                    </tr>
                                                );
                                            }
                                            return paginated.map((w, idx) => (
                                                <tr key={w.id || idx} className="hover:bg-orange-50/30 transition-colors group text-sm">
                                                    <td className="px-8 py-5">
                                                        <div className="font-black text-gray-900 group-hover:text-orange-700 transition-colors">{w.staffName || 'พนักงาน'}</div>
                                                        <div className="text-xs text-gray-400 font-bold uppercase tracking-tighter">{w.role || 'ลูกจ้าง'}</div>
                                                    </td>
                                                    <td className="px-8 py-5 text-right font-black text-orange-600 font-mono text-base whitespace-nowrap">฿{Number(w.total || 0).toLocaleString(undefined, { minimumFractionDigits: 1 })}</td>
                                                </tr>
                                            ));
                                        })()}
                                    </tbody>
                                </table>
                            </div>
                            <PaginationFooter totalCount={dailyData.wages.length} currentPage={currentPage} setCurrentPage={setCurrentPage} />
                        </div>
                    </div>
                )}
            </div>

            {/* Daily Overall Summary Footer */}
            {(() => {
                const latexBuyTotal = dailyData.buys.filter(b => (b.rubberType || 'latex') === 'latex').reduce((sum, b) => sum + Number(b.total || 0), 0);
                const cupLumpBuyTotal = dailyData.buys.filter(b => b.rubberType === 'cup_lump' || b.rubberType === 'ขี้ยาง').reduce((sum, b) => sum + Number(b.total || 0), 0);
                const totalBuy = latexBuyTotal + cupLumpBuyTotal;

                const latexSellTotal = dailyData.sells.filter(s => (s.rubberType || 'latex') === 'latex').reduce((sum, s) => sum + Number(s.total || 0), 0);
                const cupLumpSellTotal = dailyData.sells.filter(s => s.rubberType === 'cup_lump' || s.rubberType === 'ขี้ยาง').reduce((sum, s) => sum + Number(s.total || 0), 0);
                const totalSell = latexSellTotal + cupLumpSellTotal;

                const totalExpense = dailyData.expenses.reduce((sum, e) => sum + Number(e.amount || 0), 0);
                const totalWage = dailyData.wages.reduce((sum, w) => sum + Number(w.total || 0), 0);
                const netProfit = totalSell - totalBuy - totalExpense - totalWage;

                return (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8 pb-10">
                        {/* Total Buys Card */}
                        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-lg shadow-gray-200/50 flex flex-col group hover:border-blue-500 transition-all">
                            <div className="flex items-center space-x-4 mb-3">
                                <div className="p-3 bg-blue-50 rounded-xl group-hover:bg-blue-600 transition-colors duration-500 shadow-inner">
                                    <Droplets className="text-blue-600 group-hover:text-white transition-colors duration-500" size={24} />
                                </div>
                                <div>
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">ยอดรับซื้อรวม</p>
                                    <p className="text-2xl font-black text-gray-900 leading-none">฿{totalBuy.toLocaleString(undefined, { minimumFractionDigits: 1 })}</p>
                                </div>
                            </div>
                            <div className="flex border-t border-gray-50 pt-3 mt-auto">
                                <div className="flex-1 text-center border-r border-gray-50">
                                    <p className="text-[9px] font-bold text-gray-400 uppercase">น้ำยาง</p>
                                    <p className="text-xs font-black text-blue-700">+฿{latexBuyTotal.toLocaleString()}</p>
                                </div>
                                <div className="flex-1 text-center">
                                    <p className="text-[9px] font-bold text-gray-400 uppercase">ขี้ยาง</p>
                                    <p className="text-xs font-black text-orange-700">+฿{cupLumpBuyTotal.toLocaleString()}</p>
                                </div>
                            </div>
                        </div>

                        {/* Total Sells Card */}
                        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-lg shadow-gray-200/50 flex flex-col group hover:border-orange-500 transition-all">
                            <div className="flex items-center space-x-4 mb-3">
                                <div className="p-3 bg-orange-50 rounded-xl group-hover:bg-orange-600 transition-colors duration-500 shadow-inner">
                                    <Truck className="text-orange-600 group-hover:text-white transition-colors duration-500" size={24} />
                                </div>
                                <div>
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">ยอดขายรวม</p>
                                    <p className="text-2xl font-black text-gray-900 leading-none">฿{totalSell.toLocaleString(undefined, { minimumFractionDigits: 1 })}</p>
                                </div>
                            </div>
                            <div className="flex border-t border-gray-50 pt-3 mt-auto">
                                <div className="flex-1 text-center border-r border-gray-50">
                                    <p className="text-[9px] font-bold text-gray-400 uppercase">น้ำยาง</p>
                                    <p className="text-xs font-black text-blue-700">฿{latexSellTotal.toLocaleString()}</p>
                                </div>
                                <div className="flex-1 text-center">
                                    <p className="text-[9px] font-bold text-gray-400 uppercase">ขี้ยาง</p>
                                    <p className="text-xs font-black text-orange-700">฿{cupLumpSellTotal.toLocaleString()}</p>
                                </div>
                            </div>
                        </div>

                        {/* Net Profit Card */}
                        <div className={`p-5 rounded-2xl border shadow-xl transition-all duration-500 flex flex-col
                            ${netProfit >= 0
                                ? 'bg-gradient-to-br from-[#10b981] via-[#059669] to-[#047857] border-emerald-400 shadow-emerald-200/50' 
                                : 'bg-gradient-to-br from-red-600 via-red-700 to-red-800 border-red-500 shadow-red-200/50'}`}>
                            <div className="flex items-center space-x-4 mb-3">
                                <div className="p-3 bg-white/20 rounded-xl shadow-lg backdrop-blur-md">
                                    <PieChart className="text-white" size={24} />
                                </div>
                                <div>
                                    <p className="text-[10px] font-black text-white/70 uppercase tracking-widest leading-none mb-1">กำไรสุทธิ</p>
                                    <p className="text-2xl font-black text-white leading-none">฿{netProfit.toLocaleString(undefined, { minimumFractionDigits: 1 })}</p>
                                </div>
                            </div>
                            <div className="flex border-t border-white/10 pt-3 mt-auto">
                                <div className="flex-1 text-center border-r border-white/10">
                                    <p className="text-[9px] font-bold text-white/50 uppercase">จ่ายพนักงาน</p>
                                    <p className="text-xs font-black text-white">-฿{totalWage.toLocaleString()}</p>
                                </div>
                                <div className="flex-1 text-center">
                                    <p className="text-[9px] font-bold text-white/50 uppercase">จ่ายทั่วไป</p>
                                    <p className="text-xs font-black text-white">-฿{totalExpense.toLocaleString()}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                );
            })()}
        </div>
    );
};

export default DailySummaryReport;

pages/dashboard/DashboardCharts.jsx.content:
import React from 'react';
import { 
    ResponsiveContainer, LineChart, CartesianGrid, XAxis, YAxis, Tooltip, Line 
} from 'recharts';
import { truncateOneDecimal } from '../../utils/calculations';
import { format } from 'date-fns';
import { th } from 'date-fns/locale';

const DashboardCharts = ({ chartData, priceChartData }) => {
    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Trend Chart */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                    <h2 className="text-lg font-bold text-gray-900 mb-4">แนวโน้มการซื้อ-ขาย (7 วันย้อนหลัง)</h2>
                    <div className="h-72" style={{ minHeight: '288px' }}>
                        <ResponsiveContainer width="100%" height={300}>
                            <LineChart data={chartData} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#6b7280', fontSize: 12 }} dy={10} />
                                <YAxis axisLine={false} tickLine={false} tick={{ fill: '#6b7280', fontSize: 12 }} dx={-10} tickFormatter={(value) => `฿${value / 1000}k`} />
                                <Tooltip
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    formatter={(value) => [`฿${Number(value).toLocaleString()}`, undefined]}
                                />
                                <Line type="monotone" dataKey="ซื้อ" stroke="#3b82f6" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                                <Line type="monotone" dataKey="ขาย" stroke="#f97316" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Price Trend Chart 30 Days */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                    <div className="flex items-center justify-between mb-6">
                        <div>
                            <h2 className="text-lg font-bold text-gray-900">แนวโน้มราคาน้ำยาง (30 วันย้อนหลัง)</h2>
                            <p className="text-xs text-gray-500">เปรียบเทียบราคารับซื้อเฉลี่ย และราคาส่งขายโรงงาน</p>
                        </div>
                        <div className="flex items-center space-x-4">
                            <div className="flex items-center">
                                <div className="w-3 h-3 rounded-full bg-blue-500 mr-2"></div>
                                <span className="text-xs font-medium text-gray-600">รับซื้อ</span>
                            </div>
                            <div className="flex items-center">
                                <div className="w-3 h-3 rounded-full bg-emerald-500 mr-2"></div>
                                <span className="text-xs font-medium text-gray-600">ขายส่ง</span>
                            </div>
                        </div>
                    </div>
                    <div className="h-72" style={{ minHeight: '288px' }}>
                        <ResponsiveContainer width="100%" height={300}>
                            <LineChart data={priceChartData} margin={{ top: 5, right: 30, left: 10, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                                <XAxis 
                                    dataKey="date" 
                                    axisLine={false} 
                                    tickLine={false} 
                                    tick={{ fill: '#9ca3af', fontSize: 10 }} 
                                    dy={10}
                                    interval={window.innerWidth < 768 ? 4 : 2}
                                />
                                <YAxis 
                                    axisLine={false} 
                                    tickLine={false} 
                                    tick={{ fill: '#9ca3af', fontSize: 10 }} 
                                    dx={-10} 
                                    domain={['auto', 'auto']}
                                    tickFormatter={(value) => `฿${value}`}
                                />
                                <Tooltip
                                    contentStyle={{ 
                                        borderRadius: '12px', 
                                        border: 'none', 
                                        boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1)',
                                        padding: '12px'
                                    }}
                                    formatter={(value) => [`฿${Number(value).toLocaleString()}`, undefined]}
                                    labelStyle={{ fontWeight: 'bold', marginBottom: '4px', color: '#111827' }}
                                    cursor={{ stroke: '#f3f4f6', strokeWidth: 2 }}
                                />
                                <Line 
                                    type="monotone" 
                                    dataKey="ราคาซื้อ" 
                                    stroke="#3b82f6" 
                                    strokeWidth={3} 
                                    dot={{ r: 0 }} 
                                    activeDot={{ r: 6, strokeWidth: 0 }} 
                                    connectNulls
                                />
                                <Line 
                                    type="monotone" 
                                    dataKey="ราคาขาย" 
                                    stroke="#10b981" 
                                    strokeWidth={3} 
                                    dot={{ r: 0 }} 
                                    activeDot={{ r: 6, strokeWidth: 0 }} 
                                    connectNulls
                                />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default DashboardCharts;

pages/dashboard/DashboardChemicals.jsx.content:
import React from 'react';
import { FlaskConical, Droplets, Activity } from 'lucide-react';
import { format } from 'date-fns';

const DashboardChemicals = ({ chemicalCalcs, handleRecordChemical, chemicalUsage, stats }) => {
    return (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-black text-gray-900 flex items-center tracking-tight">
                    <FlaskConical className="mr-2 text-purple-600" size={24} />
                    การจัดการน้ำยาง (ปริมาณสารเคมีที่ต้องใช้)
                </h2>
                <div className="px-3 py-1 bg-purple-100 text-purple-700 text-xs font-black rounded-full border border-purple-200 uppercase tracking-widest">
                    Today's Dosage
                </div>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                {chemicalCalcs.map((chem) => {
                    const theme = {
                        amber: 'from-amber-500 to-yellow-500 shadow-amber-200 border-amber-100',
                        blue: 'from-blue-500 to-cyan-500 shadow-blue-200 border-blue-100',
                        purple: 'from-purple-500 to-indigo-500 shadow-purple-200 border-purple-100'
                    }[chem.color] || 'from-gray-500 to-slate-500 shadow-gray-200 border-gray-100';

                    const todayDateStr = format(new Date(), 'yyyy-MM-dd');
                    const isRecorded = chemicalUsage.some(u => u.chemicalId === chem.id && u.date === todayDateStr);

                    return (
                        <div key={chem.id} className={`relative overflow-hidden bg-white border rounded-2xl p-5 shadow-sm hover:shadow-md transition-all group`}>
                            <div className={`absolute top-0 right-0 w-32 h-32 bg-gradient-to-br ${theme} opacity-[0.03] -mr-8 -mt-8 rounded-full group-hover:scale-110 transition-transform`}></div>
                            <div className="flex justify-between items-start mb-3 relative z-10">
                                <div className={`p-3 rounded-xl bg-gradient-to-br ${theme} text-white shadow-lg`}>
                                    {chem.id === 'ammonia' ? <FlaskConical size={20} /> : 
                                     chem.id === 'water' ? <Droplets size={20} /> : 
                                     <Activity size={20} />}
                                </div>
                                <div className="text-right">
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Total Needed</p>
                                    <div className="text-2xl font-black text-gray-900 leading-none">
                                        {chem.result.toLocaleString()} <span className="text-xs font-bold text-gray-400">กก.</span>
                                    </div>
                                </div>
                            </div>
                            <div className="relative z-10">
                                <h3 className="font-bold text-gray-800 text-sm">{chem.name}</h3>
                                <p className="text-[10px] text-gray-400 font-medium">
                                    อัตราส่วน: {chem.amount} กก. / น้ำยาง {Number(chem.perLatex).toLocaleString()} กก.
                                </p>
                            </div>
                            <div className="flex justify-between items-center mt-4">
                                <div className="h-1 flex-1 bg-gray-100 rounded-full overflow-hidden mr-4">
                                    <div className={`h-full bg-gradient-to-r ${theme} transition-all duration-1000`} style={{ width: stats.todayBuyWeight > 0 ? '100%' : '0%' }}></div>
                                </div>
                                <button
                                    onClick={() => handleRecordChemical(chem)}
                                    disabled={isRecorded || stats.todayBuyWeight === 0}
                                    className={`px-4 py-1.5 rounded-lg text-xs font-black transition-all ${
                                        isRecorded 
                                        ? 'bg-green-100 text-green-700 cursor-default opacity-100' 
                                        : stats.todayBuyWeight === 0 
                                            ? 'bg-gray-100 text-gray-400 cursor-not-allowed opacity-50'
                                            : 'bg-white border-2 hover:bg-gray-50 active:scale-95 shadow-sm'
                                    } ${!isRecorded && stats.todayBuyWeight > 0 ? (
                                        chem.color === 'amber' ? 'border-amber-200 text-amber-700' : 
                                        chem.color === 'blue' ? 'border-blue-200 text-blue-700' : 
                                        'border-purple-200 text-purple-700'
                                    ) : ''}`}
                                >
                                    {isRecorded ? 'บันทึกแล้ว ✓' : 'บันทึก'}
                                </button>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default DashboardChemicals;

pages/dashboard/DashboardModals.jsx.content:
import React from 'react';
import { Wallet, Gift } from 'lucide-react';

const WageConfirmModal = ({ 
    wageConfirmData, setWageConfirmData, confirmAndRecordWages, stats 
}) => {
    if (!wageConfirmData.show) return null;

    return (
        <div className="fixed inset-0 bg-black/50 z-[200] flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full p-6">
                <div className="flex items-center mb-4">
                    <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center mr-3">
                        <Wallet className="text-blue-600" size={20} />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">ยืนยันบันทึกค่าจ้าง</h3>
                </div>
                <p className="text-sm text-gray-600 mb-3">
                    พนักงานที่ยังไม่ได้บันทึกวันนี้ <strong>{wageConfirmData.unpaidStaff.length} คน</strong>:
                </p>
                <ul className="text-sm text-gray-700 mb-3 space-y-1 max-h-32 overflow-y-auto bg-gray-50 rounded-lg p-3">
                    {wageConfirmData.unpaidStaff.map(s => (
                        <li key={s.id} className="flex justify-between">
                            <span className="font-medium">{s.name}</span>
                            <span className="text-gray-500">ค่าจ้าง ฿{(Number(s.salary)||0).toLocaleString()} + โบนัส ฿{wageConfirmData.bonus}</span>
                        </li>
                    ))}
                </ul>
                <p className="text-xs text-gray-400 mb-4">โบนัสคำนวณจากน้ำยาง {stats.todayBuyWeight.toLocaleString()} กก. = ฿{wageConfirmData.bonus}/คน</p>
                <div className="flex space-x-3">
                    <button onClick={() => setWageConfirmData({ show: false, unpaidStaff: [], bonus: 0 })}
                        className="flex-1 px-4 py-2 text-sm text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg font-medium">ยกเลิก</button>
                    <button onClick={confirmAndRecordWages}
                        className="flex-1 px-4 py-2 text-sm text-white bg-blue-600 hover:bg-blue-700 rounded-lg font-bold">ยืนยัน บันทึกค่าจ้าง</button>
                </div>
            </div>
        </div>
    );
};

const LuckyDrawModal = ({
    showLuckyDraw, setShowLuckyDraw, isSpinning, winner, luckyStartDate, setLuckyStartDate,
    luckyEndDate, setLuckyEndDate, startLuckyDraw, rewardName, setRewardName, handleSaveWinner,
    savingReward
}) => {
    if (!showLuckyDraw) return null;

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                <div className="bg-gradient-to-r from-yellow-400 to-yellow-500 p-6 text-white text-center rounded-t-2xl relative">
                    <button onClick={() => !isSpinning && setShowLuckyDraw(false)} className="absolute top-4 right-4 text-white/80 hover:text-white">ปิด</button>
                    <Gift size={48} className="mx-auto mb-2 opacity-90" />
                    <h2 className="text-2xl font-black tracking-tight">จับผู้โชคดีสุ่มแจกรางวัล</h2>
                    <p className="text-yellow-100 text-sm mt-1">สุ่มรางวัลจากรายชื่อเกษตรกรที่นำยางมาขาย</p>
                </div>

                <div className="p-6">
                    <div className="grid grid-cols-2 gap-3 mb-6">
                        <div>
                            <label className="block text-xs font-bold text-gray-500 mb-1">เริ่มต้น:</label>
                            <input 
                                type="date" 
                                value={luckyStartDate} 
                                onChange={e => setLuckyStartDate(e.target.value)}
                                disabled={isSpinning}
                                className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-gray-500 mb-1">สิ้นสุด:</label>
                            <input 
                                type="date" 
                                value={luckyEndDate} 
                                onChange={e => setLuckyEndDate(e.target.value)}
                                disabled={isSpinning}
                                className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500"
                            />
                        </div>
                    </div>

                    <div className="bg-gray-50 rounded-xl border-2 border-dashed border-gray-300 p-6 min-h-[140px] flex flex-col items-center justify-center relative overflow-hidden mb-6">
                        {!winner && !isSpinning ? (
                            <p className="text-gray-400 font-medium text-center">กดปุ่มเริ่มสุ่มเพื่อหาผู้โชคดี</p>
                        ) : (
                            <div className={`text-center transition-all ${isSpinning ? 'scale-105 opacity-80 blur-[1px]' : 'scale-110 opacity-100'}`}>
                                <p className="text-xs font-bold text-gray-500 mb-1">เลขที่บิล: {winner?.id}</p>
                                <h3 className="text-3xl font-black text-gray-900 mb-2 truncate max-w-[280px]">{winner?.farmerName}</h3>
                                <div className="inline-block bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-bold">
                                    น้ำยาง: {winner?.weight} กก.
                                </div>
                            </div>
                        )}
                    </div>

                    {!isSpinning && winner && (
                        <div className="mb-6 animate-in slide-in-from-bottom-2">
                            <label className="block text-sm font-bold text-gray-700 mb-2">🎈 รางวัลที่จะให้:</label>
                            <input 
                                type="text" 
                                value={rewardName}
                                onChange={e => setRewardName(e.target.value)}
                                placeholder="ไข่ไก่ 1 แผง, ปุ๋ยเคมี 1 กระสอบ..."
                                className="w-full px-4 py-3 border border-yellow-300 rounded-lg focus:ring-2 focus:ring-yellow-500 shadow-sm"
                                autoFocus
                            />
                        </div>
                    )}

                    <div className="mt-2">
                        <div className="flex flex-col space-y-2">
                            {!winner || isSpinning ? (
                                <button 
                                    onClick={startLuckyDraw}
                                    disabled={isSpinning}
                                    className={`w-full py-4 rounded-xl font-black text-base text-white shadow-lg transition-all transform active:scale-95 ${isSpinning ? 'bg-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-rubber-600 to-rubber-700 hover:shadow-rubber-200'}`}
                                >
                                    {isSpinning ? (
                                        <div className="flex items-center justify-center space-x-2">
                                            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                            <span>กำลังสุ่มผู้โชคดี...</span>
                                        </div>
                                    ) : (
                                        <div className="flex items-center justify-center space-x-2">
                                            <Gift size={20} />
                                            <span>🎯 เริ่มสุ่มรางวัลตอนนี้</span>
                                        </div>
                                    )}
                                </button>
                            ) : (
                                <>
                                    <button 
                                        onClick={handleSaveWinner}
                                        disabled={savingReward}
                                        className="w-full py-4 rounded-xl font-black text-base text-white shadow-lg bg-gradient-to-r from-yellow-500 to-orange-500 hover:shadow-yellow-200 transition-all transform active:scale-95 flex justify-center items-center space-x-2"
                                    >
                                        {savingReward ? (
                                             <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                        ) : <Gift size={20} />}
                                        <span>{savingReward ? 'กำลังบันทึก...' : 'บันทึกรางวัลผู้โชคดี'}</span>
                                    </button>
                                    <button 
                                        onClick={startLuckyDraw}
                                        className="w-full py-2 rounded-xl font-bold text-sm text-gray-400 hover:text-gray-600 hover:bg-gray-50 transition-all underline decoration-dotted"
                                    >
                                        สุ่มผู้โชคดีคนถัดไป
                                    </button>
                                </>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export { WageConfirmModal, LuckyDrawModal };

