import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { User, Phone, MapPin, Database, Save, Loader2, CheckCircle2 } from 'lucide-react';
import liff from '@line/liff';
import { getLiffFarmer, updateLiffFarmer } from '../services/liffService';
import toast from 'react-hot-toast';

const LIFFProfile = () => {
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [profile, setProfile] = useState(null);
    const [success, setSuccess] = useState(false);
    const { register, handleSubmit, reset } = useForm();

    useEffect(() => {
        const init = async () => {
            try {
                const urlParams = new URLSearchParams(window.location.search);
                const shopId = urlParams.get('shopId');

                // Get dynamic LIFF ID if shopId is provided
                let liffId = '2009445413-LKTCq5J8'; // Default
                if (shopId) {
                    try {
                        const sRes = await fetch(`/api/liff-settings?shopId=${shopId}`);
                        if (sRes.ok) {
                            const settings = await sRes.json();
                            if (settings.lineLiffIdProfile) liffId = settings.lineLiffIdProfile;
                        }
                    } catch (e) {
                        console.error("Failed to load shop-specific LIFF settings");
                    }
                }

                await liff.init({ liffId });
                
                if (!liff.isLoggedIn()) {
                    liff.login();
                    return;
                }

                const lineProfile = await liff.getProfile();
                setProfile(lineProfile);
                
                const accessToken = liff.getAccessToken();
                const res = await getLiffFarmer(lineProfile.userId, accessToken);
                
                if (res.status === 'success' && res.data) {
                    reset(res.data);
                } else {
                    // Pre-fill name from LINE if first time
                    reset({ name: lineProfile.displayName });
                }
            } catch (err) {
                console.error('LIFF Init Error:', err);
                toast.error('ไม่สามารถโหลดข้อมูล LINE ได้');
            } finally {
                setLoading(false);
            }
        };
        init();
    }, [reset]);

    const onSubmit = async (data) => {
        setSaving(true);
        try {
            const accessToken = liff.getAccessToken();
            const res = await updateLiffFarmer(profile.userId, accessToken, data);
            if (res.status === 'success') {
                setSuccess(true);
                toast.success('บันทึกข้อมูลสำเร็จ');
                setTimeout(() => liff.closeWindow(), 2000);
            } else {
                toast.error('บันทึกล้มเหลว: ' + res.message);
            }
        } catch (err) {
            toast.error('เกิดข้อผิดพลาดในการบันทึก');
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
                <div className="text-center">
                    <Loader2 className="w-10 h-10 text-rubber-600 animate-spin mx-auto mb-4" />
                    <p className="text-gray-500 font-medium">กำลังโหลดข้อมูลเกษตรกร...</p>
                </div>
            </div>
        );
    }

    if (success) {
        return (
            <div className="min-h-screen bg-white flex items-center justify-center p-6">
                <div className="text-center animate-in zoom-in duration-300">
                    <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
                        <CheckCircle2 className="w-12 h-12 text-green-600" />
                    </div>
                    <h1 className="text-2xl font-bold text-gray-900 mb-2">บันทึกข้อมูลสำรเร็จ</h1>
                    <p className="text-gray-500">ระบบกำลังปิดหน้าต่างนี้อัตโนมัติ...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 pb-12">
            <div className="bg-rubber-600 pt-8 pb-16 px-6 text-white text-center">
                {profile?.pictureUrl && (
                    <img 
                        src={profile.pictureUrl} 
                        alt="Profile" 
                        className="w-20 h-20 rounded-full border-4 border-white/20 mx-auto mb-4 shadow-lg"
                    />
                )}
                <h1 className="text-xl font-bold">ข้อมูลส่วนตัวเกษตรกร</h1>
                <p className="text-rubber-100 text-sm opacity-80 mt-1">จัดการข้อมูลบัญชีและที่อยู่ของคุณ</p>
            </div>

            <div className="px-5 -mt-8">
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 space-y-5">
                        <div className="space-y-1.5">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-wider flex items-center">
                                <User size={14} className="mr-1.5" />
                                ชื่อ-นามสกุล
                            </label>
                            <input 
                                {...register('name', { required: true })}
                                className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-rubber-500 text-gray-900 font-medium"
                                placeholder="นายสมชาย ใจดี"
                            />
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-wider flex items-center">
                                <Phone size={14} className="mr-1.5" />
                                เบอร์โทรศัพท์
                            </label>
                            <input 
                                {...register('phone')}
                                className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-rubber-500 text-gray-900 font-medium"
                                placeholder="08x-xxx-xxxx"
                            />
                        </div>

                        <div className="grid grid-cols-1 gap-5">
                            <div className="space-y-1.5 text-left">
                                <label className="text-xs font-black text-gray-400 uppercase tracking-wider flex items-center">
                                    <Database size={14} className="mr-1.5" />
                                    ธนาคาร
                                </label>
                                <input 
                                    {...register('bankName')}
                                    className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-rubber-500 text-gray-900 font-medium"
                                    placeholder="เช่น กสิกรไทย"
                                />
                            </div>
                            <div className="space-y-1.5 text-left">
                                <label className="text-xs font-black text-gray-400 uppercase tracking-wider">
                                    เลขบัญชีธนาคาร
                                </label>
                                <input 
                                    {...register('bankAccount')}
                                    className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-rubber-500 text-gray-900 font-medium"
                                    placeholder="xxx-x-xxxxx-x"
                                />
                            </div>
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-wider flex items-center">
                                <MapPin size={14} className="mr-1.5" />
                                ที่อยู่
                            </label>
                            <textarea 
                                {...register('address')}
                                rows={3}
                                className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-rubber-500 text-gray-900 font-medium"
                                placeholder="บ้านเลขที่ ตำบล อำเภอ..."
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={saving}
                        className="w-full py-4 bg-rubber-600 text-white rounded-2xl font-bold shadow-lg shadow-rubber-200 active:scale-[0.98] transition-all flex items-center justify-center disabled:opacity-70"
                    >
                        {saving ? (
                            <Loader2 className="w-5 h-5 animate-spin mr-2" />
                        ) : (
                            <Save size={20} className="mr-2" />
                        )}
                        บันทึกข้อมูล
                    </button>
                    
                    <p className="text-center text-[11px] text-gray-400 px-6">
                        ข้อมูลนี้จะถูกส่งไปยังโรงงานเพื่อให้การรับซื่้อและโอนเงินเป็นไปอย่างถูกต้อง
                    </p>
                </form>
            </div>
        </div>
    );
};

export default LIFFProfile;

pages/Login.jsx.content:
import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate, Navigate } from 'react-router-dom';
import { Leaf } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { getScriptUrl } from '../services/apiService';
import toast from 'react-hot-toast';

export const Login = () => {
    const [loading, setLoading] = useState(false);
    const { loginWithGoogle, user, isLoading } = useAuth();
    const navigate = useNavigate();

    // Show loading while checking initial session
    if (isLoading) {
        return (
            <div className="min-h-screen bg-rubber-50 flex items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-rubber-600"></div>
            </div>
        )
    }

    // Redirect if already logged in
    if (user) {
        return <Navigate to="/" replace />;
    }

    const handleGoogleLogin = async () => {
        setLoading(true);
        try {
            await loginWithGoogle();
        } catch (err) {
            toast.error('เกิดข้อผิดพลาดในการเชื่อมต่อกับ Google');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };



    return (
        <div className="min-h-screen bg-rubber-50 flex items-center justify-center p-4">
            <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">

                <div className="bg-rubber-600 p-8 text-center">
                    <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-inner">
                        <Leaf size={32} className="text-rubber-600" />
                    </div>
                    <h2 className="text-3xl font-bold text-white mb-2">ระบบจัดการรับซื้อ</h2>
                    <p className="text-rubber-100">น้ำยางพารา (Rubber Trade)</p>
                </div>

                <div className="p-8 space-y-6">
                    <p className="text-gray-600 text-center">
                        กรุณาเข้าสู่ระบบด้วยบัญชี Google เพื่อใช้งานระบบ
                    </p>

                    <button
                        onClick={handleGoogleLogin}
                        disabled={loading}
                        className="w-full flex items-center justify-center gap-3 py-3 px-4 border border-gray-300 rounded-lg shadow-sm text-base font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-rubber-500 disabled:opacity-50 transition-all duration-200"
                    >
                        {loading ? (
                            <span>กำลังเชื่อมต่อ...</span>
                        ) : (
                            <>
                                <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" className="w-6 h-6" />
                                <span>เข้าสู่ระบบด้วย Google</span>
                            </>
                        )}
                    </button>

                    <div className="text-center text-xs text-gray-400 mt-8">
                        &copy; {new Date().getFullYear()} Rubber Trade .co
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;

