import React, { useState, useEffect, useMemo } from 'react';
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameDay, parseISO } from 'date-fns';
import { th } from 'date-fns/locale';
import { 
    Calendar, Download, TrendingUp, TrendingDown, 
    Droplets, ShoppingCart, BarChart3, ChevronLeft, 
    ChevronRight, Filter, FileSpreadsheet
} from 'lucide-react';
import { fetchBuyRecords, fetchSellRecords, fetchExpenses, fetchWages, isCached } from '../services/apiService';
import { truncateOneDecimal } from '../utils/calculations';

export const MonthlyReport = () => {
    const [loading, setLoading] = useState(true);
    const [buys, setBuys] = useState([]);
    const [sells, setSells] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [wages, setWages] = useState([]);
    const [selectedMonth, setSelectedMonth] = useState(new Date());

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        if (!isCached('buys', 'sells', 'expenses', 'wages')) setLoading(true);
        try {
            const [b, s, exp, w] = await Promise.all([
                fetchBuyRecords(),
                fetchSellRecords(),
                fetchExpenses(),
                fetchWages()
            ]);
            setBuys(Array.isArray(b) ? b : []);
            setSells(Array.isArray(s) ? s : []);
            setExpenses(Array.isArray(exp) ? exp : []);
            setWages(Array.isArray(w) ? w : []);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const reportData = useMemo(() => {
        const start = startOfMonth(selectedMonth);
        const end = endOfMonth(selectedMonth);
        const days = eachDayOfInterval({ start, end });

        const dailyData = days.map(day => {
            const dateStr = format(day, 'yyyy-MM-dd');
            
            const dayBuys = buys.filter(b => b.date === dateStr);
            const daySells = sells.filter(s => s.date === dateStr);
            const dayExp = expenses.filter(e => e.date === dateStr);
            const dayWage = wages.filter(w => w.date === dateStr);

            const buyTotal = dayBuys.reduce((sum, b) => sum + Number(b.total || 0), 0);
            const sellTotal = daySells.reduce((sum, s) => sum + Number(s.total || 0), 0);
            const expTotal = dayExp.reduce((sum, e) => sum + Number(e.amount || 0), 0) + 
                             dayWage.reduce((sum, w) => sum + Number(w.total || 0), 0);
            
            const profit = sellTotal - buyTotal - expTotal;

            return {
                date: day,
                dateStr,
                buyTotal,
                sellTotal,
                expTotal,
                profit
            };
        });

        const totalBuy = dailyData.reduce((sum, d) => sum + d.buyTotal, 0);
        const totalSell = dailyData.reduce((sum, d) => sum + d.sellTotal, 0);
        const totalExp = dailyData.reduce((sum, d) => sum + d.expTotal, 0);
        const totalProfit = totalSell - totalBuy - totalExp;

        return {
            dailyData,
            totals: {
                buy: totalBuy,
                sell: totalSell,
                expenses: totalExp,
                profit: totalProfit
            }
        };
    }, [buys, sells, expenses, wages, selectedMonth]);

    const handlePrevMonth = () => {
        setSelectedMonth(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
    };

    const handleNextMonth = () => {
        setSelectedMonth(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
    };

    const exportToCSV = () => {
        const headers = ['วันที่', 'ยอดซื้อ (บาท)', 'ยอดขาย (บาท)', 'ค่าใช้จ่าย (บาท)', 'กำไร/ขาดทุน (บาท)'];
        const rows = reportData.dailyData.map(d => [
            format(d.date, 'dd/MM/yyyy'),
            d.buyTotal.toFixed(2),
            d.sellTotal.toFixed(2),
            d.expTotal.toFixed(2),
            d.profit.toFixed(2)
        ]);

        const csvContent = [
            headers.join(','),
            ...rows.map(r => r.join(','))
        ].join('\n');

        const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute('download', `รายงานยอดขาย_${format(selectedMonth, 'MMMM_yyyy', { locale: th })}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-10">
            {/* Header section */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                <div>
                    <h1 className="text-2xl font-black text-gray-900 flex items-center">
                        <BarChart3 className="mr-3 text-rubber-600" size={28} />
                        รายงานยอดขายประจำเดือน
                    </h1>
                    <p className="text-gray-500 font-medium">สรุปรายรับ-รายจ่ายรายวัน ประจำเดือน {format(selectedMonth, 'MMMM yyyy', { locale: th })}</p>
                </div>

                <div className="flex items-center gap-3">
                    <div className="flex items-center bg-gray-100 rounded-xl p-1 border border-gray-200">
                        <button onClick={handlePrevMonth} className="p-2 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600">
                            <ChevronLeft size={20} />
                        </button>
                        <span className="px-4 py-1 text-sm font-black text-gray-900 min-w-[140px] text-center">
                            {format(selectedMonth, 'MMMM yyyy', { locale: th })}
                        </span>
                        <button onClick={handleNextMonth} className="p-2 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600">
                            <ChevronRight size={20} />
                        </button>
                    </div>
                    <button 
                        onClick={exportToCSV}
                        className="flex items-center px-4 py-2.5 bg-green-600 hover:bg-green-700 text-white rounded-xl font-bold transition-all shadow-md shadow-green-100 text-sm whitespace-nowrap"
                    >
                        <FileSpreadsheet size={18} className="mr-2" />
                        Export CSV
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-rubber-600"></div>
                </div>
            ) : (
                <>
                    {/* Summary Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-20 h-20 bg-blue-50 rounded-full group-hover:scale-150 transition-transform duration-500 z-0"></div>
                            <div className="relative z-10">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <ShoppingCart size={12} className="mr-2 text-blue-500" /> ยอดรับซื้อรวม
                                </p>
                                <p className="text-2xl font-black text-gray-900 italic">
                                    ฿{reportData.totals.buy.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                </p>
                            </div>
                        </div>

                        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-20 h-20 bg-orange-50 rounded-full group-hover:scale-150 transition-transform duration-500 z-0"></div>
                            <div className="relative z-10">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <TrendingUp size={12} className="mr-2 text-orange-500" /> ยอดขายรวม
                                </p>
                                <p className="text-2xl font-black text-gray-900 italic">
                                    ฿{reportData.totals.sell.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                </p>
                            </div>
                        </div>

                        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-20 h-20 bg-red-50 rounded-full group-hover:scale-150 transition-transform duration-500 z-0"></div>
                            <div className="relative z-10">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <TrendingDown size={12} className="mr-2 text-red-500" /> ค่าใช้จ่ายรวม
                                </p>
                                <p className="text-2xl font-black text-gray-900 italic">
                                    ฿{reportData.totals.expenses.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                </p>
                            </div>
                        </div>

                        <div className={`p-5 rounded-2xl border shadow-sm relative overflow-hidden group transition-all ${reportData.totals.profit >= 0 ? 'bg-white border-gray-100' : 'bg-red-50 border-red-100'}`}>
                            <div className={`absolute -right-6 -bottom-6 w-20 h-20 rounded-full group-hover:scale-150 transition-transform duration-500 z-0 ${reportData.totals.profit >= 0 ? 'bg-green-50' : 'bg-red-100/50'}`}></div>
                            <div className="relative z-10">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    {reportData.totals.profit >= 0 ? <TrendingUp size={12} className="mr-2 text-green-500" /> : <TrendingDown size={12} className="mr-2 text-red-500" />}
                                    กำไรสุทธิจริง
                                </p>
                                <p className={`text-2xl font-black italic ${reportData.totals.profit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                    {reportData.totals.profit >= 0 ? '+' : ''}฿{reportData.totals.profit.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                </p>
                            </div>
                        </div>
                    </div>

                    {/* Table section */}
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                        <div className="p-4 bg-gray-50/50 border-b border-gray-100 flex justify-between items-center">
                            <h3 className="font-bold text-gray-700">รายละเอียดรายวัน</h3>
                            <div className="flex items-center text-xs font-bold text-gray-400 uppercase tracking-tighter">
                                <Filter size={12} className="mr-1.5" /> แสดงข้อมูลเฉพาะวันที่มีความเคลื่อนไหว
                            </div>
                        </div>
                        <div className="overflow-x-auto">
                            <table className="min-w-full divide-y divide-gray-200">
                                <thead className="bg-gray-50/50">
                                    <tr>
                                        <th className="px-6 py-4 text-left text-xs font-black text-gray-500 uppercase tracking-widest">วันที่</th>
                                        <th className="px-6 py-4 text-right text-xs font-black text-gray-500 uppercase tracking-widest">ยอดรับซื้อ (฿)</th>
                                        <th className="px-6 py-4 text-right text-xs font-black text-gray-500 uppercase tracking-widest">ยอดขาย (฿)</th>
                                        <th className="px-6 py-4 text-right text-xs font-black text-gray-500 uppercase tracking-widest">ค่าใช้จ่าย (฿)</th>
                                        <th className="px-6 py-4 text-right text-xs font-black text-gray-500 uppercase tracking-widest">สุทธิ (฿)</th>
                                    </tr>
                                </thead>
                                <tbody className="bg-white divide-y divide-gray-100">
                                    {reportData.dailyData.filter(d => d.buyTotal > 0 || d.sellTotal > 0 || d.expTotal > 0).map((day, idx) => (
                                        <tr key={day.dateStr} className="hover:bg-gray-50/80 transition-colors">
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="text-sm font-bold text-gray-900">{format(day.date, 'dd MMMM yyyy', { locale: th })}</div>
                                                <div className="text-[10px] text-gray-400 font-medium uppercase tracking-tighter">{format(day.date, 'EEEE', { locale: th })}</div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                <span className="text-sm font-bold text-blue-600">
                                                    {day.buyTotal > 0 ? day.buyTotal.toLocaleString(undefined, { minimumFractionDigits: 1 }) : '-'}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                <span className="text-sm font-bold text-orange-600">
                                                    {day.sellTotal > 0 ? day.sellTotal.toLocaleString(undefined, { minimumFractionDigits: 1 }) : '-'}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right text-red-500 text-sm font-bold">
                                                {day.expTotal > 0 ? day.expTotal.toLocaleString(undefined, { minimumFractionDigits: 1 }) : '-'}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                <div className={`text-sm font-black ${day.profit >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                                                    {day.profit !== 0 ? (day.profit > 0 ? '+' : '') + day.profit.toLocaleString(undefined, { minimumFractionDigits: 1 }) : '0.0'}
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    {reportData.dailyData.filter(d => d.buyTotal > 0 || d.sellTotal > 0 || d.expTotal > 0).length === 0 && (
                                        <tr>
                                            <td colSpan="4" className="px-6 py-12 text-center text-gray-400 italic">
                                                ไม่มีรายการเคลื่อนไหวในเดือนนี้
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                                <tfoot className="bg-gray-900 text-white">
                                    <tr>
                                        <td className="px-6 py-4 font-black text-sm">ยอดรวมทั้งเดือน</td>
                                        <td className="px-6 py-4 text-right font-black text-sm text-blue-400">
                                            {reportData.totals.buy.toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                        <td className="px-6 py-4 text-right font-black text-sm text-orange-400">
                                            {reportData.totals.sell.toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                        <td className="px-6 py-4 text-right font-black text-sm text-red-400">
                                            {reportData.totals.expenses.toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                        <td className={`px-6 py-4 text-right font-black text-sm ${reportData.totals.profit >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                                            {reportData.totals.profit.toLocaleString(undefined, { minimumFractionDigits: 1 })}
                                        </td>
                                    </tr>
                                </tfoot>
                            </table>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

export default MonthlyReport;

pages/Payments.jsx.content:
import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import { th } from 'date-fns/locale';
import { 
    Wallet, 
    Search, 
    CheckCircle2, 
    Clock, 
    QrCode, 
    User, 
    Users, 
    ArrowRight,
    Filter,
    FileText,
    Calendar,
    X,
    ExternalLink
} from 'lucide-react';
import toast from 'react-hot-toast';
import { fetchBuyRecords, fetchFarmers, fetchEmployees, updateRecord, isCached } from '../services/apiService';

export const Payments = () => {
    const [records, setRecords] = useState([]);
    const { user } = useAuth();
    const [farmers, setFarmers] = useState([]);
    const [employees, setEmployees] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filterDate, setFilterDate] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedPayment, setSelectedPayment] = useState(null); // { type: 'farmer'|'employee', amount, name, targetId, buyId }
    const [statusUpdating, setStatusUpdating] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        if (!isCached('buys', 'farmers', 'employees')) setLoading(true);
        try {
            const [buysData, farmersData, empsData] = await Promise.all([
                fetchBuyRecords(),
                fetchFarmers(),
                fetchEmployees()
            ]);
            setRecords(Array.isArray(buysData) ? buysData : []);
            setFarmers(Array.isArray(farmersData) ? farmersData : []);
            setEmployees(Array.isArray(empsData) ? empsData : []);
        } catch (error) {
            toast.error('โหลดข้อมูลล้มเหลว');
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateStatus = async (buyId, field, newStatus) => {
        setStatusUpdating(true);
        try {
            const updates = { [field]: newStatus };
            // For backward compatibility, also update 'status' if both are paid or if we want to maintain the old field
            // But let's mainly focus on the new fields.
            const res = await updateRecord('buys', buyId, updates);
            if (res.status === 'success') {
                toast.success('อัปเดตสถานะสำเร็จ');
                setRecords(prev => prev.map(r => r.id === buyId ? { ...r, ...updates } : r));
            } else {
                toast.error(res.message || 'อัปเดตล้มเหลว');
            }
        } catch (error) {
            toast.error('เกิดข้อผิดพลาด: ' + error.message);
        } finally {
            setStatusUpdating(false);
        }
    };

    const openQRModal = (type, amount, name, targetId, buyId) => {
        // Resolve target info (phone/account)
        let promptpayId = '';
        if (type === 'farmer') {
            const farmer = farmers.find(f => f.id === targetId);
            promptpayId = farmer?.phone || farmer?.bankAccount || '';
        } else {
            const emp = employees.find(e => e.id === targetId);
            promptpayId = emp?.phone || emp?.bankAccount || '';
        }

        if (!promptpayId) {
            toast.error('ไม่พบเลขบัญชีหรือเบอร์โทรศัพท์สำหรับสร้าง QR Code');
            return;
        }

        setSelectedPayment({ type, amount, name, promptpayId, buyId });
    };

    const filteredRecords = records.filter(r => {
        const recordDate = (r.date || '').split('T')[0];
        const matchDate = recordDate.startsWith(filterDate);
        const matchSearch = (r.farmerName || '').toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (r.id || '').toLowerCase().includes(searchTerm.toLowerCase());
        return matchDate && matchSearch;
    });

    const pendingCount = filteredRecords.reduce((count, r) => {
        let p = 0;
        if (r.farmerStatus !== 'Paid') p++;
        if (r.employeeTotal > 0 && r.employeeStatus !== 'Paid') p++;
        return count + p;
    }, 0);

    const totalToPay = filteredRecords.reduce((sum, r) => {
        let amt = 0;
        if (r.farmerStatus !== 'Paid') amt += Number(r.farmerTotal || r.total || 0);
        if (r.employeeTotal > 0 && r.employeeStatus !== 'Paid') amt += Number(r.employeeTotal || 0);
        return sum + amt;
    }, 0);

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900 mb-1">การชำระเงิน</h1>
                    <p className="text-gray-500">จัดการการโอนเงินให้แก่เกษตรกรและลูกจ้างประจำวัน</p>
                </div>
                
                <div className="flex items-center gap-3">
                    <div className="bg-white px-4 py-2 rounded-lg border border-gray-200 shadow-sm flex items-center">
                        <Calendar size={18} className="text-gray-400 mr-2" />
                        <input 
                            type="date" 
                            value={filterDate} 
                            onChange={(e) => setFilterDate(e.target.value)}
                            className="text-sm font-medium focus:outline-none border-none p-0"
                        />
                    </div>
                </div>
            </div>

            {/* Stats Overview */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-sm font-medium text-gray-500">รายการที่รอจ่าย</span>
                        <div className="p-2 bg-amber-50 rounded-lg text-amber-600">
                            <Clock size={20} />
                        </div>
                    </div>
                    <div className="text-2xl font-bold text-gray-900">{pendingCount} รายการ</div>
                </div>
                
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-sm font-medium text-gray-500">ยอดเงินคงค้างรวม</span>
                        <div className="p-2 bg-blue-50 rounded-lg text-blue-600">
                            <Wallet size={20} />
                        </div>
                    </div>
                    <div className="text-2xl font-bold text-blue-600">฿ {totalToPay.toLocaleString(undefined, { minimumFractionDigits: 2 })}</div>
                </div>

                <div className="hidden lg:block bg-rubber-600 p-5 rounded-xl text-white shadow-md relative overflow-hidden">
                    <div className="relative z-10">
                        <p className="text-sm opacity-80 mb-1">คำแนะนำ</p>
                        <p className="text-xs">เลือกรายการที่ต้องการโอนเงิน จากนั้นกดปุ่ม "QR" เพื่อแสดงช่องทางการชำระเงิน</p>
                    </div>
                    <QrCode size={80} className="absolute -right-4 -bottom-4 opacity-10" />
                </div>
            </div>

            {/* Filter Bar */}
            <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text" 
                        placeholder="ชื่อเกษตรกร หรือเลขที่ใบเสร็จ..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-rubber-500 outline-none transition-all"
                    />
                </div>
                <button 
                    onClick={loadData}
                    className="px-4 py-2 text-sm font-medium text-gray-600 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 flex items-center justify-center gap-2"
                >
                    <Filter size={16} /> ล้างการค้นหา
                </button>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">รายการ/สถานะ</th>
                                <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">เกษตรกร/ยอดโอน</th>
                                <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">ลูกจ้าง (ถ้ามี)/ยอดโอน</th>
                                <th className="px-6 py-4 text-right text-xs font-semibold text-gray-500 uppercase tracking-wider">ยอดรวมสุทธิ</th>
                                <th className="px-6 py-4 text-center text-xs font-semibold text-gray-500 uppercase tracking-wider">จัดการ</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {loading ? (
                                <tr>
                                    <td colSpan="5" className="px-6 py-12 text-center text-gray-500">กำลังโหลด...</td>
                                </tr>
                            ) : filteredRecords.length === 0 ? (
                                <tr>
                                    <td colSpan="5" className="px-6 py-12 text-center text-gray-500">
                                        <FileText size={48} className="mx-auto mb-3 opacity-20" />
                                        ไม่พบข้อมูลการชำระเงินสำหรับวันที่เลือก
                                    </td>
                                </tr>
                            ) : (
                                filteredRecords.map((r) => {
                                    const farmerPaid = r.farmerStatus === 'Paid';
                                    const employeePaid = r.employeeStatus === 'Paid';
                                    const recordEmp = employees.find(e => e.farmerId === r.farmerId);
                                    const hasEmployee = r.employeeTotal > 0;
                                    
                                    return (
                                        <tr key={r.id} className="hover:bg-gray-50/50 transition-colors">
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="flex flex-col gap-1.5">
                                                    <span className="text-[10px] font-bold text-gray-400">#{r.id?.substring(0, 8)}</span>
                                                    <div className="flex flex-col gap-1">
                                                        <div className="flex items-center gap-1.5">
                                                            <span className="text-[9px] font-bold text-gray-400 w-10">เกษตรกร:</span>
                                                            {farmerPaid ? (
                                                                <span className="px-1.5 py-0.5 bg-emerald-50 text-emerald-600 text-[9px] font-bold rounded">โอนแล้ว</span>
                                                            ) : (
                                                                <span className="px-1.5 py-0.5 bg-amber-50 text-amber-600 text-[9px] font-bold rounded">รอโอน</span>
                                                            )}
                                                        </div>
                                                        {hasEmployee && (
                                                            <div className="flex items-center gap-1.5">
                                                                <span className="text-[9px] font-bold text-gray-400 w-10">ลูกจ้าง:</span>
                                                                {employeePaid ? (
                                                                    <span className="px-1.5 py-0.5 bg-emerald-50 text-emerald-600 text-[9px] font-bold rounded">โอนแล้ว</span>
                                                                ) : (
                                                                    <span className="px-1.5 py-0.5 bg-amber-50 text-amber-600 text-[9px] font-bold rounded">รอโอน</span>
                                                                )}
                                                            </div>
                                                        )}
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="flex flex-col">
                                                    <div className="flex items-center gap-1.5 text-sm font-bold text-gray-900 mb-1">
                                                        <User size={14} className="text-blue-500" />
                                                        {r.farmerName}
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        <span className={`text-sm font-black ${farmerPaid ? 'text-gray-400 italic line-through' : 'text-gray-700'}`}>
                                                            ฿ {(r.farmerTotal || r.total).toLocaleString()}
                                                        </span>
                                                        <div className="flex items-center gap-1">
                                                            {!farmerPaid ? (
                                                                <>
                                                                    <button 
                                                                        onClick={() => openQRModal('farmer', r.farmerTotal || r.total, r.farmerName, r.farmerId, r.id)}
                                                                        className="p-1 text-blue-500 hover:bg-blue-50 rounded transition-colors"
                                                                        title="แสดง QR Code"
                                                                    >
                                                                        <QrCode size={16} />
                                                                    </button>
                                                                    <button 
                                                                        onClick={() => handleUpdateStatus(r.id, 'farmerStatus', 'Paid')}
                                                                        className="p-1 text-emerald-500 hover:bg-emerald-50 rounded transition-colors"
                                                                        title="ทำเครื่องหมายว่าจ่ายแล้ว"
                                                                    >
                                                                        <CheckCircle2 size={16} />
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                user?.role === 'owner' && (
                                                                    <button 
                                                                        onClick={() => handleUpdateStatus(r.id, 'farmerStatus', 'Pending')}
                                                                        className="text-[10px] text-red-400 hover:underline"
                                                                    >
                                                                        แก้เป็นรอโอน
                                                                    </button>
                                                                )
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                {hasEmployee ? (
                                                    <div className="flex flex-col">
                                                        <div className="flex items-center gap-1.5 text-sm font-medium text-gray-600 mb-1">
                                                            <Users size={14} className="text-purple-500" />
                                                            {recordEmp?.name || 'ลูกจ้าง'}
                                                        </div>
                                                        <div className="flex items-center gap-2">
                                                            <span className={`text-sm font-bold ${employeePaid ? 'text-gray-300 italic line-through' : 'text-gray-600'}`}>
                                                                ฿ {Number(r.employeeTotal).toLocaleString()}
                                                            </span>
                                                            <div className="flex items-center gap-1">
                                                                {!employeePaid ? (
                                                                    <>
                                                                        <button 
                                                                            onClick={() => openQRModal('employee', r.employeeTotal, recordEmp?.name || 'ลูกจ้าง', recordEmp?.id, r.id)}
                                                                            className="p-1 text-purple-500 hover:bg-purple-50 rounded transition-colors"
                                                                            title="แสดง QR Code"
                                                                        >
                                                                            <QrCode size={16} />
                                                                        </button>
                                                                        <button 
                                                                            onClick={() => handleUpdateStatus(r.id, 'employeeStatus', 'Paid')}
                                                                            className="p-1 text-emerald-500 hover:bg-emerald-50 rounded transition-colors"
                                                                            title="ทำเครื่องหมายว่าจ่ายแล้ว"
                                                                        >
                                                                            <CheckCircle2 size={16} />
                                                                        </button>
                                                                    </>
                                                                ) : (
                                                                    user?.role === 'owner' && (
                                                                        <button 
                                                                            onClick={() => handleUpdateStatus(r.id, 'employeeStatus', 'Pending')}
                                                                            className="text-[10px] text-red-400 hover:underline"
                                                                        >
                                                                            แก้เป็นรอโอน
                                                                        </button>
                                                                    )
                                                                )}
                                                            </div>
                                                        </div>
                                                    </div>
                                                ) : (
                                                    <span className="text-gray-300 text-xs italic">ไม่มีลูกจ้าง</span>
                                                )}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                <span className="text-base font-black text-rubber-700">฿ {Number(r.total).toLocaleString()}</span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-center">
                                                {(farmerPaid && (!hasEmployee || employeePaid)) ? (
                                                    <div className="flex flex-col items-center">
                                                        <span className="text-[10px] text-emerald-600 font-bold flex items-center gap-1">
                                                            <CheckCircle2 size={12} /> จ่ายครบแล้ว
                                                        </span>
                                                        {user?.role === 'owner' && (
                                                            <button 
                                                                onClick={async () => {
                                                                    await handleUpdateStatus(r.id, 'farmerStatus', 'Pending');
                                                                    if (hasEmployee) await handleUpdateStatus(r.id, 'employeeStatus', 'Pending');
                                                                }}
                                                                className="text-[9px] text-gray-400 hover:text-red-500 mt-1"
                                                            >
                                                                รีเซ็ตทั้งหมด
                                                            </button>
                                                        )}
                                                    </div>
                                                ) : (
                                                    <div className="flex flex-col items-center gap-1">
                                                        <span className="text-[10px] text-amber-600 font-bold">รอเคลียร์ยอด</span>
                                                        <button 
                                                            disabled={statusUpdating}
                                                            onClick={async () => {
                                                                if (!farmerPaid) await handleUpdateStatus(r.id, 'farmerStatus', 'Paid');
                                                                if (hasEmployee && !employeePaid) await handleUpdateStatus(r.id, 'employeeStatus', 'Paid');
                                                            }}
                                                            className="px-3 py-1 bg-rubber-600 text-white text-[10px] font-bold rounded hover:bg-rubber-700 transition-all"
                                                        >
                                                            จ่ายทั้งหมด
                                                        </button>
                                                    </div>
                                                )}
                                            </td>
                                        </tr>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* QR Modal */}
            {selectedPayment && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
                    <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full overflow-hidden animate-in fade-in zoom-in duration-300">
                        <div className="bg-blue-600 p-6 text-white relative">
                            <button 
                                onClick={() => setSelectedPayment(null)}
                                className="absolute right-4 top-4 p-1 hover:bg-white/20 rounded-full transition-colors"
                            >
                                <X size={20} />
                            </button>
                            <div className="flex items-center gap-3 mb-4">
                                <div className="p-3 bg-white/20 rounded-xl">
                                    <QrCode size={24} />
                                </div>
                                <h3 className="text-xl font-bold">PromptPay QR</h3>
                            </div>
                            <div className="space-y-1">
                                <p className="text-sm opacity-80 uppercase tracking-wider font-medium">ชื่อผู้รับ</p>
                                <p className="text-lg font-bold truncate">{selectedPayment.name}</p>
                            </div>
                        </div>
                        
                        <div className="p-8 flex flex-col items-center">
                            <div className="bg-white p-3 border-2 border-dashed border-gray-100 rounded-2xl shadow-inner mb-6">
                                <img 
                                    src={`https://promptpay.io/${selectedPayment.promptpayId}/${selectedPayment.amount}.png`} 
                                    alt="PromptPay QR Code"
                                    className="w-48 h-48"
                                />
                            </div>

                            <div className="w-full bg-gray-50 rounded-xl p-4 mb-6 border border-gray-100">
                                <div className="flex justify-between items-center mb-2">
                                    <span className="text-sm text-gray-500">ยอดเงินโอน</span>
                                    <span className="text-lg font-black text-blue-600">฿ {selectedPayment.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                </div>
                                <div className="flex justify-between items-center">
                                    <span className="text-sm text-gray-500">PromptPay ID</span>
                                    <span className="text-sm font-bold text-gray-700">{selectedPayment.promptpayId}</span>
                                </div>
                            </div>

                            <div className="flex gap-3 w-full">
                                <button 
                                    onClick={() => setSelectedPayment(null)}
                                    className="flex-1 py-3 border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-colors"
                                >
                                    ปิดหน้าต่าง
                                </button>
                                <button 
                                    onClick={() => {
                                        const field = selectedPayment.type === 'farmer' ? 'farmerStatus' : 'employeeStatus';
                                        handleUpdateStatus(selectedPayment.buyId, field, 'Paid');
                                        setSelectedPayment(null);
                                    }}
                                    className="flex-1 py-3 bg-emerald-600 text-white font-bold rounded-xl hover:bg-emerald-700 shadow-md shadow-emerald-200 transition-colors flex items-center justify-center gap-2"
                                >
                                    <CheckCircle2 size={18} /> โอนแล้ว
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Payments;

pages/Promotions.jsx.content:
import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { format } from 'date-fns';
import { Gift, Award, Clock, Users, Search, Trash2, PlusCircle } from 'lucide-react';
import toast from 'react-hot-toast';
import { fetchBuyRecords, fetchFarmers, fetchPromotions, addPromotion, getSettings, deleteRecord, isCached } from '../services/apiService';

export const Promotions = () => {
    const [activeTab, setActiveTab] = useState('points'); // points, history
    const [farmers, setFarmers] = useState([]);
    const [buyRecords, setBuyRecords] = useState([]);
    const [promotions, setPromotions] = useState([]);
    const [pointsPerKg, setPointsPerKg] = useState(10); // default 10kg = 1 point
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [showRedeemForm, setShowRedeemForm] = useState(false);
    const [selectedFarmerId, setSelectedFarmerId] = useState('');
    const [confirmDeleteId, setConfirmDeleteId] = useState(null);
    const isDemo = false;

    const redeemForm = useForm({ defaultValues: { date: format(new Date(), 'yyyy-MM-dd') } });

    useEffect(() => {
        loadData();
    }, [activeTab]);

    const loadData = async () => {
        if (!isCached('buys', 'farmers')) setLoading(true);
        try {
            const [bRaw, fData, pRaw, sRes] = await Promise.all([
                fetchBuyRecords(),
                fetchFarmers(),
                fetchPromotions(),
                getSettings()
            ]);
            setBuyRecords(Array.isArray(bRaw) ? bRaw : []);
            setFarmers(fData || []);
            setPromotions(Array.isArray(pRaw) ? [...pRaw].reverse() : []);

            if (sRes && sRes.status === 'success' && sRes.data && sRes.data.pointsPerKg) {
                setPointsPerKg(Number(sRes.data.pointsPerKg));
            }
        } catch (e) {
            toast.error('โหลดข้อมูลล้มเหลว: ' + e.message);
        } finally {
            setLoading(false);
        }
    };

    // Calculate Points
    const getFarmerPoints = (farmerId) => {
        const farmer = farmers.find(f => String(f.id) === String(farmerId));
        if (!farmer) {
            return { totalWeight: 0, earnedPoints: 0, usedPoints: 0, currentPoints: 0 };
        }

        // 1. Total Weight (fallback to name if farmerId missing from sheet)
        const farmerBuys = buyRecords.filter(r => 
            (r.farmerId && String(r.farmerId) === String(farmerId)) ||
            (r.farmerName && String(r.farmerName).trim() === String(farmer.name).trim())
        );
        const totalWeight = farmerBuys.reduce((sum, r) => sum + Number(r.dryRubber || r.dryWeight || 0), 0);

        // 2. Total Earned Points
        const earnedPoints = Math.floor(totalWeight / pointsPerKg);

        // 3. Points Used (fallback to name just in case)
        const farmerPromos = promotions.filter(p => 
            (p.farmerId && String(p.farmerId) === String(farmerId)) ||
            (p.farmerName && String(p.farmerName).trim() === String(farmer.name).trim())
        );
        const usedPoints = farmerPromos.reduce((sum, p) => sum + Number(p.pointsUsed || 0), 0);

        return {
            totalWeight,
            earnedPoints,
            usedPoints,
            currentPoints: Math.max(0, earnedPoints - usedPoints)
        };
    };

    const handleRedeemClick = (farmerId) => {
        setSelectedFarmerId(farmerId);
        redeemForm.setValue('farmerId', farmerId);
        setShowRedeemForm(true);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const onRedeem = async (data) => {
        const farmer = farmers.find(f => String(f.id) === String(data.farmerId));
        if (!farmer) {
            toast.error("ไม่พบข้อมูลเกษตรกร");
            return;
        }

        const stats = getFarmerPoints(farmer.id);
        const pointsToUse = Number(data.pointsUsed);

        if (pointsToUse <= 0) {
            toast.error("ระบุคะแนนที่ใช้ให้ถูกต้อง");
            return;
        }
        if (pointsToUse > stats.currentPoints) {
            toast.error(`คะแนนไม่พอ (มีอยู่ ${stats.currentPoints} คะแนน)`);
            return;
        }

        setSubmitting(true);
        try {
            const payload = {
                date: data.date,
                farmerId: farmer.id,
                farmerName: farmer.name,
                pointsUsed: pointsToUse,
                rewardName: data.rewardName
            };

            if (isDemo) {
                const newRec = { ...payload, id: Date.now().toString(), timestamp: new Date().toISOString() };
                setPromotions(prev => [newRec, ...prev]);
                toast.success('บันทึกสำเร็จ (Demo)');
                setShowRedeemForm(false);
                redeemForm.reset();
                return;
            }

            const res = await addPromotion(payload);
            if (res.status === 'success') {
                toast.success('แลกคะแนนสำเร็จ');
                setShowRedeemForm(false);
                redeemForm.reset();
                loadData();
            } else {
                toast.error(res.message || 'บันทึกล้มเหลว');
            }
        } catch (e) {
            toast.error('บันทึกล้มเหลว: ' + e.message);
        } finally {
            setSubmitting(false);
        }
    };

    const confirmDelete = async () => {
        const id = confirmDeleteId;
        setConfirmDeleteId(null);
        const toastId = toast.loading('กำลังลบ...');
        try {
            if (isDemo) {
                setPromotions(prev => prev.filter(r => String(r.id) !== String(id)));
                toast.success('ลบสำเร็จ (Demo)', { id: toastId });
                return;
            }
            const res = await deleteRecord('Promotions', id);
            if (res && res.status === 'success') {
                toast.success('ลบสำเร็จ', { id: toastId });
                loadData();
            } else {
                toast.error('ลบล้มเหลว', { id: toastId });
            }
        } catch (e) {
            toast.error('ลบล้มเหลว: ' + e.message, { id: toastId });
        }
    };

    // Filtered data
    const filteredFarmers = farmers.filter(f => 
        (f.name || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (f.code || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    const filteredPromotions = promotions.filter(p =>
        (p.farmerName || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (p.rewardName || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6">
            {/* Confirm Delete Modal */}
            {confirmDeleteId && (
                <div className="fixed inset-0 bg-black/40 z-[100] flex items-center justify-center">
                    <div className="bg-white rounded-xl shadow-2xl p-6 max-w-sm w-full mx-4">
                        <div className="flex items-center mb-3">
                            <div className="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center mr-3">
                                <Trash2 className="text-red-600" size={20} />
                            </div>
                            <h3 className="text-lg font-bold text-gray-900">ยกเลิกการแลกของรางวัล?</h3>
                        </div>
                        <p className="text-gray-600 mb-5 text-sm">การลบประวัติจะทำให้คะแนนตีกลับคืนให้เกษตรกร คุณต้องการลบใช่หรือไม่?</p>
                        <div className="flex justify-end space-x-3">
                            <button onClick={() => setConfirmDeleteId(null)}
                                className="px-4 py-2 text-sm text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg">ยกเลิก</button>
                            <button onClick={confirmDelete}
                                className="px-4 py-2 text-sm text-white bg-red-600 hover:bg-red-700 rounded-lg">ลบรายการ</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Header */}
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">โปรโมชั่นและของรางวัล</h1>
                    <p className="text-gray-500">ระบบคะแนนสะสมและแลกของรางวัลสำหรับสมาชิก</p>
                </div>
                <div className="bg-yellow-50 border border-yellow-200 rounded-xl px-4 py-2 flex items-center shadow-sm">
                    <Award className="text-yellow-600 mr-2" size={20} />
                    <div>
                        <p className="text-xs text-yellow-700 font-bold uppercase tracking-wider">อัตราแลกคะแนน</p>
                        <p className="text-sm font-black text-yellow-800">{pointsPerKg} กก. (ยางแห้ง) = 1 คะแนน</p>
                    </div>
                </div>
            </div>

            {/* Redeem Form Action Area */}
            {showRedeemForm && (
                <div className="bg-gradient-to-br from-yellow-50 to-orange-50 border border-yellow-200 rounded-2xl p-6 shadow-md animate-in fade-in zoom-in-95 duration-200">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="text-lg font-bold text-yellow-900 flex items-center">
                            <Gift className="mr-2" size={24} /> แลกคะแนน / ของรางวัล
                        </h3>
                        <button onClick={() => setShowRedeemForm(false)} className="text-gray-400 hover:text-gray-600">ปิด</button>
                    </div>

                    <form onSubmit={redeemForm.handleSubmit(onRedeem)} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                        <div>
                            <label className="block text-xs font-bold text-gray-700 mb-1">วันที่</label>
                            <input type="date" {...redeemForm.register('date', { required: true })}
                                className="w-full px-3 py-2 border border-white rounded-lg text-sm focus:ring-2 focus:ring-yellow-400 focus:outline-none shadow-sm" />
                        </div>
                        <div className="md:col-span-2">
                            <label className="block text-xs font-bold text-gray-700 mb-1">เลือกเกษตรกร *</label>
                            <select {...redeemForm.register('farmerId', { required: true })}
                                onChange={(e) => setSelectedFarmerId(e.target.value)}
                                className="w-full px-3 py-2 border border-white rounded-lg text-sm bg-white focus:ring-2 focus:ring-yellow-400 focus:outline-none shadow-sm">
                                <option value="">-- เลือกเกษตรกร --</option>
                                {farmers.map(f => (
                                    <option key={f.id} value={f.id}>{f.code} - {f.name}</option>
                                ))}
                            </select>
                        </div>
                        {selectedFarmerId && (
                            <div className="bg-white rounded-lg px-3 py-2 border border-yellow-100 shadow-sm flex items-center justify-between">
                                <span className="text-xs text-gray-500">คะแนนคงเหลือ:</span>
                                <span className="font-black text-lg text-green-600">{getFarmerPoints(selectedFarmerId).currentPoints}</span>
                            </div>
                        )}
                        <div className="md:col-span-2">
                            <label className="block text-xs font-bold text-gray-700 mb-1">รางวัล/โปรโมชั่น ที่ต้องการแลก *</label>
                            <input {...redeemForm.register('rewardName', { required: true })} placeholder="เช่น ปุ๋ย 1 กระสอบ, เสื้อยืด"
                                className="w-full px-3 py-2 border border-white rounded-lg text-sm focus:ring-2 focus:ring-yellow-400 focus:outline-none shadow-sm" />
                        </div>
                        <div className="md:col-span-1">
                            <label className="block text-xs font-bold text-gray-700 mb-1">คะแนนที่ใช้ *</label>
                            <input type="number" min="1" {...redeemForm.register('pointsUsed', { required: true, min: 1 })} placeholder="จำนวนคะแนน"
                                className="w-full px-3 py-2 border border-white rounded-lg text-sm focus:ring-2 focus:ring-yellow-400 focus:outline-none shadow-sm" />
                        </div>
                        <div className="md:col-span-1">
                            <button type="submit" disabled={submitting}
                                className="w-full bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-2 px-4 rounded-lg shadow-sm transition-colors disabled:opacity-50">
                                ยืนยันการแลก
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* Tabs */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="flex border-b border-gray-100">
                    <button onClick={() => { setActiveTab('points'); setSearchTerm(''); }}
                        className={`flex-1 py-4 px-6 text-center font-medium text-sm transition-colors border-b-2 ${activeTab === 'points' ? 'border-yellow-500 text-yellow-700 bg-yellow-50/30' : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}>
                        <div className="flex items-center justify-center space-x-2">
                            <Users size={18} /><span>คะแนนสะสมรายบุคคล</span>
                        </div>
                    </button>
                    <button onClick={() => { setActiveTab('history'); setSearchTerm(''); }}
                        className={`flex-1 py-4 px-6 text-center font-medium text-sm transition-colors border-b-2 ${activeTab === 'history' ? 'border-yellow-500 text-yellow-700 bg-yellow-50/30' : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}>
                        <div className="flex items-center justify-center space-x-2">
                            <Clock size={18} /><span>ประวัติการแลกของรางวัล</span>
                        </div>
                    </button>
                </div>

                <div className="p-6">
                    <div className="mb-4 flex items-center bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 w-full max-w-sm">
                        <Search size={18} className="text-gray-400 mr-2 flex-shrink-0" />
                        <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                            placeholder="ค้นหาชื่อเกษตรกร, ของรางวัล..."
                            className="bg-transparent text-sm w-full focus:outline-none" />
                    </div>

                    {/* POINTS TAB */}
                    {activeTab === 'points' && (
                        <div className="overflow-x-auto rounded-xl border border-gray-100">
                            <table className="min-w-full divide-y divide-gray-100 text-sm">
                                <thead className="bg-gray-50">
                                    <tr>
                                        <th className="px-5 py-4 text-left font-bold text-gray-500 uppercase tracking-wider text-xs">รหัส</th>
                                        <th className="px-5 py-4 text-left font-bold text-gray-500 uppercase tracking-wider text-xs">รายชื่อเกษตรกร</th>
                                        <th className="px-5 py-4 text-right font-bold text-gray-500 uppercase tracking-wider text-xs bg-blue-50/50">น้ำหนักยางแห้ง (กก.)</th>
                                        <th className="px-5 py-4 text-right font-bold text-gray-500 uppercase tracking-wider text-xs bg-yellow-50/50">คะแนนที่ได้</th>
                                        <th className="px-5 py-4 text-right font-bold text-gray-500 uppercase tracking-wider text-xs bg-red-50/50">ใช้ไปแล้ว</th>
                                        <th className="px-5 py-4 text-right font-bold text-green-700 uppercase tracking-wider text-xs bg-green-50/50">คงเหลือสุทธิ</th>
                                        <th className="px-5 py-4 text-center font-bold text-gray-500 uppercase tracking-wider text-xs">จัดการ</th>
                                    </tr>
                                </thead>
                                <tbody className="bg-white divide-y divide-gray-50">
                                    {loading ? (
                                        <tr><td colSpan="7" className="px-5 py-10 text-center text-gray-400">กำลังโหลด...</td></tr>
                                    ) : filteredFarmers.length === 0 ? (
                                        <tr><td colSpan="7" className="px-5 py-10 text-center text-gray-400">ไม่พบข้อมูลเกษตรกร</td></tr>
                                    ) : filteredFarmers.map(f => {
                                        const stats = getFarmerPoints(f.id);
                                        return (
                                            <tr key={f.id} className="hover:bg-gray-50/50 transition-colors">
                                                <td className="px-5 py-3 whitespace-nowrap text-gray-500 font-mono text-xs">{f.code}</td>
                                                <td className="px-5 py-3 font-semibold text-gray-900">{f.name}</td>
                                                <td className="px-5 py-3 text-right text-gray-600 bg-blue-50/10 border-l border-blue-50/50">{stats.totalWeight.toLocaleString(undefined, { maximumFractionDigits: 1 })}</td>
                                                <td className="px-5 py-3 text-right text-yellow-600 font-bold bg-yellow-50/10 border-l border-yellow-50/50">{stats.earnedPoints.toLocaleString()}</td>
                                                <td className="px-5 py-3 text-right text-red-500 bg-red-50/10 border-l border-red-50/50">{stats.usedPoints > 0 ? `-${stats.usedPoints.toLocaleString()}` : '0'}</td>
                                                <td className="px-5 py-3 text-right font-black text-green-700 bg-green-50/30 border-l border-green-100 text-lg">{stats.currentPoints.toLocaleString()}</td>
                                                <td className="px-5 py-3 text-center">
                                                    <button onClick={() => handleRedeemClick(f.id)}
                                                        className="inline-flex items-center px-3 py-1 bg-yellow-100 text-yellow-700 hover:bg-yellow-200 rounded-full text-xs font-bold transition-colors">
                                                        <Gift size={12} className="mr-1" /> แลกคะแนน
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {/* HISTORY TAB */}
                    {activeTab === 'history' && (
                        <div className="overflow-x-auto rounded-xl border border-gray-100">
                            <table className="min-w-full divide-y divide-gray-100 text-sm">
                                <thead className="bg-gray-50">
                                    <tr>
                                        <th className="px-5 py-3 text-left font-semibold text-gray-500 uppercase text-xs">วันที่</th>
                                        <th className="px-5 py-3 text-left font-semibold text-gray-500 uppercase text-xs">เกษตรกร</th>
                                        <th className="px-5 py-3 text-left font-semibold text-gray-500 uppercase text-xs">ของรางวัลที่แลก</th>
                                        <th className="px-5 py-3 text-right font-semibold text-gray-500 uppercase text-xs">คะแนนที่ใช้</th>
                                        <th className="px-5 py-3 text-center font-semibold text-gray-500 uppercase text-xs">ยกเลิกรายการ</th>
                                    </tr>
                                </thead>
                                <tbody className="bg-white divide-y divide-gray-50">
                                    {loading ? (
                                        <tr><td colSpan="5" className="px-5 py-10 text-center text-gray-400">กำลังโหลด...</td></tr>
                                    ) : filteredPromotions.length === 0 ? (
                                        <tr><td colSpan="5" className="px-5 py-10 text-center text-gray-400 flex-col items-center">
                                            <Gift size={32} className="mx-auto mb-2 opacity-20" />ยังไม่มีประวัติการแลกของรางวัล
                                        </td></tr>
                                    ) : filteredPromotions.map((p, i) => (
                                        <tr key={p.id || i} className="hover:bg-gray-50/50">
                                            <td className="px-5 py-4 whitespace-nowrap text-gray-500">{p.date}</td>
                                            <td className="px-5 py-4 font-semibold text-gray-900">{p.farmerName}</td>
                                            <td className="px-5 py-4 text-gray-700 font-medium">
                                                {Number(p.pointsUsed) === 0 ? p.rewardName : `✨ ${p.rewardName}`}
                                            </td>
                                            <td className="px-5 py-4 text-right">
                                                {Number(p.pointsUsed) === 0 ? (
                                                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold bg-purple-100 text-purple-700 border border-purple-200">
                                                        รางวัลจับฉลาก
                                                    </span>
                                                ) : (
                                                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold bg-red-100 text-red-700">
                                                        -{Number(p.pointsUsed).toLocaleString()}
                                                    </span>
                                                )}
                                            </td>
                                            <td className="px-5 py-4 text-center">
                                                <button onClick={() => { setConfirmDeleteId(p.id); }}
                                                    className="text-gray-300 hover:text-red-500 transition-colors p-1"><Trash2 size={18} /></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

export default Promotions;

pages/Report.jsx.content:
import React, { useState, useEffect, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { format, subMonths, isWithinInterval, startOfMonth, endOfMonth, parseISO } from 'date-fns';
import { th } from 'date-fns/locale';
import { Calendar, Download, Filter, TrendingUp, Droplets, Target, Calculator, Wallet, Users, BarChart3, FlaskConical, Truck, Activity, Save } from 'lucide-react';
import { fetchBuyRecords, fetchSellRecords, getSettings, fetchExpenses, fetchWages, fetchChemicalUsage, isCached, addChemicalUsage } from '../services/apiService';
import { truncateOneDecimal } from '../utils/calculations';
import toast from 'react-hot-toast';

export const Report = () => {
    const [loading, setLoading] = useState(true);
    const [buys, setBuys] = useState([]);
    const [sells, setSells] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [wages, setWages] = useState([]);
    const [chemicalUsage, setChemicalUsage] = useState([]);
    const [settings, setSettings] = useState({});
    const [profitMargin, setProfitMargin] = useState(1.50);

    // Filters
    const [dateRange, setDateRange] = useState('thisMonth'); // thisMonth, lastMonth, all
    const [fStart, setFStart] = useState(format(new Date(), 'yyyy-MM-dd'));
    const [fEnd, setFEnd] = useState(format(new Date(), 'yyyy-MM-dd'));

    const isDemo = false;

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        if (!isCached('buys', 'sells', 'settings', 'expenses', 'wages', 'chemicals')) setLoading(true);
        try {
            if (isDemo) {
                setBuys([
                    { date: new Date().toISOString(), weight: 1500, total: 52500 }
                ]);
                setSells([
                    { date: new Date().toISOString(), weight: 1600, total: 72000 }
                ]);
                setExpenses([]);
                setWages([]);
                return;
            }

            const [b, s, setRes, expRes, wageRes, chemUsage] = await Promise.all([
                fetchBuyRecords(),
                fetchSellRecords(),
                getSettings(),
                fetchExpenses(),
                fetchWages(),
                fetchChemicalUsage()
            ]);
            setBuys(Array.isArray(b) ? b : []);
            setSells(Array.isArray(s) ? s : []);
            setExpenses(Array.isArray(expRes) ? expRes : []);
            setWages(Array.isArray(wageRes) ? wageRes : []);
            setChemicalUsage(Array.isArray(chemUsage) ? chemUsage : []);
            
            if (setRes && setRes.status === 'success') {
                setSettings(setRes.data || {});
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleSaveChemical = async (chemId, value) => {
        if (!value || isNaN(value)) {
            toast.error('กรุณาระบุตัวเลขที่ถูกต้อง');
            return;
        }
        const toastId = toast.loading('กำลังบันทึก...');
        try {
            const res = await addChemicalUsage({
                chemicalId: chemId,
                amount: Number(value),
                date: format(new Date(), 'yyyy-MM-dd'),
                unit: 'กิโลกรัม'
            });
            if (res.status === 'success') {
                toast.success('บันทึกสำเร็จ', { id: toastId });
                // Clear manual input for this chemical to show actual usage
                setManualChemicals(prev => {
                    const next = { ...prev };
                    delete next[chemId];
                    return next;
                });
                // Refresh data
                loadData();
            } else {
                toast.error(res.message || 'บันทึกล้มเหลว', { id: toastId });
            }
        } catch (err) {
            toast.error('บันทึกล้มเหลว: ' + err.message, { id: toastId });
        }
    };

    const [manualChemicals, setManualChemicals] = useState({});

    // Reset manual values when dates change so they start with data from the new period
    useEffect(() => {
        setManualChemicals({});
    }, [fStart, fEnd]);

    const filteredData = useMemo(() => {
        let start, end;
        const now = new Date();
        if (dateRange === 'thisMonth') {
            start = startOfMonth(now);
            end = endOfMonth(now);
        } else if (dateRange === 'lastMonth') {
            const lastMonth = subMonths(now, 1);
            start = startOfMonth(lastMonth);
            end = endOfMonth(lastMonth);
        }

        const filterFn = item => {
            if (dateRange === 'all') return true;
            return isWithinInterval(parseISO(item.date || item.timestamp), { start, end });
        };

        const periodBuys = buys.filter(b => filterFn(b) && (b.rubberType === 'latex' || !b.rubberType));
        const periodSells = sells.filter(s => filterFn(s) && (s.rubberType === 'latex' || !s.rubberType));

        const buyTotal = truncateOneDecimal(periodBuys.reduce((sum, item) => sum + Number(item.total || 0), 0));
        const buyWeight = truncateOneDecimal(periodBuys.reduce((sum, item) => {
            const net = Number(item.netWeight);
            if (!isNaN(net) && net > 0) return sum + net;
            return sum + (Number(item.weight || 0) - Number(item.bucketWeight || 0));
        }, 0));

        const sellTotal = truncateOneDecimal(periodSells.reduce((sum, item) => sum + Number(item.total || 0), 0));
        const sellWeight = truncateOneDecimal(periodSells.reduce((sum, item) => sum + Number(item.weight || 0), 0));
        const sellLoss = truncateOneDecimal(periodSells.reduce((sum, item) => sum + Number(item.lossWeight || 0), 0));

        // Chemicals weights for this period
        const periodChemicals = chemicalUsage.filter(filterFn);
        const ammoniaWeight = truncateOneDecimal(periodChemicals.filter(c => c.chemicalId === 'ammonia').reduce((sum, c) => sum + Number(c.amount || 0), 0));
        const waterWeight = truncateOneDecimal(periodChemicals.filter(c => c.chemicalId === 'water').reduce((sum, c) => sum + Number(c.amount || 0), 0));
        const whiteMedWeight = truncateOneDecimal(periodChemicals.filter(c => c.chemicalId === 'whiteMedicine').reduce((sum, c) => sum + Number(c.amount || 0), 0));

        const profit = truncateOneDecimal(sellTotal - buyTotal);
        const currentStock = truncateOneDecimal(buyWeight + ammoniaWeight + waterWeight + whiteMedWeight - sellWeight - sellLoss);
        
        // Daily breakdown for chart (grouped by date)
        const dailyMap = {};
        [...periodBuys.map(i => ({ ...i, type: 'buy' })), ...periodSells.map(i => ({ ...i, type: 'sell' }))].forEach(item => {
            const dateStr = format(parseISO(item.date || item.timestamp), 'dd MMM', { locale: th });
            if (!dailyMap[dateStr]) dailyMap[dateStr] = { name: dateStr, ซื้อ: 0, ขาย: 0 };
            if (item.type === 'buy') dailyMap[dateStr].ซื้อ += Number(item.total || 0);
            else dailyMap[dateStr].ขาย += Number(item.total || 0);
        });

        const chartData = Object.values(dailyMap);

        // Period Forecast summary (fStart/fEnd)
        const periodForecastBuys = buys.filter(b => b.date >= fStart && b.date <= fEnd && (b.rubberType === 'latex' || !b.rubberType));
        const periodForecastSells = sells.filter(s => s.date >= fStart && s.date <= fEnd && (s.rubberType === 'latex' || !s.rubberType));
        
        const fBuyWeight = truncateOneDecimal(periodForecastBuys.reduce((sum, b) => sum + (Number(b.weight || 0) - Number(b.bucketWeight || 0)), 0));
        const fBuyTotal = truncateOneDecimal(periodForecastBuys.reduce((sum, b) => sum + Number(b.total || 0), 0));
        const fSellWeight = truncateOneDecimal(periodForecastSells.reduce((sum, s) => sum + Number(s.weight || 0), 0));
        const fSellLoss = truncateOneDecimal(periodForecastSells.reduce((sum, s) => sum + Number(s.lossWeight || 0), 0));
        const fDryWeight = truncateOneDecimal(periodForecastBuys.reduce((sum, b) => sum + Number(b.dryRubber || 0), 0));
        
        const fAvgDrc = fBuyWeight > 0 ? truncateOneDecimal((fDryWeight / fBuyWeight) * 100) : 0;
        
        const dailyPrice = Number(settings.daily_price || 0);
        const projectedSellPrice = dailyPrice + Number(profitMargin || 0);
        const projectedRevenue = truncateOneDecimal(fDryWeight * projectedSellPrice);
        const projectedProfit = truncateOneDecimal(projectedRevenue - fBuyTotal);
 
        const fExpenses = truncateOneDecimal(expenses.filter(e => e.date >= fStart && e.date <= fEnd).reduce((sum, e) => sum + Number(e.amount || 0), 0));
        const fWages = truncateOneDecimal(wages.filter(w => w.date >= fStart && w.date <= fEnd).reduce((sum, w) => sum + Number(w.total || 0), 0));
        const fNetOutcome = truncateOneDecimal(projectedProfit - (fExpenses + fWages));

        // Parse chemical settings for recommendations
        let chemSettings = [];
        try {
            if (settings.chemicalSettings) {
                chemSettings = JSON.parse(settings.chemicalSettings);
            }
        } catch (e) {
            console.error('Failed to parse chemical settings', e);
        }

        const getRecommended = (id, defaultAmount, defaultPer) => {
            const config = chemSettings.find(s => s.id === id) || { amount: defaultAmount, perLatex: defaultPer };
            const amount = Number(config.amount) || 0;
            const per = Number(config.perLatex) || 1000;
            return truncateOneDecimal((amount / per) * fBuyWeight);
        };

        const recAmmonia = getRecommended('ammonia', 20, 1000);
        const recWater = getRecommended('water', 30, 800);
        const recWhiteMed = getRecommended('whiteMedicine', 1, 1000);

        return {
            buyTotal,
            buyWeight,
            sellTotal,
            sellWeight,
            sellLoss,
            profit,
            currentStock,
            chartData,
            periodChemicals: {
                ammonia: ammoniaWeight,
                water: waterWeight,
                whiteMedicine: whiteMedWeight
            },
            todaySummary: {
                weight: fBuyWeight,
                sellWeight: fSellWeight,
                sellLoss: fSellLoss,
                avgDrc: fAvgDrc,
                cost: fBuyTotal,
                profit: projectedProfit,
                expenses: fExpenses,
                wages: fWages,
                netOutcome: fNetOutcome,
                dailyPrice: dailyPrice,
                chemicals: {
                    ammonia: truncateOneDecimal(chemicalUsage.filter(c => c.chemicalId === 'ammonia' && c.date >= fStart && c.date <= fEnd).reduce((sum, c) => sum + Number(c.amount || 0), 0)),
                    water: truncateOneDecimal(chemicalUsage.filter(c => c.chemicalId === 'water' && c.date >= fStart && c.date <= fEnd).reduce((sum, c) => sum + Number(c.amount || 0), 0)),
                    whiteMedicine: truncateOneDecimal(chemicalUsage.filter(c => c.chemicalId === 'whiteMedicine' && c.date >= fStart && c.date <= fEnd).reduce((sum, c) => sum + Number(c.amount || 0), 0))
                },
                recommendedChemicals: {
                    ammonia: recAmmonia,
                    water: recWater,
                    whiteMedicine: recWhiteMed
                }
            }
        };
    }, [buys, sells, expenses, wages, chemicalUsage, dateRange, settings, profitMargin, fStart, fEnd]);


    return (
        <div className="space-y-6 max-w-7xl mx-auto">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">รายงานคาดการณ์ ประจำวัน</h1>
                    <p className="text-gray-500">วิเคราะห์และสรุปยอดซื้อ-ขาย รายวัน</p>
                </div>

                <div className="flex items-center space-x-2 bg-white rounded-lg p-1 border border-gray-200">
                    <button
                        onClick={() => setDateRange('thisMonth')}
                        className={`px-4 py-2 text-sm font-medium rounded-md transition-colors ${dateRange === 'thisMonth' ? 'bg-rubber-100 text-rubber-700' : 'text-gray-600 hover:bg-gray-50'}`}
                    >
                        เดือนนี้
                    </button>
                    <button
                        onClick={() => setDateRange('lastMonth')}
                        className={`px-4 py-2 text-sm font-medium rounded-md transition-colors ${dateRange === 'lastMonth' ? 'bg-rubber-100 text-rubber-700' : 'text-gray-600 hover:bg-gray-50'}`}
                    >
                        เดือนที่แล้ว
                    </button>
                    <button
                        onClick={() => setDateRange('all')}
                        className={`px-4 py-2 text-sm font-medium rounded-md transition-colors ${dateRange === 'all' ? 'bg-rubber-100 text-rubber-700' : 'text-gray-600 hover:bg-gray-50'}`}
                    >
                        ทั้งหมด
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-rubber-600"></div>
                </div>
            ) : (
                <>
                    {/* Today's Daily Summary Section */}
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                        <div className="bg-gradient-to-r from-rubber-600 to-rubber-500 px-6 py-4 flex flex-col lg:flex-row justify-between lg:items-center gap-4 text-white">
                            <h2 className="text-lg font-bold flex items-center">
                                <Calendar className="mr-2 opacity-80" size={20} />
                                สรุปรายการรับซื้อ (พยากรณ์)
                            </h2>
                            
                            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 text-sm">
                                <div className="flex items-center space-x-2 bg-white/20 px-3 py-1.5 rounded-xl border border-white/10 shadow-sm">
                                    <span className="text-[10px] font-black uppercase tracking-tighter opacity-60">ช่วงวิเคราะห์:</span>
                                    <input 
                                        type="date"
                                        value={fStart}
                                        onChange={(e) => setFStart(e.target.value)}
                                        className="bg-transparent border-none p-0 text-white font-bold focus:ring-0 w-[115px] text-sm cursor-pointer"
                                    />
                                    <span className="opacity-40">-</span>
                                    <input 
                                        type="date"
                                        value={fEnd}
                                        onChange={(e) => setFEnd(e.target.value)}
                                        className="bg-transparent border-none p-0 text-white font-bold focus:ring-0 w-[115px] text-sm cursor-pointer"
                                    />
                                </div>

                                <div className="flex items-center space-x-4">
                                    <div className="h-4 w-px bg-white/20 hidden md:block"></div>
                                    <span className="opacity-90 font-medium whitespace-nowrap">ราคากลาง: ฿{Number(filteredData.todaySummary.dailyPrice).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                                    <div className="h-4 w-px bg-white/20 hidden md:block"></div>
                                    
                                    <div className="flex items-center bg-white/20 px-3 py-1.5 rounded-xl border border-white/10 group hover:bg-white/30 transition-all shadow-sm">
                                        <Calculator size={14} className="mr-2 opacity-80" />
                                        <span className="mr-2 font-bold whitespace-nowrap">กำไรส่วนต่าง:</span>
                                        <input 
                                            type="number" 
                                            step="0.1"
                                            value={profitMargin}
                                            onChange={(e) => setProfitMargin(e.target.value)}
                                            className="w-10 bg-transparent border-none p-0 text-white font-black focus:ring-0 placeholder-white/50 text-right"
                                            placeholder="1.50"
                                        />
                                        <span className="ml-1 font-bold">บ.</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                        
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 divide-y md:divide-y-0 md:divide-x divide-gray-100">
                            <div className="p-6 hover:bg-gray-50/50 transition-colors">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <Droplets size={12} className="mr-1.5 text-blue-500" />น้ำหนักรวม
                                </p>
                                <p className="text-2xl font-black text-gray-900">{Number(filteredData.todaySummary.weight).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} <span className="text-sm font-normal text-gray-400">กก.</span></p>
                            </div>
                            <div className="p-6 hover:bg-gray-50/50 transition-colors">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <Target size={12} className="mr-1.5 text-orange-500" />เฉลี่ย %DRC
                                </p>
                                <p className="text-2xl font-black text-gray-900">{Number(filteredData.todaySummary.avgDrc).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} <span className="text-sm font-normal text-gray-400">%</span></p>
                            </div>
                            <div className="p-6 hover:bg-gray-50/50 transition-colors">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <Calculator size={12} className="mr-1.5 text-rubber-500" />ต้นทุนรับซื้อ
                                </p>
                                <p className="text-2xl font-black text-gray-900">{Number(filteredData.todaySummary.cost).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} <span className="text-sm font-normal text-gray-400">฿</span></p>
                            </div>
                            <div className={`p-6 bg-gradient-to-br transition-colors ${filteredData.todaySummary.profit >= 0 ? 'from-green-50/50 to-white' : 'from-red-50/50 to-white'}`}>
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <TrendingUp size={12} className={`mr-1.5 ${filteredData.todaySummary.profit >= 0 ? 'text-green-500' : 'text-red-500'}`} />กำไรจากเนื้อยาง
                                </p>
                                <div className="flex items-baseline space-x-1">
                                    <p className={`text-2xl font-black ${filteredData.todaySummary.profit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                        {filteredData.todaySummary.profit >= 0 ? '+' : ''}{Number(filteredData.todaySummary.profit).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                    </p>
                                    <span className={`text-xs font-bold ${filteredData.todaySummary.profit >= 0 ? 'text-green-600/60' : 'text-red-600/60'}`}>฿</span>
                                </div>
                                 <p className="text-[10px] text-gray-400 font-medium mt-1">ส่วนต่าง +{profitMargin}บ.</p>
                            </div>
                        </div>

                        {/* Chemicals summary row (Interactive Calculator) */}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 divide-y md:divide-y-0 md:divide-x divide-gray-100 border-t border-gray-100 bg-white">
                            <div className="p-6 hover:bg-gray-50/50 transition-colors group/chem text-left">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <FlaskConical size={12} className="mr-1.5 text-amber-500" />แอมโมเนีย
                                </p>
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center">
                                        <input 
                                            type="number" 
                                            step="0.1"
                                            value={manualChemicals.ammonia !== undefined ? manualChemicals.ammonia : filteredData.todaySummary.chemicals.ammonia}
                                            onChange={(e) => setManualChemicals(prev => ({ ...prev, ammonia: e.target.value }))}
                                            className="text-2xl font-black text-gray-900 bg-transparent border-none p-0 focus:ring-0 w-24"
                                        />
                                        <span className="text-sm font-normal text-gray-400 ml-1">กก.</span>
                                    </div>
                                    <button 
                                        onClick={() => handleSaveChemical('ammonia', manualChemicals.ammonia !== undefined ? manualChemicals.ammonia : filteredData.todaySummary.chemicals.ammonia)}
                                        className="p-2 text-gray-400 hover:text-amber-600 hover:bg-amber-50 rounded-lg transition-all opacity-0 group-hover/chem:opacity-100"
                                        title="บันทึกลงระบบ"
                                    >
                                        <Save size={18} />
                                    </button>
                                </div>
                                <button 
                                    onClick={() => setManualChemicals(prev => ({ ...prev, ammonia: filteredData.todaySummary.recommendedChemicals.ammonia }))}
                                    className="text-[14px] font-bold text-amber-600 mt-1 opacity-60 group-hover/chem:opacity-100 transition-opacity hover:underline"
                                >
                                    แนะนำ: {filteredData.todaySummary.recommendedChemicals.ammonia} กก.
                                </button>
                            </div>
                            <div className="p-6 hover:bg-gray-50/50 transition-colors group/chem text-left">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <Droplets size={12} className="mr-1.5 text-blue-500" />น้ำ
                                </p>
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center">
                                        <input 
                                            type="number" 
                                            step="0.1"
                                            value={manualChemicals.water !== undefined ? manualChemicals.water : filteredData.todaySummary.chemicals.water}
                                            onChange={(e) => setManualChemicals(prev => ({ ...prev, water: e.target.value }))}
                                            className="text-2xl font-black text-gray-900 bg-transparent border-none p-0 focus:ring-0 w-24"
                                        />
                                        <span className="text-sm font-normal text-gray-400 ml-1">กก.</span>
                                    </div>
                                    <button 
                                        onClick={() => handleSaveChemical('water', manualChemicals.water !== undefined ? manualChemicals.water : filteredData.todaySummary.chemicals.water)}
                                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all opacity-0 group-hover/chem:opacity-100"
                                        title="บันทึกลงระบบ"
                                    >
                                        <Save size={18} />
                                    </button>
                                </div>
                                <button 
                                    onClick={() => setManualChemicals(prev => ({ ...prev, water: filteredData.todaySummary.recommendedChemicals.water }))}
                                    className="text-[14px] font-bold text-blue-600 mt-1 opacity-60 group-hover/chem:opacity-100 transition-opacity hover:underline"
                                >
                                    แนะนำ: {filteredData.todaySummary.recommendedChemicals.water} กก.
                                </button>
                            </div>
                            <div className="p-6 hover:bg-gray-50/50 transition-colors group/chem text-left">
                                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center">
                                    <Activity size={12} className="mr-1.5 text-purple-500" />ยาขาว
                                </p>
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center">
                                        <input 
                                            type="number" 
                                            step="0.1"
                                            value={manualChemicals.whiteMedicine !== undefined ? manualChemicals.whiteMedicine : filteredData.todaySummary.chemicals.whiteMedicine}
                                            onChange={(e) => setManualChemicals(prev => ({ ...prev, whiteMedicine: e.target.value }))}
                                            className="text-2xl font-black text-gray-900 bg-transparent border-none p-0 focus:ring-0 w-24"
                                        />
                                        <span className="text-sm font-normal text-gray-400 ml-1">กก.</span>
                                    </div>
                                    <button 
                                        onClick={() => handleSaveChemical('whiteMedicine', manualChemicals.whiteMedicine !== undefined ? manualChemicals.whiteMedicine : filteredData.todaySummary.chemicals.whiteMedicine)}
                                        className="p-2 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-all opacity-0 group-hover/chem:opacity-100"
                                        title="บันทึกลงระบบ"
                                    >
                                        <Save size={18} />
                                    </button>
                                </div>
                                <button 
                                    onClick={() => setManualChemicals(prev => ({ ...prev, whiteMedicine: filteredData.todaySummary.recommendedChemicals.whiteMedicine }))}
                                    className="text-[14px] font-bold text-purple-600 mt-1 opacity-60 group-hover/chem:opacity-100 transition-opacity hover:underline"
                                >
                                    แนะนำ: {filteredData.todaySummary.recommendedChemicals.whiteMedicine} กก.
                                </button>
                            </div>
                            <div className="p-6 bg-blue-50/50 transition-colors border-l border-gray-100">
                                <p className="text-xs font-black text-blue-600 uppercase tracking-widest mb-1 flex items-center">
                                    <TrendingUp size={12} className="mr-1.5 text-blue-600" />น้ำหนักรวมสุทธิ
                                </p>
                                <div className="flex items-baseline space-x-1">
                                    {(() => {
                                        const rubberW = Number(filteredData.todaySummary.weight || 0);
                                        const ammonia = Number(manualChemicals.ammonia !== undefined ? manualChemicals.ammonia : filteredData.todaySummary.chemicals.ammonia || 0);
                                        const water = Number(manualChemicals.water !== undefined ? manualChemicals.water : filteredData.todaySummary.chemicals.water || 0);
                                        const whiteMedicine = Number(manualChemicals.whiteMedicine !== undefined ? manualChemicals.whiteMedicine : filteredData.todaySummary.chemicals.whiteMedicine || 0);
                                        const chemW = ammonia + water + whiteMedicine;
                                        return (
                                            <p className="text-2xl font-black text-blue-700">
                                                {Number(rubberW + chemW).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                                <span className="text-sm font-normal text-blue-400 ml-1">กก.</span>
                                            </p>
                                        );
                                    })()}
                                </div>
                                <p className="text-[10px] text-blue-400 font-medium mt-1">น้ำยาง + สารเคมีที่ใส่</p>
                            </div>
                        </div>

                        {/* Extra daily costs row */}
                        <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x divide-gray-100 border-t border-gray-100 bg-gray-50/30">
                            <div className="p-4 flex items-center justify-between">
                                <div className="flex items-center">
                                    <Wallet size={16} className="text-red-400 mr-2" />
                                    <span className="text-sm font-bold text-gray-600">ค่าใช้จ่ายทั่วไป:</span>
                                </div>
                                <span className="text-sm font-black text-red-600">-{Number(filteredData.todaySummary.expenses).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} ฿</span>
                            </div>
                            <div className="p-4 flex items-center justify-between">
                                <div className="flex items-center">
                                    <Users size={16} className="text-orange-400 mr-2" />
                                    <span className="text-sm font-bold text-gray-600">ค่าจ้างพนักงาน:</span>
                                </div>
                                <span className="text-sm font-black text-red-600">-{Number(filteredData.todaySummary.wages).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} ฿</span>
                            </div>
                            <div className={`p-4 flex items-center justify-between bg-gradient-to-r ${filteredData.todaySummary.netOutcome >= 0 ? 'from-green-600 to-green-500' : 'from-red-600 to-red-500'} text-white`}>
                                <div className="flex items-center">
                                    <BarChart3 size={18} className="mr-2" />
                                    <span className="text-sm font-black uppercase tracking-wider">ผลประกอบการสุทธิ:</span>
                                </div>
                                <div className="text-right">
                                    <span className="text-lg font-black">{Number(filteredData.todaySummary.netOutcome).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                                    <span className="text-xs ml-1 opacity-80 font-bold">฿</span>
                                </div>
                            </div>
                        </div>
                    </div>
                    {/* Summary Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-24 h-24 bg-blue-50 rounded-full group-hover:scale-150 transition-transform duration-500 ease-out z-0"></div>
                            <div className="relative z-10">
                                <p className="text-sm font-medium text-gray-500 mb-1">ยอดรับซื้อรวม (บาท)</p>
                                <p className="text-3xl font-bold text-gray-900">฿{Number(filteredData.buyTotal).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</p>
                                <p className="text-xs text-blue-600 mt-2 font-medium">{Number(filteredData.buyWeight).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} กิโลกรัม</p>
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-24 h-24 bg-orange-50 rounded-full group-hover:scale-150 transition-transform duration-500 ease-out z-0"></div>
                            <div className="relative z-10">
                                <p className="text-sm font-medium text-gray-500 mb-1">ยอดขายรวม (บาท)</p>
                                <p className="text-3xl font-bold text-gray-900">฿{Number(filteredData.sellTotal).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</p>
                                <p className="text-xs text-orange-600 mt-2 font-medium">{Number(filteredData.sellWeight).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} กิโลกรัม</p>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm relative overflow-hidden group">
                            <div className="absolute -right-6 -bottom-6 w-24 h-24 bg-purple-50 rounded-full group-hover:scale-150 transition-transform duration-500 ease-out z-0"></div>
                            <div className="relative z-10">
                                <p className="text-sm font-medium text-gray-500 mb-1">สต๊อกน้ำยางคงเหลือ (กก.)</p>
                                <p className="text-3xl font-bold text-gray-900">{Number(filteredData.currentStock).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</p>
                                <p className="text-[11px] text-purple-600 mt-2 font-black tracking-tight leading-none">
                                    สูตร: {Number(filteredData.buyWeight).toLocaleString()} - {Number(filteredData.sellWeight).toLocaleString()} {filteredData.sellLoss >= 0 ? '-' : '+'} {Number(Math.abs(filteredData.sellLoss)).toLocaleString()} (ปรับปรุง) + {Number(filteredData.periodChemicals.ammonia + filteredData.periodChemicals.water + filteredData.periodChemicals.whiteMedicine).toLocaleString()} (สารเคมี)
                                </p>
                            </div>
                        </div>

                        <div className={`bg-white p-6 rounded-xl border border-gray-100 shadow-sm lg:col-span-2 relative overflow-hidden group ${filteredData.profit >= 0 ? 'bg-green-50/30' : 'bg-red-50/30'}`}>
                            <div className={`absolute right-0 top-0 w-full h-full opacity-10 ${filteredData.profit >= 0 ? 'bg-gradient-to-l from-green-400' : 'bg-gradient-to-l from-red-400'}`}></div>
                            <div className="relative z-10 flex justify-between items-center h-full">
                                <div>
                                    <p className="text-sm font-medium text-gray-500 mb-1">กำไร / ขาดทุน (ขั้นต้น)</p>
                                    <p className={`text-4xl font-black ${filteredData.profit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                        {filteredData.profit >= 0 ? '+' : ''}฿{Number(filteredData.profit).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}
                                    </p>
                                </div>
                                <div className="hidden sm:block text-right">
                                    <p className="text-sm font-medium text-gray-500 mb-1">ส่วนต่างน้ำหนัก (Stock/สูญเสีย)</p>
                                    <p className="text-xl font-bold text-gray-700">{Number(filteredData.currentStock).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} กก.</p>
                                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">
                                        สูตร: {Number(filteredData.buyWeight).toLocaleString()} - {Number(filteredData.sellWeight).toLocaleString()} {filteredData.sellLoss >= 0 ? '-' : '+'} {Number(Math.abs(filteredData.sellLoss)).toLocaleString()} + {Number(filteredData.periodChemicals.ammonia).toLocaleString()} + {Number(filteredData.periodChemicals.water).toLocaleString()} + {Number(filteredData.periodChemicals.whiteMedicine).toLocaleString()}
                                    </p>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Chart */}
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-lg font-bold text-gray-900">กราฟเปรียบเทียบยอดรับซื้อ-ขาย (รายวัน)</h2>
                            <button className="flex items-center text-sm font-medium text-rubber-600 hover:text-rubber-800 transition-colors">
                                <Download size={16} className="mr-1" />
                                ส่งออกข้อมูล
                            </button>
                        </div>

                        {filteredData.chartData.length === 0 ? (
                            <div className="h-80 flex flex-col justify-center items-center text-gray-400">
                                <BarChart className="w-16 h-16 opacity-20 mb-4" />
                                <p>ไม่มีข้อมูลในช่วงเวลาที่เลือก</p>
                            </div>
                        ) : (
                            <div className="h-96 w-full mt-4">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={filteredData.chartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#6b7280', fontSize: 12 }} dy={10} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#6b7280', fontSize: 12 }} dx={-10} tickFormatter={(v) => `฿${v / 1000}k`} />
                                        <Tooltip
                                            cursor={{ fill: '#f3f4f6' }}
                                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                            formatter={(value) => [`฿${Number(value).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}`, undefined]}
                                        />
                                        <Legend iconType="circle" wrapperStyle={{ paddingTop: '20px' }} />
                                        <Bar dataKey="ซื้อ" fill="#3b82f6" radius={[4, 4, 0, 0]} maxBarSize={50} />
                                        <Bar dataKey="ขาย" fill="#f97316" radius={[4, 4, 0, 0]} maxBarSize={50} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        )}
                    </div>
                </>
            )}
        </div>
    );
};

export default Report;

pages/sell/SellForm.jsx.content:
import React from 'react';
import { 
    Truck, ChevronDown, Upload, X, Edit2
} from 'lucide-react';

const SellForm = ({ 
    register, handleSubmit, onSubmit, watch, setValue, reset, errors,
    editingRecord, setEditingRecord, isSubmitting,
    watchRubberType, watchWeight, watchDrc, watchPricePerKg,
    factorySearch, setFactorySearch, showFactoryResults, setShowFactoryResults,
    truckSearch, setTruckSearch, showTruckResults, setShowTruckResults,
    staffSearch, setStaffSearch, showStaffResults, setShowStaffResults,
    factories, trucks, staff,
    lossSign, setLossSign, isAutoAdjust, setIsAutoAdjust,
    stockMetrics, calculateDryRubber, calculateTotal,
    previewUrl, setPreviewUrl, setSelectedFile, handleImageUpload
}) => {
    return (
        <div className="lg:col-span-1">
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                    <Truck className="mr-2 text-orange-500" size={20} />
                    {editingRecord ? 'แก้ไขรายการขาย' : 'เพิ่มรายการขาย'}
                </h2>

                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="flex p-1 bg-gray-100 rounded-lg">
                        <button 
                            type="button"
                            onClick={() => { setValue('rubberType', 'latex'); setIsAutoAdjust(true); }}
                            className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${watchRubberType === 'latex' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                        >
                            น้ำยางสด
                        </button>
                        <button 
                            type="button"
                            onClick={() => { setValue('rubberType', 'cup_lump'); setIsAutoAdjust(false); setValue('lossWeight', '0'); }}
                            className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${watchRubberType === 'cup_lump' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                        >
                            ขี้ยาง
                        </button>
                    </div>
                    <input type="hidden" {...register('rubberType')} />

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">วันที่ <span className="text-red-500">*</span></label>
                        <input 
                            type="date" 
                            {...register('date', { 
                                required: 'กรุณาระบุวันที่ขาย',
                                validate: (val) => new Date(val) <= new Date() || 'ห้ามระบุวันที่ในอนาคต'
                            })} 
                            className={`w-full px-3 py-2 border rounded-lg focus:ring-orange-500 focus:border-orange-500 ${errors.date ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                        />
                        {errors.date && <p className="text-red-500 text-xs mt-1 font-medium">{errors.date.message}</p>}
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">โรงงาน / ผู้ซื้อ</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <ChevronDown className="h-4 w-4 text-gray-400" />
                            </div>
                            <input 
                                type="text" 
                                value={factorySearch}
                                onChange={(e) => {
                                    setFactorySearch(e.target.value);
                                    setShowFactoryResults(true);
                                    setValue('buyerName', e.target.value);
                                }}
                                onFocus={() => setShowFactoryResults(true)}
                                onClick={() => setShowFactoryResults(true)}
                                placeholder="ค้นหาชื่อโรงงาน / ผู้ซื้อ..." 
                                className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500 cursor-pointer" 
                            />
                            {showFactoryResults && (
                                <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-2xl max-h-60 overflow-auto">
                                    {factories.filter(f => 
                                        !factorySearch || f.name?.toLowerCase().includes(factorySearch.toLowerCase())
                                    ).length === 0 ? (
                                        <div className="p-4 text-center text-gray-500 text-sm">ไม่พบข้อมูลโรงงาน</div>
                                    ) : (
                                        factories.filter(f => 
                                            !factorySearch || f.name?.toLowerCase().includes(factorySearch.toLowerCase())
                                        ).map(f => (
                                            <div 
                                                key={f.id}
                                                className="px-4 py-3 hover:bg-orange-50 cursor-pointer border-b border-gray-50 last:border-0 group"
                                                onClick={() => {
                                                    setValue('buyerName', f.name);
                                                    setValue('factoryId', f.id);
                                                    setFactorySearch(f.name);
                                                    setShowFactoryResults(false);
                                                }}
                                            >
                                                <div className="font-black text-gray-900 group-hover:text-orange-700">{f.name}</div>
                                                <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">ID: {f.code || '-'}</div>
                                            </div>
                                        ))
                                    )}
                                </div>
                            )}
                        </div>
                        <input type="hidden" {...register('buyerName', { required: true })} />
                        <input type="hidden" {...register('factoryId')} />
                    </div>

                    {watchRubberType === 'latex' && (
                        <>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">รถขนส่ง</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <ChevronDown className="h-4 w-4 text-gray-400" />
                                    </div>
                                    <input 
                                        type="text" 
                                        value={truckSearch}
                                        onChange={(e) => {
                                            setTruckSearch(e.target.value);
                                            setShowTruckResults(true);
                                            setValue('truckInfo', e.target.value);
                                        }}
                                        onFocus={() => setShowTruckResults(true)}
                                        placeholder="ค้นหาทะเบียนรถ..." 
                                        className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500 cursor-pointer" 
                                    />
                                    {showTruckResults && (
                                        <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-2xl max-h-60 overflow-auto">
                                            {trucks.filter(t => 
                                                !truckSearch || 
                                                t.licensePlate?.toLowerCase().includes(truckSearch.toLowerCase()) || 
                                                t.brand?.toLowerCase().includes(truckSearch.toLowerCase())
                                            ).length === 0 ? (
                                                <div className="p-4 text-center text-gray-500 text-sm">ไม่พบข้อมูลรถ</div>
                                            ) : (
                                                trucks.filter(t => 
                                                    !truckSearch ||
                                                    t.licensePlate?.toLowerCase().includes(truckSearch.toLowerCase()) || 
                                                    t.brand?.toLowerCase().includes(truckSearch.toLowerCase())
                                                ).map(t => (
                                                    <div 
                                                        key={t.id}
                                                        className="px-4 py-3 hover:bg-orange-50 cursor-pointer border-b border-gray-50 last:border-0 group"
                                                        onClick={() => {
                                                            setValue('truckInfo', t.licensePlate);
                                                            setValue('truckId', t.id);
                                                            setTruckSearch(t.licensePlate);
                                                            setShowTruckResults(false);
                                                        }}
                                                    >
                                                        <div className="font-black text-gray-900 group-hover:text-orange-700">{t.licensePlate}</div>
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">{t.brand} {t.model}</div>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    )}
                                </div>
                                <input type="hidden" {...register('truckInfo')} />
                                <input type="hidden" {...register('truckId')} />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">พนักงานผู้รับผิดชอบ</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <ChevronDown className="h-4 w-4 text-gray-400" />
                                    </div>
                                    <input 
                                        type="text" 
                                        value={staffSearch}
                                        onChange={(e) => {
                                            setStaffSearch(e.target.value);
                                            setShowStaffResults(true);
                                        }}
                                        onFocus={() => setShowStaffResults(true)}
                                        placeholder="ค้นหาชื่อพนักงาน..." 
                                        className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500 cursor-pointer" 
                                    />
                                    {showStaffResults && (
                                        <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-2xl max-h-60 overflow-auto">
                                            {staff.filter(s => 
                                                !staffSearch || s.name?.toLowerCase().includes(staffSearch.toLowerCase())
                                            ).length === 0 ? (
                                                <div className="p-4 text-center text-gray-500 text-sm">ไม่พบข้อมูลพนักงาน</div>
                                            ) : (
                                                staff.filter(s => 
                                                    !staffSearch || s.name?.toLowerCase().includes(staffSearch.toLowerCase())
                                                ).map(s => (
                                                    <div 
                                                        key={s.id}
                                                        className="px-4 py-3 hover:bg-orange-50 cursor-pointer border-b border-gray-50 last:border-0 group"
                                                        onClick={() => {
                                                            setValue('employeeId', s.id);
                                                            setStaffSearch(s.name);
                                                            setShowStaffResults(false);
                                                        }}
                                                    >
                                                        <div className="font-black text-gray-900 group-hover:text-orange-700">{s.name}</div>
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">Phone: {s.phone || '-'}</div>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    )}
                                </div>
                                <input type="hidden" {...register('employeeId')} />
                            </div>
                        </>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <div className="flex justify-between items-center mb-1">
                                <label className="block text-sm font-medium text-gray-700 font-bold">น้ำหนักรวมขาย (กก.)</label>
                                <button 
                                    type="button"
                                    onClick={() => setValue('weight', watchRubberType === 'cup_lump' ? stockMetrics.cupLumpStock : stockMetrics.currentStock)}
                                    className="text-[10px] bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded-md font-black hover:bg-gray-200 transition-colors cursor-pointer"
                                    title="คลิกเพื่อใส่ค่ายอดคงเหลือ"
                                >
                                    คงเหลือ: {(watchRubberType === 'cup_lump' ? stockMetrics.cupLumpStock : stockMetrics.currentStock).toLocaleString()} กก.
                                </button>
                            </div>
                            <input 
                                type="number" 
                                step="0.1" 
                                {...register('weight', { 
                                    required: 'กรุณาระบุน้ำหนักที่ขาย',
                                    min: { value: 0.1, message: 'น้ำหนักต้องมากกว่า 0' }
                                })} 
                                className={`w-full px-3 py-2 border rounded-lg focus:ring-orange-500 focus:border-orange-500 font-bold ${errors.weight ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                            />
                            {errors.weight && <p className="text-red-500 text-[10px] mt-1 font-medium">{errors.weight.message}</p>}
                        </div>
                        {watchRubberType === 'latex' && (
                            <div>
                                <div className="flex justify-between items-center mb-1">
                                    <label className="block text-sm font-medium text-gray-700">DRC (%)</label>
                                    <button 
                                        type="button"
                                        onClick={() => setValue('drc', stockMetrics.avgDrc)}
                                        className="text-[10px] bg-orange-50 text-orange-700 px-1.5 py-0.5 rounded-md font-black hover:bg-orange-100 transition-colors cursor-pointer"
                                        title="คลิกเพื่อใช้ค่า DRC เฉลี่ย"
                                    >
                                        เฉลี่ย: {stockMetrics.avgDrc.toFixed(2)}%
                                    </button>
                                </div>
                                <input 
                                    type="number" 
                                    step="0.01" 
                                    {...register('drc', { 
                                        required: 'กรุณาระบุเปอร์เซ็นต์ DRC',
                                        min: { value: 1, message: 'DRC ขั้นต่ำ 1%' },
                                        max: { value: 100, message: 'DRC สูงสุด 100%' }
                                    })} 
                                    className={`w-full px-3 py-2 border rounded-lg focus:ring-orange-500 focus:border-orange-500 ${errors.drc ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                                />
                                {errors.drc && <p className="text-red-500 text-[10px] mt-1 font-medium">{errors.drc.message}</p>}
                            </div>
                        )}
                    </div>

                    {watchRubberType === 'latex' && (
                        <div className="p-3 bg-gray-50 rounded-lg border border-gray-100 border-dashed">
                            <div className="flex justify-between items-center mb-2">
                                <label className="block text-sm font-bold text-gray-700">ปรับปรุงสต๊อก (Stock Adjustment)</label>
                                <button 
                                    type="button"
                                    onClick={() => setIsAutoAdjust(!isAutoAdjust)}
                                    className={`px-2 py-1 rounded text-[10px] font-black transition-all flex items-center gap-1 ${isAutoAdjust ? 'bg-orange-600 text-white' : 'bg-gray-200 text-gray-500'}`}
                                >
                                    {isAutoAdjust ? 'AUTO ON' : 'AUTO OFF'}
                                </button>
                            </div>

                            <div className="flex items-center space-x-2 mb-2">
                                <button 
                                    type="button"
                                    onClick={() => { setLossSign('plus'); setIsAutoAdjust(false); }}
                                    className={`flex-1 py-1.5 rounded-md text-[11px] font-black transition-all ${lossSign === 'plus' ? 'bg-green-600 text-white shadow-sm ring-2 ring-green-100' : 'bg-white text-gray-400 border border-gray-200 hover:bg-gray-50'}`}
                                >
                                    + เพิ่มสต๊อก
                                </button>
                                <button 
                                    type="button"
                                    onClick={() => { setLossSign('minus'); setIsAutoAdjust(false); }}
                                    className={`flex-1 py-1.5 rounded-md text-[11px] font-black transition-all ${lossSign === 'minus' ? 'bg-red-600 text-white shadow-sm ring-2 ring-red-100' : 'bg-white text-gray-400 border border-gray-200 hover:bg-gray-50'}`}
                                >
                                    - ลดสต๊อก (สูญเสีย)
                                </button>
                            </div>

                            <div className="relative">
                                <div className={`absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none font-bold ${lossSign === 'plus' ? 'text-green-600' : 'text-red-600'}`}>
                                    {lossSign === 'plus' ? '+' : '-'}
                                </div>
                                <input 
                                    type="number" 
                                    step="0.1" 
                                    {...register('lossWeight')} 
                                    readOnly={isAutoAdjust}
                                    placeholder="กรอกน้ำหนัก (กก.)"
                                    className={`w-full pl-8 pr-3 py-2 border rounded-lg focus:ring-opacity-50 font-bold transition-colors ${
                                        isAutoAdjust ? 'bg-gray-100 text-gray-500 cursor-not-allowed border-gray-200' :
                                        lossSign === 'plus' 
                                            ? 'border-green-200 focus:ring-green-500 focus:border-green-500 bg-white text-green-700' 
                                            : 'border-red-200 focus:ring-red-500 focus:border-red-500 bg-white text-red-700'
                                    }`} 
                                />
                            </div>
                            <p className="text-[10px] text-gray-400 mt-2">
                                {isAutoAdjust ? `* คำนวณอัตโนมัติเพื่อให้สต๊อกเหลือ 0 กก.` : `* ใช้สำหรับปรับยอดคงเหลือให้ตรงกับหน้างานจริง`}
                            </p>
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">{watchRubberType === 'cup_lump' ? 'ราคาขายขี้ยาง (บาท/กก.)' : 'ราคาขายน้ำยาง (บาท/กก. ยางแห้ง)'} <span className="text-red-500">*</span></label>
                        <input 
                            type="number" 
                            step="0.01" 
                            {...register('pricePerKg', { 
                                required: 'กรุณาระบุราคาขาย',
                                min: { value: 0.1, message: 'ราคาต้องมากกว่า 0' }
                            })} 
                            className={`w-full px-3 py-2 border rounded-lg focus:ring-orange-500 focus:border-orange-500 ${errors.pricePerKg ? 'border-red-500 bg-red-50' : 'border-gray-300'}`} 
                        />
                        {errors.pricePerKg && <p className="text-red-500 text-xs mt-1 font-medium">{errors.pricePerKg.message}</p>}
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">หมายเหตุ</label>
                        <input type="text" placeholder="ข้อมูลเพิ่มเติม..." {...register('note')} className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">หลักฐานการขาย (ใบชั่ง/สลิป)</label>
                        <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-lg hover:bg-gray-50 transition-colors relative overflow-hidden group">
                            {previewUrl ? (
                                <div className="absolute inset-0 flex items-center justify-center bg-black/5 group-hover:bg-black/20 transition-all cursor-pointer">
                                    <img src={previewUrl} alt="Preview" className="h-full w-full object-cover opacity-80" />
                                    <div className="absolute bg-white/90 p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Edit2 size={24} className="text-orange-600" />
                                    </div>
                                    <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleImageUpload} accept="image/*" />
                                    <button 
                                        type="button" 
                                        onClick={(e) => { e.stopPropagation(); setPreviewUrl(null); setSelectedFile(null); setValue('receiptUrl', ''); }}
                                        className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full hover:bg-red-600 z-10"
                                    >
                                        <X size={16} />
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-1 text-center">
                                    <Upload className="mx-auto h-12 w-12 text-gray-400 group-hover:text-orange-400 transition-colors" />
                                    <div className="flex text-sm text-gray-600 justify-center">
                                        <label className="relative cursor-pointer bg-white rounded-md font-medium text-orange-600 hover:text-orange-500 focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-orange-500">
                                            <span>อัปโหลดไฟล์</span>
                                            <input type="file" className="sr-only" onChange={handleImageUpload} accept="image/*" />
                                        </label>
                                    </div>
                                    <p className="text-xs text-gray-500">PNG, JPG up to 10MB</p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 mt-6 space-y-2">
                        <div className="flex justify-between items-center">
                            <span className="text-sm text-orange-800">{watchRubberType === 'cup_lump' ? 'น้ำหนักขี้ยางรวม:' : 'น้ำยางแห้งรวม:'}</span>
                            <span className="font-bold text-orange-900">{calculateDryRubber().toLocaleString()} กก.</span>
                        </div>
                        <div className="flex justify-between items-center pt-2 border-t border-orange-200">
                            <span className="text-sm font-bold text-orange-800">ยอดเงินรวม:</span>
                            <span className="text-xl font-black text-orange-900">฿{calculateTotal().toLocaleString()}</span>
                        </div>
                    </div>

                    <div className="flex space-x-3 mt-6">
                        {editingRecord && (
                            <button 
                                type="button"
                                onClick={() => { 
                                    setEditingRecord(null); 
                                    reset(); 
                                    setFactorySearch('');
                                    setTruckSearch('');
                                    setStaffSearch('');
                                    setPreviewUrl(null);
                                    setSelectedFile(null);
                                }}
                                className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 font-medium transition-colors"
                            >
                                ยกเลิก
                            </button>
                        )}
                        <button 
                            type="submit" 
                            disabled={isSubmitting}
                            className="flex-[2] bg-orange-600 text-white font-bold py-2 rounded-lg hover:bg-orange-700 transition-colors shadow-md disabled:opacity-50"
                        >
                            {isSubmitting ? 'กำลังบันทึก...' : (editingRecord ? 'อัปเดตรายการ' : 'บันทึกรายการขาย')}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default SellForm;

pages/Sell.jsx.content:
import React, { useState, useEffect, useRef } from 'react';
import { useForm } from 'react-hook-form';
import { format } from 'date-fns';
import toast from 'react-hot-toast';
import { 
    addSellRecord, fetchSellRecords, deleteRecord, updateRecord, fetchFarmers, fetchStaff, 
    fetchFactories, fetchTrucks, isCached, getSettings, saveReceiptImageToDrive, 
    deleteReceiptFileToDrive, fetchBuyRecords, fetchChemicalUsage 
} from '../services/apiService';
import { truncateOneDecimal, truncateTwoDecimals } from '../utils/calculations';
import { useAuth } from '../context/AuthContext';

// Sub-components
import SellStockCards from './sell/SellStockCards';
import SellForm from './sell/SellForm';
import SellTable from './sell/SellTable';
import SellPaperReceipt from './sell/SellPaperReceipt';
import DeleteConfirmDialog from './buy/DeleteConfirmDialog'; // Reusing from buy folder

export const Sell = () => {
    const { user } = useAuth();
    const [records, setRecords] = useState([]);
    const [factories, setFactories] = useState([]);
    const [trucks, setTrucks] = useState([]);
    const [staff, setStaff] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSubmitting, setSubmitting] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedDate, setSelectedDate] = useState(format(new Date(), 'yyyy-MM-dd'));
    const [allBuys, setAllBuys] = useState([]);
    const [chemicalUsage, setChemicalUsage] = useState([]);

    // Selection state
    const [showFactoryResults, setShowFactoryResults] = useState(false);
    const [factorySearch, setFactorySearch] = useState('');
    const [showTruckResults, setShowTruckResults] = useState(false);
    const [truckSearch, setTruckSearch] = useState('');
    const [showStaffResults, setShowStaffResults] = useState(false);
    const [staffSearch, setStaffSearch] = useState('');

    const [printingRecord, setPrintingRecord] = useState(null);
    const [editingRecord, setEditingRecord] = useState(null);
    const [confirmDeleteId, setConfirmDeleteId] = useState(null);
    const [settings, setLocalSettings] = useState({ factoryName: 'ร้านรับซื้อน้ำยางพารา', address: '', phone: '' });
    const [lossSign, setLossSign] = useState('minus'); 
    const [isAutoAdjust, setIsAutoAdjust] = useState(true);
    const isDemo = false;

    // Form setup
    const { register, handleSubmit, watch, setValue, reset, formState: { errors } } = useForm({
        defaultValues: {
            date: format(new Date(), 'yyyy-MM-dd'),
            buyerName: '',
            factoryId: '',
            employeeId: '',
            truckId: '',
            truckInfo: '',
            weight: '',
            lossWeight: '',
            drc: '',
            pricePerKg: '',
            note: '',
            receiptUrl: '',
            rubberType: 'latex'
        }
    });

    const watchRubberType = watch('rubberType');
    const watchWeight = watch('weight');
    const watchDrc = watch('drc');
    const watchPricePerKg = watch('pricePerKg');
    const [selectedFile, setSelectedFile] = useState(null);
    const [previewUrl, setPreviewUrl] = useState(null);

    // References for printing
    const printRef = useRef(null);

    useEffect(() => {
        loadData();
        fetchSettings();

        const handleClickOutside = (event) => {
            if (!event.target.closest('.relative')) {
                setShowFactoryResults(false);
                setShowTruckResults(false);
                setShowStaffResults(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const fetchSettings = async () => {
        try {
            const res = await getSettings();
            if (res.status === 'success' && res.data) {
                setLocalSettings(prev => ({ ...prev, ...res.data }));
            }
        } catch (e) {
            console.error('Settings error:', e);
        }
    };

     const loadData = async () => {
         setIsLoading(true);
         try {
             const [recs, facs, trks, stf, buys, chems] = await Promise.all([
                 fetchSellRecords(),
                 fetchFactories(),
                 fetchTrucks(),
                 fetchStaff(),
                 fetchBuyRecords(),
                 fetchChemicalUsage()
             ]);
             setRecords(recs || []);
             setFactories(facs || []);
             setTrucks(trks || []);
             setStaff(stf || []);
             setAllBuys(buys || []);
             setChemicalUsage(chems || []);
         } catch (error) {
             toast.error('โหลดข้อมูลล้มเหลว');
         } finally {
             setIsLoading(false);
         }
     };

    const onSubmit = async (data) => {
        setSubmitting(true);
        const toastId = toast.loading(editingRecord ? 'กำลังอัปเดต...' : 'กำลังบันทึก...');

        try {
            let receiptUrl = data.receiptUrl || '';

            if (selectedFile) {
                toast.loading('กำลังอัปโหลดรูปภาพ...', { id: toastId });
                const reader = new FileReader();
                const base64Promise = new Promise((resolve) => {
                    reader.onloadend = () => resolve(reader.result);
                    reader.readAsDataURL(selectedFile);
                });
                const base64 = await base64Promise;
                const filename = `Sell_Receipt_${Date.now()}.png`;
                const uploadRes = await saveReceiptImageToDrive(base64, filename);
                if (uploadRes.status === 'success') {
                    receiptUrl = uploadRes.url;
                }
            }

            const weight = Number(data.weight);
            const isCupLump = data.rubberType === 'cup_lump';

            const rawLoss = isCupLump ? 0 : Number(data.lossWeight || 0);
            const lWeight = lossSign === 'plus' ? -rawLoss : rawLoss;

            const drc = isCupLump ? 100 : Number(data.drc);
            const price = Number(data.pricePerKg);
            const dryRubber = isCupLump ? weight : truncateTwoDecimals((weight * drc) / 100);
            const total = truncateTwoDecimals(dryRubber * price);

            const payload = {
                ...data,
                weight,
                lossWeight: lWeight,
                drc,
                pricePerKg: price,
                total,
                receiptUrl,
                profitShareAmount: 0 
            };

            let res;
            if (editingRecord) {
                const { id, created_at, timestamp, ...updatePayload } = payload;
                res = await updateRecord('sells', editingRecord.id, updatePayload);
            } else {
                res = await addSellRecord(payload);
            }

            if (res.status === 'success') {
                toast.success(editingRecord ? 'อัปเดตสำเร็จ' : 'บันทึกสำเร็จ', { id: toastId });
                loadData();
                reset({
                    date: format(new Date(), 'yyyy-MM-dd'),
                    lossWeight: '',
                    note: '',
                    rubberType: data.rubberType || 'latex'
                });
                setFactorySearch('');
                setTruckSearch('');
                setStaffSearch('');
                setSelectedFile(null);
                setPreviewUrl(null);
                setEditingRecord(null);
                setLossSign('minus');
                setIsAutoAdjust(true);
            } else {
                toast.error(res.message, { id: toastId });
            }
        } catch (error) {
            toast.error('ข้อผิดพลาด: ' + error.message, { id: toastId });
        } finally {
            setSubmitting(false);
        }
    };

    const handleEdit = (record) => {
        setEditingRecord(record);
        setIsAutoAdjust(false);

        const lWeight = Number(record.lossWeight || 0);
        const lSign = lWeight < 0 ? 'plus' : 'minus';
        const absLoss = Math.abs(lWeight);

        reset({
            date: record.date,
            buyerName: record.buyerName,
            factoryId: record.factoryId,
            employeeId: record.employeeId,
            truckId: record.truckId,
            truckInfo: record.truckInfo,
            weight: record.weight,
            drc: record.drc,
            lossWeight: absLoss === 0 ? '' : absLoss,
            pricePerKg: record.pricePerKg,
            note: record.note,
            receiptUrl: record.receiptUrl || '',
            rubberType: record.rubberType || 'latex'
        });

        setLossSign(lSign);
        setFactorySearch(record.buyerName || '');
        setTruckSearch(record.truckInfo || '');
        setPreviewUrl(record.receiptUrl || null);
        const currentStaff = staff.find(s => s.id === record.employeeId);
        setStaffSearch(currentStaff ? currentStaff.name : '');
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = (id) => { setConfirmDeleteId(id); };

    const confirmDelete = async () => {
        if (!confirmDeleteId) return;
        const id = confirmDeleteId;
        setConfirmDeleteId(null);
        const toastId = toast.loading('กำลังลบรายการ...');
        try {
            const targetRecord = records.find(r => String(r.id) === String(id));
            const res = await deleteRecord('sells', id);
            if (res.status === 'success') {
                if (targetRecord && targetRecord.receiptUrl) {
                    deleteReceiptFileToDrive(targetRecord.receiptUrl).catch(e => console.warn(e));
                }
                toast.success('ลบสำเร็จ', { id: toastId });
                setRecords(prev => prev.filter(r => String(r.id) !== String(id)));
            } else {
                toast.error(res.message || 'ลบล้มเหลว', { id: toastId });
            }
        } catch (error) {
            toast.error('ลบล้มเหลว: ' + error.message, { id: toastId });
        }
    };

    const handlePrint = (record) => {
        const toastId = toast.loading('กำลังเตรียมใบส่งสินค้า...');
        setPrintingRecord(record);
        setTimeout(() => {
            toast.dismiss(toastId);
            window.print();
            setPrintingRecord(null);
        }, 1000);
    };

    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (!file) return;
        setSelectedFile(file);
        setPreviewUrl(URL.createObjectURL(file));
        toast.success('เลือกรูปภาพสำเร็จ');
    };

    const calculateDryRubber = () => {
        const rubberType = watchRubberType;
        const w = truncateOneDecimal(Number(watchWeight) || 0);
        if (rubberType === 'cup_lump') return w;
        const d = truncateTwoDecimals(Number(watchDrc) || 0);
        return truncateTwoDecimals((w * d) / 100);
    };

    const calculateTotal = () => {
        const dryRubber = calculateDryRubber();
        const p = truncateTwoDecimals(Number(watchPricePerKg) || 0);
        return truncateTwoDecimals(dryRubber * p);
    };

    const filteredRecords = records.filter(r => {
        const matchesSearch = (r.buyerName || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
                              (r.id || '').toLowerCase().includes(searchTerm.toLowerCase());
        const matchesDate = (r.date || '').split('T')[0] === selectedDate;
        return matchesSearch && matchesDate;
    });

    const stockMetrics = React.useMemo(() => {
        const latexBuys = allBuys.filter(b => b.rubberType === 'latex' || !b.rubberType);
        const cupLumpBuys = allBuys.filter(b => b.rubberType === 'cup_lump' || b.rubberType === 'ขี้ยาง');

        const buyWeightLatex = latexBuys.reduce((sum, item) => {
            const net = Number(item.netWeight);
            if (!isNaN(net) && net > 0) return sum + net;
            return sum + (Number(item.weight || 0) - Number(item.bucketWeight || 0));
        }, 0);

        const buyWeightCupLump = cupLumpBuys.reduce((sum, item) => {
            const net = Number(item.netWeight);
            if (!isNaN(net) && net > 0) return sum + net;
            return sum + (Number(item.weight || 0) - Number(item.bucketWeight || 0));
        }, 0);

        const ammoniaWeight = chemicalUsage.filter(c => c.chemicalId === 'ammonia').reduce((sum, c) => sum + Number(c.amount || 0), 0);
        const waterWeight = chemicalUsage.filter(c => c.chemicalId === 'water').reduce((sum, c) => sum + Number(c.amount || 0), 0);
        const whiteMedWeight = chemicalUsage.filter(c => c.chemicalId === 'whiteMedicine').reduce((sum, c) => sum + Number(c.amount || 0), 0);

        const sellLatex = records.filter(r => r.rubberType === 'latex' || !r.rubberType);
        const sellCupLump = records.filter(r => r.rubberType === 'cup_lump');
        const sellWeightLatex = sellLatex.reduce((sum, r) => sum + Number(r.weight || 0), 0);
        const sellLossLatex = sellLatex.reduce((sum, r) => sum + Number(r.lossWeight || 0), 0);
        const sellWeightCupLump = sellCupLump.reduce((sum, r) => sum + Number(r.weight || 0), 0);

        const currentStockLatex = truncateOneDecimal(buyWeightLatex + ammoniaWeight + waterWeight + whiteMedWeight - sellWeightLatex - sellLossLatex);
        const currentStockCupLump = truncateOneDecimal(buyWeightCupLump - sellWeightCupLump);

        const totalWeightedDrc = latexBuys.reduce((sum, b) => {
            const net = Number(b.netWeight);
            const w = (!isNaN(net) && net > 0) ? net : (Number(b.weight || 0) - Number(b.bucketWeight || 0));
            return sum + (w * (Number(b.drc || 0)));
        }, 0);
        const avgDrc = buyWeightLatex > 0 ? truncateOneDecimal(totalWeightedDrc / buyWeightLatex) : 0;

        return { currentStock: currentStockLatex, cupLumpStock: currentStockCupLump, avgDrc };
    }, [allBuys, records, chemicalUsage]);

    // Auto Adjust Logic
    useEffect(() => {
        if (isAutoAdjust && watchWeight !== undefined && watchRubberType !== 'cup_lump') {
            const currentStock = stockMetrics.currentStock;
            const weightValue = Number(watchWeight) || 0;
            const diff = truncateOneDecimal(currentStock - weightValue);
            if (diff > 0) { setLossSign('minus'); setValue('lossWeight', diff); }
            else if (diff < 0) { setLossSign('plus'); setValue('lossWeight', Math.abs(diff)); }
            else { setValue('lossWeight', 0); }
        }
    }, [isAutoAdjust, watchWeight, watchRubberType, stockMetrics.currentStock, setValue]);

    return (
        <div className="space-y-6">
            <style dangerouslySetInnerHTML={{ __html: `
                @media print {
                    @page { size: auto; margin: 10mm; }
                    body { margin: 0; padding: 0; background: white; }
                    .print-hidden { display: none !important; }
                    .receipt-content { display: block !important; width: 100%; font-family: 'Noto Sans Thai', sans-serif; color: black; }
                }
            ` }} />

            <DeleteConfirmDialog confirmDeleteId={confirmDeleteId} setConfirmDeleteId={setConfirmDeleteId} confirmDelete={confirmDelete} />

            <SellPaperReceipt printingRecord={printingRecord} printRef={printRef} settings={settings} />

            <div className="print-hidden space-y-6">
                <SellStockCards stockMetrics={stockMetrics} />

                <div>
                    <h1 className="text-2xl font-bold text-gray-900 mb-2">บันทึกการขายยางพารา</h1>
                    <p className="text-gray-500 mb-6">บันทึกข้อมูลการขายยางให้โรงงาน/ปลายทาง และแนบหลักฐาน</p>

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        <SellForm 
                            register={register} handleSubmit={handleSubmit} onSubmit={onSubmit}
                            watch={watch} setValue={setValue} reset={reset} errors={errors}
                            editingRecord={editingRecord} setEditingRecord={setEditingRecord}
                            isSubmitting={isSubmitting} watchRubberType={watchRubberType}
                            watchWeight={watchWeight} watchDrc={watchDrc} watchPricePerKg={watchPricePerKg}
                            factorySearch={factorySearch} setFactorySearch={setFactorySearch}
                            showFactoryResults={showFactoryResults} setShowFactoryResults={setShowFactoryResults}
                            truckSearch={truckSearch} setTruckSearch={setTruckSearch}
                            showTruckResults={showTruckResults} setShowTruckResults={setShowTruckResults}
                            staffSearch={staffSearch} setStaffSearch={setStaffSearch}
                            showStaffResults={showStaffResults} setShowStaffResults={setShowStaffResults}
                            factories={factories} trucks={trucks} staff={staff}
                            lossSign={lossSign} setLossSign={setLossSign}
                            isAutoAdjust={isAutoAdjust} setIsAutoAdjust={setIsAutoAdjust}
                            stockMetrics={stockMetrics} calculateDryRubber={calculateDryRubber}
                            calculateTotal={calculateTotal} previewUrl={previewUrl}
                            setPreviewUrl={setPreviewUrl} setSelectedFile={setSelectedFile}
                            handleImageUpload={handleImageUpload}
                        />

                        <SellTable 
                            filteredRecords={filteredRecords} searchTerm={searchTerm}
                            setSearchTerm={setSearchTerm} selectedDate={selectedDate}
                            setSelectedDate={setSelectedDate} handleEdit={handleEdit}
                            handleDelete={handleDelete} handlePrint={handlePrint}
                            isLoading={isLoading} user={user}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Sell;

pages/settings/ActivityLog.jsx.content:
import React, { useState, useEffect } from 'react';
import { 
    History, 
    Search, 
    Filter, 
    Plus, 
    Pencil, 
    Trash2, 
    Info, 
    Calendar,
    User,
    ChevronDown,
    ChevronUp,
    RefreshCw,
    X,
    FileJson,
    Building2,
    Zap
} from 'lucide-react';
import { fetchActivityLogs, adminFetchReportUsers } from '../../services/apiService';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';
const ActivityLog = () => {
    const { user: currentUser } = useAuth();
    const [logs, setLogs] = useState([]);
    const [total, setTotal] = useState(0);
    const [isLoading, setIsLoading] = useState(true);
    const [offset, setOffset] = useState(0);
    const [expandedRow, setExpandedRow] = useState(null);
    const [usersList, setUsersList] = useState([]);
    const [filters, setFilters] = useState({ userId: '', type: '', action: '' });
    const [searchQuery, setSearchQuery] = useState('');
    const LIMIT = 20;

    const isSuperAdmin = currentUser?.role?.toLowerCase() === 'super_admin';

    useEffect(() => {
        if (isSuperAdmin) {
            const fetchUsers = async () => {
                try {
                    const data = await adminFetchReportUsers();
                    setUsersList(data || []);
                } catch (err) {
                    console.error('Error fetching users for filter:', err);
                }
            };
            fetchUsers();
        }
    }, [isSuperAdmin]);

    const loadLogs = async (newOffset = 0) => {
        setIsLoading(true);
        try {
            const params = {
                limit: LIMIT,
                offset: newOffset,
                ...filters
            };
            // Clean empty filters
            Object.keys(params).forEach(key => (params[key] === '' || params[key] === 'all') && delete params[key]);
            const res = await fetchActivityLogs(params);
            if (res.status === 'success') {
                setLogs(res.results);
                setTotal(res.total);
            } else {
                toast.error('ไม่สามารถดึงข้อมูลประวัติได้: ' + res.message);
            }
        } catch (err) {
            toast.error('เกิดข้อผิดพลาดในการโหลดข้อมูล');
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadLogs(offset);
    }, [offset, filters]);

    const handleFilterChange = (key, value) => {
        setFilters(prev => ({ ...prev, [key]: value }));
        // If user manually selects from dropdown, clear the search query to avoid confusion
        if (key === 'userId') setSearchQuery('');
        setOffset(0); // Reset to first page
    };

    const handleSearchSubmit = (e) => {
        if (e) e.preventDefault();

        // Logic: Try to find a direct match in usersList by name/store, 
        // otherwise assume it's a raw UserID string
        const searchTerm = searchQuery.trim().toLowerCase();
        if (!searchTerm) {
            handleFilterChange('userId', '');
            return;
        }

        const foundUser = usersList.find(u => 
            (u.store_name && u.store_name.toLowerCase().includes(searchTerm)) || 
            (u.username && u.username.toLowerCase().includes(searchTerm)) ||
            (u.id.toLowerCase() === searchTerm)
        );

        if (foundUser) {
            handleFilterChange('userId', foundUser.id);
        } else {
            // Assume it's a raw UserID if it looks like a prefix or UUID
            handleFilterChange('userId', searchTerm);
        }
    };

    const getActionIcon = (action) => {
        switch (action) {
            case 'CREATE': return <Plus className="text-green-500" size={16} />;
            case 'UPDATE': return <Pencil className="text-blue-500" size={16} />;
            case 'DELETE': return <Trash2 className="text-red-500" size={16} />;
            default: return <Info className="text-gray-400" size={16} />;
        }
    };

    const getEntityLabel = (type) => {
        const labels = {
            'buys': 'รายการซื้อ (Buy)',
            'sells': 'รายการขาย (Sell)',
            'farmers': 'เกษตรกร',
            'employees': 'ลูกจ้าง',
            'staff': 'พนักงาน',
            'factories': 'โรงงาน',
            'expenses': 'ค่าใช้จ่าย',
            'wages': 'ค่าจ้าง',
            'trucks': 'รถขนส่ง',
            'settings': 'ตั้งค่าระบบ',
            'subscriptions': 'สิทธิการสมัคร',
            'packages': 'แพ็กเกจสมาชิก'
        };
        return labels[type] || type;
    };

    const formatDateTime = (dateStr) => {
        const date = new Date(dateStr);
        return date.toLocaleString('th-TH', { 
            year: 'numeric', month: 'short', day: 'numeric',
            hour: '2-digit', minute: '2-digit'
        });
    };

    const renderDiff = (oldData, newData) => {
        if (!oldData && !newData) return <p className="text-gray-400 italic">ไม่มีข้อมูลแสดงผล</p>;

        // If it's an update, we might want to highlight changes
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {oldData && (
                    <div className="space-y-2">
                        <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest">ข้อมูลเดิม (Before)</div>
                        <div className="bg-gray-900 text-green-400 p-4 rounded-xl text-[11px] font-mono overflow-auto max-h-60 custom-scrollbar">
                            <pre>{JSON.stringify(oldData, null, 2)}</pre>
                        </div>
                    </div>
                )}
                {newData && (
                    <div className="space-y-2">
                        <div className="text-[10px] font-black text-rubber-600 uppercase tracking-widest">ข้อมูลใหม่ (After) {oldData ? '/ ปัจจุบัน' : ''}</div>
                        <div className="bg-gray-900 text-blue-300 p-4 rounded-xl text-[11px] font-mono overflow-auto max-h-60 custom-scrollbar">
                            <pre>{JSON.stringify(newData, null, 2)}</pre>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="max-w-6xl mx-auto pb-20">
            <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-black text-gray-900 flex items-center">
                        <History className="mr-3 text-rubber-600" />
                        บันทึกความเคลื่อนไหว (Activity Log)
                    </h1>
                    <p className="text-gray-500 text-sm mt-1 font-medium">ติดตามประวัติการเพิ่ม แก้ไข หรือลบข้อมูลสำคัญในกิจการของคุณ</p>
                </div>

                <div className="flex flex-wrap items-center gap-2">
                    {/* UserID Search (Express) - Super Admin Only */}
                    {isSuperAdmin && (
                        <form onSubmit={handleSearchSubmit} className="relative group">
                            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                                <Search size={14} />
                            </div>
                            <input 
                                type="text"
                                placeholder="ค้นหา UserID หรือชื่อร้าน..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                onBlur={() => handleSearchSubmit()}
                                className="pl-9 pr-4 py-2 bg-white border border-gray-100 rounded-xl text-xs font-bold text-gray-700 focus:outline-none focus:ring-2 focus:ring-rubber-500 shadow-sm min-w-[200px]"
                            />
                        </form>
                    )}

                    <div className="h-6 w-px bg-gray-100 mx-1 hidden md:block"></div>

                    {/* User Filter (Super Admin Only) */}
                    {isSuperAdmin && (
                        <div className="relative group">
                            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                                <Building2 size={16} />
                            </div>
                            <select 
                                value={filters.userId}
                                onChange={(e) => handleFilterChange('userId', e.target.value)}
                                className="pl-10 pr-8 py-2 bg-white border border-gray-100 rounded-xl text-xs font-bold text-gray-700 appearance-none focus:outline-none focus:ring-2 focus:ring-rubber-500 shadow-sm min-w-[160px]"
                            >
                                <option value="">เลือกทุกร้านค้า (All Stores)</option>
                                {usersList.map(u => (
                                    <option key={u.id} value={u.id}>
                                        {u.store_name || u.username} ({u.username})
                                    </option>
                                ))}
                            </select>
                            <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                        </div>
                    )}

                    {/* Type Filter */}
                    <div className="relative group">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                            <Filter size={14} />
                        </div>
                        <select 
                            value={filters.type}
                            onChange={(e) => handleFilterChange('type', e.target.value)}
                            className="pl-9 pr-8 py-2 bg-white border border-gray-100 rounded-xl text-xs font-bold text-gray-700 appearance-none focus:outline-none focus:ring-2 focus:ring-rubber-500 shadow-sm"
                        >
                            <option value="">ทั้งหมด (All Types)</option>
                            <option value="buys">รายการซื้อ (Buy)</option>
                            <option value="sells">รายการขาย (Sell)</option>
                            <option value="farmers">เกษตรกร</option>
                            <option value="employees">ลูกจ้าง</option>
                            <option value="staff">พนักงาน</option>
                            <option value="factories">โรงงาน</option>
                            <option value="expenses">ค่าใช้จ่าย</option>
                            <option value="wages">ค่าจ้าง</option>
                            <option value="trucks">รถขนส่ง</option>
                            <option value="settings">ตั้งค่าระบบ</option>
                            <option value="subscriptions">สิทธิการสมัคร</option>
                            <option value="packages">แพ็กเกจสมาชิก</option>
                        </select>
                        <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                    </div>

                    {/* Action Filter */}
                    <div className="relative group">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                            <Zap size={14} />
                        </div>
                        <select 
                            value={filters.action}
                            onChange={(e) => handleFilterChange('action', e.target.value)}
                            className="pl-9 pr-8 py-2 bg-white border border-gray-100 rounded-xl text-xs font-bold text-gray-700 appearance-none focus:outline-none focus:ring-2 focus:ring-rubber-500 shadow-sm"
                        >
                            <option value="">ทุกการกระทำ (All Actions)</option>
                            <option value="CREATE">เพิ่มข้อมูล (CREATE)</option>
                            <option value="UPDATE">แก้ไขข้อมูล (UPDATE)</option>
                            <option value="DELETE">ลบข้อมูล (DELETE)</option>
                        </select>
                        <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                    </div>

                    <div className="flex items-center space-x-2">
                        {(filters.userId || filters.type || filters.action) && (
                            <button 
                                onClick={() => {
                                    setFilters({ userId: '', type: '', action: '' });
                                    setSearchQuery('');
                                    setOffset(0);
                                }}
                                className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-all active:scale-95"
                                title="ล้างตัวกรองทั้งหมด"
                            >
                                <X size={20} />
                            </button>
                        )}
                        <button 
                            onClick={() => loadLogs(offset)}
                            disabled={isLoading}
                            className="flex items-center space-x-2 px-4 py-2 bg-rubber-600 rounded-xl shadow-lg shadow-rubber-200 text-xs font-black text-white hover:bg-rubber-700 transition-all active:scale-95 disabled:opacity-50"
                        >
                            <RefreshCw size={14} className={isLoading ? 'animate-spin' : ''} />
                            <span className="hidden sm:inline">รีเฟรช</span>
                        </button>
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <div className="bg-white rounded-[2rem] shadow-xl shadow-gray-200/50 border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-100">
                                <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Action</th>
                                <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Entity & ID</th>
                                <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Who</th>
                                <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">When</th>
                                <th className="px-6 py-4 text-center"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {isLoading && logs.length === 0 ? (
                                Array(5).fill(0).map((_, i) => (
                                    <tr key={i} className="animate-pulse">
                                        <td className="px-6 py-6"><div className="h-4 bg-gray-100 rounded w-20"></div></td>
                                        <td className="px-6 py-6"><div className="h-4 bg-gray-100 rounded w-32"></div></td>
                                        <td className="px-6 py-6"><div className="h-4 bg-gray-100 rounded w-24"></div></td>
                                        <td className="px-6 py-6"><div className="h-4 bg-gray-100 rounded w-28"></div></td>
                                        <td className="px-6 py-6"></td>
                                    </tr>
                                ))
                            ) : logs.length > 0 ? (
                                logs.map((log) => (
                                    <React.Fragment key={log.id}>
                                        <tr className={`hover:bg-gray-50/50 transition-colors group ${expandedRow === log.id ? 'bg-gray-50/50' : ''}`}>
                                            <td className="px-6 py-5">
                                                <div className="flex items-center space-x-3">
                                                    <div className={`p-2 rounded-xl bg-opacity-10 ${
                                                        log.action === 'CREATE' ? 'bg-green-100 text-green-600' : 
                                                        log.action === 'UPDATE' ? 'bg-blue-100 text-blue-600' : 
                                                        'bg-red-100 text-red-600'
                                                    }`}>
                                                        {getActionIcon(log.action)}
                                                    </div>
                                                    <span className={`text-xs font-black tracking-wider ${
                                                        log.action === 'CREATE' ? 'text-green-700' : 
                                                        log.action === 'UPDATE' ? 'text-blue-700' : 
                                                        'text-red-700'
                                                    }`}>
                                                        {log.action}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-5">
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold text-gray-900">{getEntityLabel(log.entityType)}</span>
                                                    <span className="text-[10px] font-mono text-gray-400">{log.entityId}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-5">
                                                <div className="flex items-center text-xs font-bold text-gray-600">
                                                    <User size={14} className="mr-2 text-gray-400" />
                                                    {log.username}
                                                </div>
                                            </td>
                                            <td className="px-6 py-5">
                                                <div className="flex items-center text-xs text-gray-500 font-medium">
                                                    <Calendar size={14} className="mr-2 text-gray-300" />
                                                    {formatDateTime(log.created_at)}
                                                </div>
                                            </td>
                                            <td className="px-6 py-5 text-right">
                                                <button 
                                                    onClick={() => setExpandedRow(expandedRow === log.id ? null : log.id)}
                                                    className={`p-2 rounded-lg transition-all ${expandedRow === log.id ? 'bg-rubber-600 text-white shadow-lg shadow-rubber-200' : 'bg-white border border-gray-100 text-gray-400 hover:text-rubber-600 hover:border-rubber-200'}`}
                                                >
                                                    {expandedRow === log.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                                                </button>
                                            </td>
                                        </tr>
                                        {expandedRow === log.id && (
                                            <tr className="bg-gray-50/50">
                                                <td colSpan="5" className="px-8 py-8 border-t border-gray-100">
                                                    <div className="animate-in fade-in slide-in-from-top-2">
                                                        <div className="flex items-center justify-between mb-6">
                                                            <div className="flex items-center space-x-3">
                                                                <FileJson className="text-rubber-600" size={20} />
                                                                <h4 className="text-sm font-black text-gray-900 uppercase tracking-widest">รายละเอียดการเปลี่ยนแปลงข้อมูล (Data Snapshot)</h4>
                                                            </div>
                                                            <div className="text-[10px] text-gray-400 font-mono bg-white px-3 py-1 rounded-full border border-gray-200">
                                                                IP: {log.ip_address}
                                                            </div>
                                                        </div>
                                                        {renderDiff(log.oldData, log.newData)}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan="5" className="px-6 py-20 text-center">
                                        <div className="max-w-xs mx-auto flex flex-col items-center">
                                            <div className="p-4 bg-gray-50 rounded-full text-gray-300 mb-4">
                                                <History size={40} />
                                            </div>
                                            <p className="text-gray-400 font-bold">ไม่พบประวัติความเคลื่อนไหว</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                {total > LIMIT && (
                    <div className="bg-white border-t border-gray-50 px-6 py-4 flex items-center justify-between">
                        <p className="text-xs font-bold text-gray-400">Showing {offset + 1} to {Math.min(offset + LIMIT, total)} of {total} events</p>
                        <div className="flex space-x-2">
                            <button 
                                disabled={offset === 0}
                                onClick={() => setOffset(Math.max(0, offset - LIMIT))}
                                className="px-4 py-2 text-xs font-bold bg-white border border-gray-100 rounded-xl text-gray-500 hover:bg-gray-50 disabled:opacity-50 transition-all active:scale-95"
                            >
                                Previous
                            </button>
                            <button 
                                disabled={offset + LIMIT >= total}
                                onClick={() => setOffset(offset + LIMIT)}
                                className="px-4 py-2 text-xs font-bold bg-rubber-600 text-white rounded-xl shadow-lg shadow-rubber-200 hover:bg-rubber-700 disabled:opacity-50 transition-all active:scale-95"
                            >
                                Next
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ActivityLog;

pages/settings/ChemicalManagement.jsx.content:
import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { FlaskConical, Save, RotateCcw, Droplets, Activity, Beaker, Info, Trash2, Edit3, Calendar, Search, RefreshCw } from 'lucide-react';
import toast from 'react-hot-toast';
import { getSettings, updateSettingsAPI, fetchChemicalUsage, deleteChemicalUsage, addChemicalUsage } from '../../services/apiService';

const defaultChemicals = [
    {
        id: 'ammonia',
        name: 'แอมโมเนีย',
        icon: '🧪',
        iconName: 'FlaskConical',
        color: 'amber',
        amount: '20',
        perLatex: '1000',
        unit: 'กิโลกรัม',
        description: 'ใช้รักษาสภาพน้ำยางไม่ให้จับตัว'
    },
    {
        id: 'water',
        name: 'น้ำ',
        icon: '💧',
        iconName: 'Droplets',
        color: 'blue',
        amount: '30',
        perLatex: '800',
        unit: 'กิโลกรัม',
        description: 'ใช้ผสมเพื่อปรับความเข้มข้น'
    },
    {
        id: 'whiteMedicine',
        name: 'ยาขาว',
        icon: '⚪',
        iconName: 'Activity',
        color: 'gray',
        amount: '1',
        perLatex: '1000',
        unit: 'กิโลกรัม',
        description: 'ใช้เพื่อปรับคุณภาพน้ำยาง'
    }
];

const colorMap = {
    amber: {
        bg: 'bg-amber-50',
        border: 'border-amber-200',
        ring: 'ring-amber-100',
        text: 'text-amber-700',
        iconBg: 'bg-amber-100',
        badge: 'bg-amber-100 text-amber-800 border-amber-200'
    },
    blue: {
        bg: 'bg-blue-50',
        border: 'border-blue-200',
        ring: 'ring-blue-100',
        text: 'text-blue-700',
        iconBg: 'bg-blue-100',
        badge: 'bg-blue-100 text-blue-800 border-blue-200'
    },
    gray: {
        bg: 'bg-gray-50',
        border: 'border-gray-200',
        ring: 'ring-gray-100',
        text: 'text-gray-700',
        iconBg: 'bg-gray-100',
        badge: 'bg-gray-100 text-gray-800 border-gray-200'
    }
};

export const ChemicalManagement = () => {
    const [chemicals, setChemicals] = useState(defaultChemicals);
    const [saving, setSaving] = useState(false);
    const [loading, setLoading] = useState(true);
    const [hasChanges, setHasChanges] = useState(false);

    // History State
    const [usageHistory, setUsageHistory] = useState([]);
    const [loadingHistory, setLoadingHistory] = useState(false);
    const [editingRecord, setEditingRecord] = useState(null);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        await Promise.all([
            loadChemicalSettings(),
            loadUsageHistory()
        ]);
        setLoading(false);
    };

    const loadChemicalSettings = async () => {
        try {
            const res = await getSettings();
            if (res.status === 'success' && res.data && res.data.chemicalSettings) {
                try {
                    const saved = JSON.parse(res.data.chemicalSettings);
                    const merged = defaultChemicals.map(def => {
                        const found = saved.find(s => s.id === def.id);
                        return found ? { ...def, amount: found.amount, perLatex: found.perLatex } : def;
                    });
                    setChemicals(merged);
                } catch (e) {
                    console.error('Failed to parse chemicalSettings:', e);
                }
            }
        } catch (err) {
            console.error('Error loading chemical settings:', err);
        }
    };

    const loadUsageHistory = async () => {
        setLoadingHistory(true);
        try {
            const data = await fetchChemicalUsage();
            setUsageHistory(data || []);
        } catch (err) {
            console.error('Error loading usage history:', err);
        } finally {
            setLoadingHistory(false);
        }
    };

    const handleChange = (id, field, value) => {
        setChemicals(prev => prev.map(c =>
            c.id === id ? { ...c, [field]: value } : c
        ));
        setHasChanges(true);
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            const toSave = chemicals.map(({ id, amount, perLatex }) => ({ id, amount, perLatex }));
            const res = await updateSettingsAPI({ chemicalSettings: JSON.stringify(toSave) });
            if (res.status === 'success') {
                toast.success('บันทึกการตั้งค่าสารเคมีสำเร็จ');
                setHasChanges(false);
            } else {
                toast.error(res.message || 'บันทึกล้มเหลว');
            }
        } catch (err) {
            toast.error('บันทึกล้มเหลว: ' + err.message);
        } finally {
            setSaving(false);
        }
    };

    const handleDeleteUsage = async (id) => {
        if (!window.confirm('ยืนยันการลบประวัติการใช้งานสารเคมีนี้?')) return;

        const toastId = toast.loading('กำลังลบข้อมูล...');
        try {
            const res = await deleteChemicalUsage(id);
            if (res.status === 'success') {
                toast.success('ลบข้อมูลสำเร็จ', { id: toastId });
                loadUsageHistory();
            } else {
                toast.error(res.message || 'ลบล้มเหลว', { id: toastId });
            }
        } catch (err) {
            toast.error('ลบล้มเหลว: ' + err.message, { id: toastId });
        }
    };

    const handleUpdateRecord = async (e) => {
        e.preventDefault();
        const formData = new FormData(e.target);
        const amount = formData.get('amount');

        if (!amount || isNaN(amount)) {
            toast.error('กรุณาระบุปริมาณที่ถูกต้อง');
            return;
        }

        const toastId = toast.loading('กำลังปรับปรุงข้อมูล...');
        try {
            const res = await addChemicalUsage({
                ...editingRecord,
                amount: Number(amount)
            });

            if (res.status === 'success') {
                toast.success('ปรับปรุงข้อมูลสำเร็จ', { id: toastId });
                setEditingRecord(null);
                loadUsageHistory();
            } else {
                toast.error(res.message || 'อัปเดตล้มเหลว', { id: toastId });
            }
        } catch (err) {
            toast.error('อัปเดตล้มเหลว: ' + err.message, { id: toastId });
        }
    };

    const handleReset = () => {
        setChemicals(defaultChemicals);
        setHasChanges(true);
    };

    const getChemicalInfo = (id) => {
        return defaultChemicals.find(c => c.id === id) || { name: id, icon: '🧪' };
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-40">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-rubber-600"></div>
            </div>
        );
    }

    return (
        <div className="space-y-12">
            {/* Section 1: Settings */}
            <div className="space-y-8">
                <div className="flex justify-between items-start">
                    <div>
                        <h2 className="text-xl font-bold text-gray-900 flex items-center">
                            <FlaskConical className="mr-2 text-purple-600" size={24} />
                            ตั้งค่าอัตราส่วนสารเคมี
                        </h2>
                        <p className="text-sm text-gray-500 mt-1">
                            กำหนดอัตราการใส่สารเคมีอัตโนมัติอิงตามน้ำหนักยางที่รับซื้อ
                        </p>
                    </div>
                    <div className="flex space-x-2">
                        <button
                            onClick={handleReset}
                            className="inline-flex items-center px-3 py-2 text-gray-500 hover:bg-gray-100 rounded-lg transition text-sm font-bold"
                            title="รีเซ็ตเป็นค่าเริ่มต้น"
                        >
                            <RotateCcw size={16} className="mr-1.5" />
                            ค่าเริ่มต้น
                        </button>
                        <button
                            onClick={handleSave}
                            disabled={saving || !hasChanges}
                            className="inline-flex items-center px-5 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition shadow-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <Save size={16} className="mr-1.5" />
                            {saving ? 'กำลังบันทึก...' : 'บันทึกสูตร'}
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {chemicals.map((chem) => {
                        const colors = colorMap[chem.color] || colorMap.gray;
                        return (
                            <div key={chem.id} className={`${colors.bg} border ${colors.border} rounded-2xl p-6 transition-all hover:shadow-md`}>
                                <div className="flex items-center space-x-3 mb-5">
                                    <div className={`w-12 h-12 ${colors.iconBg} rounded-xl flex items-center justify-center text-2xl shadow-sm`}>
                                        {chem.icon}
                                    </div>
                                    <div>
                                        <h3 className={`font-bold text-lg ${colors.text}`}>{chem.name}</h3>
                                        <p className="text-xs text-gray-500">{chem.description}</p>
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <div>
                                        <label className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1.5 block">ใส่ {chem.name}</label>
                                        <div className="relative">
                                            <input
                                                type="number" step="0.1" value={chem.amount}
                                                onChange={(e) => handleChange(chem.id, 'amount', e.target.value)}
                                                className={`w-full px-4 py-3 border-2 ${colors.border} rounded-xl bg-white text-lg font-bold text-gray-900`}
                                            />
                                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-sm font-bold text-gray-400">{chem.unit}</span>
                                        </div>
                                    </div>
                                    <div className="text-center text-[10px] font-black text-gray-300 uppercase tracking-widest">ต่อน้ำยางสด</div>
                                    <div>
                                        <div className="relative">
                                            <input
                                                type="number" step="1" value={chem.perLatex}
                                                onChange={(e) => handleChange(chem.id, 'perLatex', e.target.value)}
                                                className={`w-full px-4 py-3 border-2 ${colors.border} rounded-xl bg-white text-lg font-bold text-gray-900`}
                                            />
                                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-sm font-bold text-gray-400">กก.</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <hr className="border-gray-100" />

            {/* Section 2: Usage History */}
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h2 className="text-xl font-bold text-gray-900 flex items-center">
                            <Calendar className="mr-2 text-rubber-600" size={24} />
                            ประวัติการใส่สารเคมีรายวัน
                        </h2>
                        <p className="text-sm text-gray-500 mt-1">
                            ตรวจสอบและแก้ไขรายการสารเคมีที่บันทึกไปแล้ว
                        </p>
                    </div>
                    <button 
                        onClick={loadUsageHistory}
                        className="p-2 text-gray-400 hover:text-rubber-600 hover:bg-rubber-50 rounded-xl transition-all"
                    >
                        <RefreshCw size={20} className={loadingHistory ? 'animate-spin' : ''} />
                    </button>
                </div>

                {/* Edit Modal / Inline Form */}
                {editingRecord && (
                    <div className="bg-amber-50 border border-amber-200 rounded-2xl p-6 shadow-sm animate-in fade-in slide-in-from-top-4 duration-300">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="font-black text-amber-800 flex items-center">
                                <Edit3 size={18} className="mr-2" />
                                แก้ไขรายการ: {getChemicalInfo(editingRecord.chemicalId).name} ({editingRecord.date})
                            </h3>
                            <button onClick={() => setEditingRecord(null)} className="text-amber-400 hover:text-amber-600">ยกเลิก</button>
                        </div>
                        <form onSubmit={handleUpdateRecord} className="flex flex-col md:flex-row items-end space-y-4 md:space-y-0 md:space-x-4">
                            <div className="flex-1">
                                <label className="text-xs font-bold text-amber-600/70 uppercase tracking-widest mb-1.5 block">ระบุจำนวนที่ถูกต้อง</label>
                                <div className="relative">
                                    <input 
                                        type="number" 
                                        step="0.1" 
                                        name="amount"
                                        defaultValue={editingRecord.amount}
                                        autoFocus
                                        className="w-full px-5 py-3 rounded-xl border-2 border-amber-200 focus:border-amber-500 focus:ring-0 text-xl font-black text-amber-900" 
                                    />
                                    <span className="absolute right-4 top-1/2 -translate-y-1/2 font-bold text-amber-400">{editingRecord.unit}</span>
                                </div>
                            </div>
                            <button type="submit" className="w-full md:w-auto px-8 py-3.5 bg-amber-600 text-white rounded-xl font-black shadow-lg shadow-amber-200 hover:bg-amber-700 transition-all">
                                บันทึกการแก้ไข
                            </button>
                        </form>
                    </div>
                )}

                {/* History Table */}
                <div className="bg-white border border-gray-100 rounded-2xl overflow-hidden shadow-sm">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead>
                                <tr className="bg-gray-50/50 border-b border-gray-100">
                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest">วันที่</th>
                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest">รายการสารเคมี</th>
                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest text-right">ปริมาณบันทึก</th>
                                    <th className="px-6 py-4 text-xs font-black text-gray-400 uppercase tracking-widest text-center">จัดการ</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {usageHistory.length === 0 ? (
                                    <tr>
                                        <td colSpan="4" className="px-6 py-12 text-center text-gray-400 font-medium">
                                            {loadingHistory ? 'กำลังโหลดข้อมูล...' : 'ยังไม่มีประวัติการบันทึก'}
                                        </td>
                                    </tr>
                                ) : (
                                    usageHistory.map((item) => {
                                        const chem = getChemicalInfo(item.chemicalId);
                                        return (
                                            <tr key={item.id} className="hover:bg-gray-50/30 transition-colors group">
                                                <td className="px-6 py-4">
                                                    <div className="font-bold text-gray-900">{format(new Date(item.date), 'dd/MM/yyyy')}</div>
                                                    <div className="text-[10px] text-gray-400 uppercase font-mono">{item.id.split('_')[1] || ''}</div>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center space-x-3">
                                                        <span className="text-xl">{chem.icon}</span>
                                                        <span className="font-bold text-gray-700">{chem.name}</span>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-4 text-right">
                                                    <span className="text-lg font-black text-gray-900">{Number(item.amount).toLocaleString()}</span>
                                                    <span className="text-xs font-medium text-gray-400 ml-1">{item.unit || 'กก.'}</span>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center justify-center space-x-2">
                                                        <button 
                                                            onClick={() => setEditingRecord(item)}
                                                            className="p-2 text-gray-400 hover:text-amber-600 hover:bg-amber-50 rounded-lg transition-all"
                                                            title="แก้ไข"
                                                        >
                                                            <Edit3 size={18} />
                                                        </button>
                                                        <button 
                                                            onClick={() => handleDeleteUsage(item.id)}
                                                            className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                                                            title="ลบ"
                                                        >
                                                            <Trash2 size={18} />
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                        );
                                    })
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </div>
    );
};

pages/settings/MaintenanceSettings.jsx.content:
import React, { useState, useEffect } from 'react';
import { AlertTriangle, RefreshCcw, Database, ShieldAlert } from 'lucide-react';
import toast from 'react-hot-toast';
import { db, resetLocalDatabase } from '../../services/db';

export const MaintenanceSettings = () => {
    const [pendingCount, setPendingCount] = useState(0);
    const [isResetting, setIsResetting] = useState(false);
    const [confirmText, setConfirmText] = useState('');
    const [showConfirm, setShowConfirm] = useState(false);

    useEffect(() => {
        checkSyncQueue();
    }, []);

    const checkSyncQueue = async () => {
        try {
            const count = await db.sync_queue.count();
            setPendingCount(count);
        } catch (e) {
            console.error("Failed to check sync queue:", e);
        }
    };

    const handleReset = async () => {
        if (confirmText !== 'RESET') {
            toast.error('กรุณาพิมพ์ RESET เพื่อยืนยัน');
            return;
        }

        setIsResetting(true);
        const toastId = toast.loading('กำลังล้างข้อมูลในเครื่อง...');

        try {
            await resetLocalDatabase();
            toast.success('ล้างข้อมูลสำเร็จ ระบบจะเริ่มใหม่ใน 2 วินาที', { id: toastId });

            // Wait 2s and reload
            setTimeout(() => {
                window.location.reload();
            }, 2000);
        } catch (error) {
            toast.error('เกิดข้อผิดพลาด: ' + error.message, { id: toastId });
            setIsResetting(false);
        }
    };

    return (
        <div className="max-w-2xl space-y-8 animate-in fade-in duration-500">
            <div>
                <h2 className="text-xl font-bold text-gray-900 mb-2 flex items-center">
                    <Database className="mr-2 text-gray-400" size={24} />
                    จัดการฐานข้อมูลในเครื่อง
                </h2>
                <p className="text-sm text-gray-500">
                    เมนูสำหรับดูแลรักษาข้อมูลที่เก็บไว้ภายในเบราว์เซอร์ของคุณ
                </p>
            </div>

            {/* Sync Queue Warning */}
            <div className={`p-6 rounded-2xl border-2 transition-all ${pendingCount > 0 ? 'bg-amber-50 border-amber-200 shadow-sm' : 'bg-green-50 border-green-200'}`}>
                <div className="flex items-start space-x-4">
                    <div className={`p-3 rounded-xl ${pendingCount > 0 ? 'bg-amber-100 text-amber-600' : 'bg-green-100 text-green-600'}`}>
                        {pendingCount > 0 ? <AlertTriangle size={24} /> : <RefreshCcw size={24} />}
                    </div>
                    <div>
                        <h3 className={`font-bold mb-1 ${pendingCount > 0 ? 'text-amber-900' : 'text-green-900'}`}>
                            {pendingCount > 0 ? 'มีรายการรอซิงค์ค้างอยู่' : 'ข้อมูลทั้งหมดซิงค์เรียบร้อยแล้ว'}
                        </h3>
                        <p className={`text-sm ${pendingCount > 0 ? 'text-amber-700' : 'text-green-700'}`}>
                            {pendingCount > 0 
                                ? `คุณมี ${pendingCount} รายการที่บันทึกขณะออฟไลน์และยังส่งไม่ถึงเซิร์ฟเวอร์ การล้างข้อมูลตอนนี้จะทำให้รายการเหล่านี้หายไปถาวร`
                                : 'ข้อมูลในเครื่องของคุณตรงกับบนเซิร์ฟเวอร์ (หรือไม่มีรายการค้าง) สามารถล้างข้อมูลได้อย่างปลอดภัย'}
                        </p>
                        {pendingCount > 0 && (
                            <button 
                                onClick={checkSyncQueue}
                                className="mt-4 text-xs font-bold uppercase tracking-wider text-amber-600 hover:text-amber-800 flex items-center"
                            >
                                <RefreshCcw size={12} className="mr-1" /> ตรวจสอบใหม่
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Danger Zone */}
            <div className="pt-8 border-t border-gray-100">
                <div className="bg-red-50 rounded-3xl border border-red-100 overflow-hidden">
                    <div className="p-6 bg-red-100/50 flex items-center space-x-3">
                        <ShieldAlert className="text-red-600" size={20} />
                        <h3 className="font-black text-red-900 uppercase tracking-wider text-sm">Danger Zone</h3>
                    </div>

                    <div className="p-8 space-y-6">
                        <div>
                            <h4 className="font-bold text-gray-900 mb-2 text-lg">ล้างข้อมูลในเครื่องทั้งหมด (Reset Local DB)</h4>
                            <p className="text-sm text-gray-600 leading-relaxed">
                                การดำเนินการนี้จะลบตารางข้อมูลทั้งหมด (เกษตรกร, บิลซื้อ-ขาย, ตั้งค่าหน้าจอ) เฉพาะในเครื่องนี้เท่านั้น 
                                ข้อมูลบนระบบ Cloud จะไม่หายไป แต่ระบบจะบังคับให้คุณโหลดข้อมูลใหม่ทั้งหมดเมื่อเข้าใช้งานครั้งถัดไป
                            </p>
                        </div>

                        {!showConfirm ? (
                            <button
                                onClick={() => setShowConfirm(true)}
                                className="w-full sm:w-auto px-8 py-4 bg-red-600 text-white font-black rounded-2xl shadow-lg shadow-red-200 hover:bg-red-700 hover:-translate-y-1 transition-all active:translate-y-0"
                            >
                                เริ่มต้นการล้างข้อมูล
                            </button>
                        ) : (
                            <div className="space-y-4 animate-in zoom-in-95 duration-300">
                                <div className="p-4 bg-white border border-red-200 rounded-2xl">
                                    <label className="block text-xs font-bold text-red-600 uppercase tracking-widest mb-2">
                                        พิมพ์คำว่า "RESET" เพื่อยืนยัน
                                    </label>
                                    <input
                                        type="text"
                                        value={confirmText}
                                        onChange={(e) => setConfirmText(e.target.value)}
                                        placeholder="RESET"
                                        className="w-full px-4 py-3 bg-red-50 border-2 border-red-100 rounded-xl focus:border-red-500 focus:ring-0 font-black text-center text-xl text-red-600 placeholder:text-red-200"
                                    />
                                </div>

                                <div className="flex space-x-3">
                                    <button
                                        onClick={() => { setShowConfirm(false); setConfirmText(''); }}
                                        className="flex-1 px-6 py-4 bg-gray-100 text-gray-500 font-bold rounded-2xl hover:bg-gray-200 transition-all"
                                    >
                                        ยกเลิก
                                    </button>
                                    <button
                                        onClick={handleReset}
                                        disabled={confirmText !== 'RESET' || isResetting}
                                        className="flex-[2] px-6 py-4 bg-red-600 text-white font-black rounded-2xl shadow-xl shadow-red-200 hover:bg-red-700 disabled:opacity-30 disabled:shadow-none transition-all flex items-center justify-center space-x-2"
                                    >
                                        {isResetting ? <RefreshCcw className="animate-spin" /> : null}
                                        <span>ยืนยันล้างข้อมูลและเริ่มระบบใหม่</span>
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

pages/settings/TeamManagement.jsx.content:
import React, { useState, useEffect } from 'react';
import { Users, UserPlus, Trash2, Mail, Shield, ShieldAlert, RefreshCw, CheckCircle2, AlertCircle } from 'lucide-react';
import { fetchTeamMembers, inviteTeamMember, removeTeamMember } from '../../services/apiService';

export const TeamManagement = ({ user }) => {
    const [team, setTeam] = useState([]);
    const [loading, setLoading] = useState(true);
    const [inviting, setInviting] = useState(false);
    const [email, setEmail] = useState('');
    const [message, setMessage] = useState({ type: '', text: '' });

    const loadTeam = async () => {
        setLoading(true);
        try {
            const data = await fetchTeamMembers();
            setTeam(data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadTeam();
    }, []);

    const handleInvite = async (e) => {
        e.preventDefault();
        if (!email) return;
        setInviting(true);
        setMessage({ type: '', text: '' });
        try {
            const res = await inviteTeamMember(email);
            if (res.status === 'success') {
                setMessage({ type: 'success', text: res.message || 'ส่งคำเชิญสำเร็จ' });
                setEmail('');
                loadTeam();
            } else {
                setMessage({ type: 'error', text: res.message || 'เกิดข้อผิดพลาด' });
            }
        } catch (err) {
            setMessage({ type: 'error', text: err.message });
        } finally {
            setInviting(false);
        }
    };

    const handleRemove = async (userId, userName) => {
        if (!window.confirm(`ยืนยันการลบ ${userName} ออกจากทีม?`)) return;
        try {
            const res = await removeTeamMember(userId);
            if (res.status === 'success') {
                loadTeam();
            } else {
                alert(res.message);
            }
        } catch (err) {
            alert(err.message);
        }
    };

    const isOwner = user?.role === 'owner' || user?.role === 'super_admin';

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center mb-6">
                <div className="flex flex-col">
                    <h2 className="text-xl font-bold text-gray-900 flex items-center">
                        <Users className="mr-2 text-indigo-600" size={24} />
                        จัดการสมาชิกในทีม (System Access)
                    </h2>
                    <p className="text-xs text-gray-500 mt-1">จัดการสิทธิการใช้งานระบบสำหรับพนักงานของร้าน</p>
                </div>
                <button
                    onClick={loadTeam}
                    className="inline-flex items-center px-3 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition text-sm font-bold"
                >
                    <RefreshCw size={18} className={`mr-1 ${loading ? 'animate-spin' : ''}`} />
                    รีเฟรช
                </button>
            </div>

            {isOwner && (
                <section className="bg-white border-2 border-dashed border-indigo-100 rounded-2xl p-6 mb-8">
                    <div className="flex items-center space-x-4 mb-4">
                        <div className="w-12 h-12 bg-indigo-100 rounded-xl flex items-center justify-center text-indigo-600">
                            <UserPlus size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-gray-900">เชิญพนักงานเข้าสู่ระบบ</h3>
                            <p className="text-sm text-gray-500">พนักงานที่ถูกเชิญ จะสามารถล็อกอินด้วย Gmail เพื่อเข้าถึงข้อมูลร้านของท่านได้</p>
                        </div>
                    </div>

                    <form onSubmit={handleInvite} className="flex flex-col md:flex-row gap-4">
                        <div className="flex-1 relative">
                            <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="ระบุ Gmail ของพนักงาน"
                                className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all font-medium"
                                required
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={inviting || !email}
                            className="bg-indigo-600 text-white font-bold py-3 px-8 rounded-xl hover:bg-indigo-700 disabled:opacity-50 shadow-lg shadow-indigo-100 transition-all flex items-center justify-center space-x-2 whitespace-nowrap"
                        >
                            {inviting ? <RefreshCw size={20} className="animate-spin" /> : <UserPlus size={20} />}
                            <span>เชิญพนักงาน</span>
                        </button>
                    </form>

                    {message.text && (
                        <div className={`mt-4 flex items-center p-3 rounded-lg text-sm ${message.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                            {message.type === 'success' ? <CheckCircle2 size={16} className="mr-2" /> : <AlertCircle size={16} className="mr-2" />}
                            {message.text}
                        </div>
                    )}

                    <div className="mt-4 flex items-center justify-between py-2 px-4 bg-amber-50 rounded-lg border border-amber-100">
                        <div className="flex items-center text-amber-800 text-xs font-bold">
                            <ShieldAlert size={14} className="mr-2" />
                            โควตาพนักงานในแพ็กเกจของคุณ: 
                        </div>
                        <div className="text-sm font-black text-amber-900">
                            {team.filter(m => m.role === 'staff').length} / {user?.maxStaffLimit || 1} คน
                        </div>
                    </div>
                </section>
            )}

            <div className="bg-white border border-gray-200 rounded-xl overflow-hidden shadow-sm">
                <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="px-6 py-4 text-left text-[11px] font-black text-gray-400 uppercase tracking-wider">สมาชิก</th>
                            <th className="px-6 py-4 text-left text-[11px] font-black text-gray-400 uppercase tracking-wider">บทบาท</th>
                            <th className="px-6 py-4 text-left text-[11px] font-black text-gray-400 uppercase tracking-wider">วันที่เข้าร่วม</th>
                            <th className="px-6 py-4 text-right"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {team.map((member) => (
                            <tr key={member.id} className="hover:bg-gray-50/50 transition-colors">
                                <td className="px-6 py-4">
                                    <div className="flex items-center space-x-3">
                                        <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-white shadow-sm ${member.role === 'owner' ? 'bg-indigo-600' : member.role === 'admin' ? 'bg-amber-500' : 'bg-gray-400'}`}>
                                            {member.username?.charAt(0).toUpperCase()}
                                        </div>
                                        <div>
                                            <div className="font-bold text-gray-900">{member.username}</div>
                                            <div className="text-xs text-gray-500">{member.email}</div>
                                            {member.id.startsWith('invited_') && (
                                                <span className="text-[10px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold uppercase mt-1 inline-block">Pending Invite</span>
                                            )}
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <div className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold border ${
                                        member.role === 'owner' ? 'bg-indigo-50 text-indigo-700 border-indigo-100' :
                                        member.role === 'super_admin' ? 'bg-purple-50 text-purple-700 border-purple-100' :
                                        'bg-gray-50 text-gray-600 border-gray-200'
                                    }`}>
                                        <Shield size={12} className="mr-1.5" />
                                        {member.role === 'owner' ? 'เจ้าของร้าน' : member.role === 'super_admin' ? 'Super Admin' : 'พนักงาน'}
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-500 font-mono">
                                    {member.created_at ? new Date(member.created_at).toLocaleDateString('th-TH') : '-'}
                                </td>
                                <td className="px-6 py-4 text-right">
                                    {isOwner && member.role !== 'owner' && member.role !== 'super_admin' && (
                                        <button
                                            onClick={() => handleRemove(member.id, member.username)}
                                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                            title="ลบออกจากทีม"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {team.length === 0 && !loading && (
                    <div className="py-20 text-center text-gray-400">
                        <Users size={48} className="mx-auto mb-4 opacity-10" />
                        <p>ยังไม่มีข้อมูลทีม</p>
                    </div>
                )}
            </div>
        </div>
    );
};

pages/Settings.jsx.content:
import React, { useState, useEffect, useRef } from 'react';
import { useForm } from 'react-hook-form';
import { format } from 'date-fns';
import { Settings as SettingsIcon, Save, Link, Building2, UserCircle, Leaf, Users, Trash2, DollarSign, RefreshCw, Truck, Database, Shield } from 'lucide-react';

import toast from 'react-hot-toast';

// API Services
import {
    getScriptUrl,
    updateScriptUrl,
    getSettings,
    updateSettingsAPI,
    setupSheets,
    fetchFarmers,
    addFarmer,
    fetchEmployees,
    addEmployee,
    fetchStaff,
    addStaff,
    deleteRecord,
    fetchDailyPrice,
    updateDailyPriceAPI,
    clearCache,
    clearAllCache,
    saveReceiptImageToDrive,

    broadcastPrice,
    updateRecord,
    fetchFactories,
    addFactory,
    fetchTrucks,
    addTruck,
    fetchMemberTypes,
    addMemberType,
    deleteMemberType
} from '../services/apiService';

// Auth & DB
import { useAuth } from '../context/AuthContext';
import db from '../services/db';


// Sub-components
import { GeneralSettings } from './settings/GeneralSettings';
import { PriceSettings } from './settings/PriceSettings';
import { UserManagement } from './settings/UserManagement';
import { LineIntegration } from './settings/LineIntegration';
import { StaffManagement } from './settings/StaffManagement';
import { TeamManagement } from './settings/TeamManagement';
import { FactoryManagement } from './settings/FactoryManagement';
import { TruckManagement } from './settings/TruckManagement';
import { ChemicalManagement } from './settings/ChemicalManagement';


export const Settings = () => {
    const { user } = useAuth();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState('general'); // general, price, farmers_employees, staff, line_integration
    const [dailyPriceObj, setDailyPriceObj] = useState({ price: '50', date: '' });
    const [drcBonuses, setDrcBonuses] = useState([]);
    const [fscBonus, setFscBonus] = useState('1');
    const [lineLogs, setLineLogs] = useState({ lastEvent: '', lastError: '', lastStatus: '' });
    const [notifyPriceLine, setNotifyPriceLine] = useState(true);
    const [previewImage, setPreviewImage] = useState(null);
    const [logoUrl, setLogoUrl] = useState('');
    const [showPreviewModal, setShowPreviewModal] = useState(false);
    const [isBroadcasting, setIsBroadcasting] = useState(false);
    const priceCardRef = useRef(null);

    // Farmers & Employees State
    const [farmers, setFarmers] = useState([]);
    const [employees, setEmployees] = useState([]);
    const [showFarmerForm, setShowFarmerForm] = useState(false);
    const [editingFarmer, setEditingFarmer] = useState(null);
    const [showEmployeeForm, setShowEmployeeForm] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState(null);

    // Staff State
    const [staffList, setStaffList] = useState([]);
    const [showStaffForm, setShowStaffForm] = useState(false);
    const [editingStaff, setEditingStaff] = useState(null);

    // Factory State
    const [factories, setFactories] = useState([]);
    const [showFactoryForm, setShowFactoryForm] = useState(false);
    const [editingFactory, setEditingFactory] = useState(null);

    // Truck State
    const [trucks, setTrucks] = useState([]);
    const [showTruckForm, setShowTruckForm] = useState(false);
    const [editingTruck, setEditingTruck] = useState(null);

    // Member Type State
    const [memberTypes, setMemberTypes] = useState([]);
    const [showMemberTypeForm, setShowMemberTypeForm] = useState(false);
    const [editingMemberType, setEditingMemberType] = useState(null);

    const { register, handleSubmit, reset, setValue, watch } = useForm({
        defaultValues: {
            factoryName: '',
            address: '',
            phone: '',
            lineChannelAccessToken: '',
            lineChannelSecret: '',
            lineLiffIdProfile: '',
            lineLiffIdAddEmployee: '',
            scriptUrl: getScriptUrl() || '',
            printESlip: true,
            printPaperSlip: true,
            showPrizeDraw: true
        }
    });

    // Separate forms
    const priceForm = useForm();
    const farmerForm = useForm();
    const employeeForm = useForm();
    const staffForm = useForm();

    useEffect(() => {
        loadData();
    }, [activeTab]);

    const loadData = async () => {
        setLoading(true);
        try {
            if (activeTab === 'general') {
                const res = await getSettings();
                const defaultStation = user?.username ? user.username.substring(0, 3).toUpperCase() : 'RTB';

                if (res.status === 'success' && res.data) {
                    reset({
                        factoryName: res.data.factoryName || '',
                        address: res.data.address || '',
                        phone: res.data.phone || '',
                        pointsPerKg: res.data.pointsPerKg || '10',
                        lineChannelAccessToken: res.data.lineChannelAccessToken || '',
                        lineChannelSecret: res.data.lineChannelSecret || '',
                        lineLiffIdProfile: res.data.lineLiffIdProfile || '',
                        lineLiffIdAddEmployee: res.data.lineLiffIdAddEmployee || '',
                        station_code: res.data.station_code || defaultStation,
                        format_buy_bill: res.data.format_buy_bill || 'B-{STATION}{YYYY}-{SEQ4}',
                        format_sell_bill: res.data.format_sell_bill || 'S-{STATION}{YYYY}-{SEQ4}',
                        format_farmer_id: res.data.format_farmer_id || '{STATION}-F-{SEQ4}',
                        format_employee_id: res.data.format_employee_id || '{STATION}-E-{SEQ3}',
                        printESlip: res.data.printESlip === undefined ? true : (res.data.printESlip === 'true' || res.data.printESlip === true),
                        printPaperSlip: res.data.printPaperSlip === undefined ? true : (res.data.printPaperSlip === 'true' || res.data.printPaperSlip === true),
                        showPrizeDraw: res.data.showPrizeDraw === undefined ? true : (res.data.showPrizeDraw === 'true' || res.data.showPrizeDraw === true)
                    });

                    setLogoUrl(res.data.logoUrl || '');
                }
            } else if (activeTab === 'price') {
                const [priceRes, settingsRes] = await Promise.all([
                    fetchDailyPrice(),
                    getSettings()
                ]);
                if (priceRes.status === 'success') {
                    setDailyPriceObj(priceRes.data);
                    priceForm.setValue('dailyPrice', priceRes.data.price);
                }
                if (settingsRes.status === 'success' && settingsRes.data) {
                    if (settingsRes.data.drcBonuses) {
                        try {
                            setDrcBonuses(JSON.parse(settingsRes.data.drcBonuses));
                        } catch (e) {
                            setDrcBonuses(getDefaultDrcBonuses());
                        }
                    } else {
                        setDrcBonuses(getDefaultDrcBonuses());
                    }
                    setFscBonus(settingsRes.data.fsc_bonus || '1');
                    priceForm.setValue('cupLumpPrice', settingsRes.data.cupLumpPrice || '');
                }
            } else if (activeTab === 'farmers_employees') {
                clearCache('farmers', 'employees', 'farmer_types');
                const [fData, eData, mtData] = await Promise.all([
                    fetchFarmers(),
                    fetchEmployees(),
                    fetchMemberTypes()
                ]);
                setFarmers(fData || []);
                setEmployees(eData || []);
                setMemberTypes(mtData || []);
            } else if (activeTab === 'line_integration') {
                const res = await getSettings();
                if (res.status === 'success' && res.data) {
                    setValue('lineChannelAccessToken', res.data.lineChannelAccessToken || '');
                    setValue('lineChannelSecret', res.data.lineChannelSecret || '');
                    setValue('lineLiffIdProfile', res.data.lineLiffIdProfile || '');
                    setValue('lineLiffIdAddEmployee', res.data.lineLiffIdAddEmployee || '');
                    setLineLogs({
                        lastEvent: res.data.lineLastEvent || 'ยังไม่มีความเคลื่อนไหวที่ได้รับ',
                        lastError: res.data.lineLastError || 'ไม่มีข้อผิดพลาด',
                        lastStatus: res.data.lineLastStatus || 'รอการเชื่อมต่อ'
                    });
                }
            } else if (activeTab === 'staff') {
                const sData = await fetchStaff();
                setStaffList(sData || []);
            } else if (activeTab === 'factories') {
                const fData = await fetchFactories();
                setFactories(fData || []);
            } else if (activeTab === 'trucks') {
                const tData = await fetchTrucks();
                setTrucks(tData || []);
            }
        } catch (error) {
            toast.error('โหลดข้อมูลล้มเหลว');
        } finally {
            setLoading(false);
        }
    };

    const getDefaultDrcBonuses = () => ([
        { drc: '31', bonus: '1' },
        { drc: '32', bonus: '2' },
        { drc: '33', bonus: '3' },
        { drc: '34', bonus: '4' },
        { drc: '35', bonus: '5' },
        { drc: '40', bonus: '10' }
    ]);

    const onSubmitGeneral = async (data) => {
        setSaving(true);
        try {
            const payload = {
                factoryName: data.factoryName,
                address: data.address,
                phone: data.phone,
                pointsPerKg: data.pointsPerKg,
                lineChannelAccessToken: data.lineChannelAccessToken,
                lineChannelSecret: data.lineChannelSecret,
                lineLiffIdProfile: data.lineLiffIdProfile,
                lineLiffIdAddEmployee: data.lineLiffIdAddEmployee,
                station_code: data.station_code,
                format_buy_bill: data.format_buy_bill,
                format_sell_bill: data.format_sell_bill,
                format_farmer_id: data.format_farmer_id,
                format_employee_id: data.format_employee_id,
                printESlip: data.printESlip,
                printPaperSlip: data.printPaperSlip,
                showPrizeDraw: data.showPrizeDraw,
                logoUrl: logoUrl

            };
            const res = await updateSettingsAPI(payload);
            if (res.status === 'success') {
                toast.success('บันทึกการตั้งค่าสำเร็จ');
            } else {
                toast.error(res.message);
            }
        } catch (error) {
            toast.error('บันทึกล้มเหลว: ' + error.message);
        } finally {
            setSaving(false);
        }
    };

    const handleLogoUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            toast.error('ไฟล์มีขนาดใหญ่เกินไป (สูงสุด 2MB)');
            return;
        }

        const toastId = toast.loading('กำลังอัปโหลดโลโก้...');
        try {
            const reader = new FileReader();
            reader.readAsDataURL(file);
            reader.onload = async () => {
                const base64 = reader.result;
                const filename = `logo_${Date.now()}.${file.name.split('.').pop()}`;
                const res = await saveReceiptImageToDrive(base64, filename);
                if (res.status === 'success') {
                    setLogoUrl(res.url);
                    toast.success('อัปโหลดโลโก้สำเร็จ', { id: toastId });
                } else {
                    toast.error('อัปโหลดล้มเหลว: ' + res.message, { id: toastId });
                }
            };
        } catch (error) {
            toast.error('เกิดข้อผิดพลาดในการอัปโหลด', { id: toastId });
        }
    };

    const onSubmitDailyPrice = async (data) => {
